  { id:"mvttnv-tar-devil-harrier",name:"Tar Devil Harrier",source:"mvttnv",level:3,role:"Artillery",xp:150,size:"Medium",origin:"Immortal",type:"Humanoid",keywords:["devil"],hp:36,ac:17,fort:14,ref:16,will:14,initiative:5,perception:8,speed:"6",senses:["Darkvision"],resist:["10 fire"],vulnerable:["5 acid"],powers:[{name:"Kukri",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +8 vs. AC Hit: 1d6 + 5 damage."},{name:"Tar Ball",action:"Standard",keywords:["fire"],description:"Attack: Ranged 10 (one creature); +8 vs. Reflex Hit: 2d6 + 4 fire damage, and the target is slowed and takes ongoing 2 fire damage (save ends both)."},{name:"Fuming Cloud",action:"Minor",keywords:["fire","zone"],recharge:"Encounter",description:"Attack: Close burst 1 (creatures in the burst); +6 vs. Fortitude Hit: 1d6 + 4 fire damage. Effect: The burst creates a zone that lasts until the end of the encounter. The zone is difficult terrain. While entirely within the zone, creatures have partial concealment, and any creature that ends its turn in the zone takes 2 fire damage."}],alignment:"Evil",languages:["Supernal Equipment : kukri . Monster Vault: Threats to the Nentir Vale","page(s) 75","Dungeon Master's Kit."] },
  { id:"mvttnv-tigerclaw-brave",name:"Tigerclaw Brave",source:"mvttnv",level:3,role:"Soldier",xp:150,size:"Medium",origin:"Natural",type:"Humanoid",hp:49,ac:19,fort:17,ref:14,will:14,initiative:5,perception:3,speed:"6",powers:[{name:"Broadsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +8 vs. AC Hit: 1d10 + 6 damage. Effect: The target is marked until the end of the brave's next turn."},{name:"Sabertooth Spear",action:"Standard",keywords:["weapon"],recharge:"Recharge when first bloodied",description:"Attack: Ranged 5 (one creature); +6 vs. Reflex Hit: 2d6 + 5 damage, and the target is immobilized until the end of its next turn. Miss: Half damage, and the target is slowed until the end of its next turn."},{name:"Sabertooth Jab",action:"Triggered",description:"Trigger: An enemy adjacent to the brave and marked by it shifts. Effect (Opportunity Action): The brave uses broadsword against the triggering enemy. Skills Athletics +9"}],alignment:"Unaligned",languages:["Common Equipment : broadsword","hide armor","spear x2. Monster Vault: Threats to the Nentir Vale","page(s) 101","Dungeon Magazine 220."] },
  { id:"mvttnv-tigerclaw-hordeling",name:"Tigerclaw Hordeling",source:"mvttnv",level:3,role:"Skirmisher",roleModifier:"Minion",xp:38,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:17,fort:16,ref:15,will:14,initiative:5,perception:3,speed:"6",powers:[{name:"Battleaxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +8 vs. AC. The attack can score a critical hit on a roll of 18-20. Hit: 4 damage, or 7 if the attack was a critical hit."}],alignment:"Unaligned",languages:["Common Equipment : battleaxe","hide armor . Monster Vault: Threats to the Nentir Vale","page(s) 101","Dungeon Magazine 220."] },
  { id:"mvttnv-twig-blight-swampvine",name:"Twig Blight Swampvine",source:"mvttnv",level:3,role:"Soldier",xp:150,size:"Small",origin:"Fey",type:"Humanoid",keywords:["plant"],hp:42,ac:19,fort:14,ref:16,will:15,initiative:6,perception:8,speed:"5 (swamp walk), climb 5, swim 5",senses:["Darkvision"],resist:["5 poison"],vulnerable:["5 fire"],powers:[{name:"Rooted",action:"Trait",description:"When an effect forces the swampvine to move through a pull, a push, or a slide, the seedling can move 3 squares fewer than the effect specifies"},{name:"Claw",action:"Standard",keywords:["poison"],description:"Attack: Melee 1 (one creature); +8 vs. AC Hit: 1d8 + 6 poison damage."},{name:"Vine Snare",action:"Minor",description:"1/round Attack: Melee 3 (one creature); +6 vs. Reflex Hit: The swampvine pulls the target up to 2 squares, and the target is grabbed (escape DC 13)."},{name:"Poison Lash",action:"Triggered",keywords:["poison"],description:"Trigger: An enemy the swampvine is grabbing uses an attack power that does not include the swampvine as a target. Effect (Immediate Reaction): Melee 3 (triggering enemy). The target takes 5 poison damage. Skills Stealth +9"}],alignment:"Chaotic Evil",languages:["Elven Monster Vault: Threats to the Nentir Vale","page(s) 109."] },
  { id:"mvttnv-bloodspear-grenadier",name:"Bloodspear Grenadier",source:"mvttnv",level:4,role:"Artillery",xp:175,size:"Medium",origin:"Natural",type:"Humanoid",hp:44,ac:18,fort:16,ref:17,will:15,initiative:6,perception:8,speed:"6",senses:["Low-light vision"],powers:[{name:"Handaxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 1d6 + 9 damage."},{name:"Handaxe",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10 (one creature); +11 vs. AC Hit: 1d6 + 9 damage."},{name:"Fire Bomb",action:"Standard",keywords:["fire","weapon"],description:"Attack: Area burst 1 within 10 (creatures in the burst); +9 vs. Reflex Hit: 1d8 + 5 fire damage."},{name:"Blazing Fury",action:"Triggered",recharge:"Encounter",description:"Trigger: The grenadier drops to 0 hit points. Effect (Free Action): Each creature adjacent to the grenadier takes 5 fire damage, and the grenadier uses fire bomb. Caltrops ✦ Encounter Trigger: An enemy ends its movement adjacent to the grenadier. Effect (Immediate Reaction): The grenadier shifts up to 2 squares and drops caltrops in a close blast 3, which must include the enemy's space. Until the end of the encounter, any creature that enters the blast's area or ends its turn there takes 5 damage and is slowed (save ends)."}],alignment:"Chaotic Evil",languages:["Common","Giant Equipment : 4 fire bombs","caltrops","handaxe x2","leather armor . Monster Vault: Threats to the Nentir Vale","page(s) 34."] },
  { id:"mvttnv-boggle-blink-trickster",name:"Boggle Blink Trickster",source:"mvttnv",level:4,role:"Artillery",xp:175,size:"Small",origin:"Fey",type:"Humanoid",hp:43,ac:18,fort:16,ref:18,will:14,initiative:7,perception:9,speed:"6, climb 6",senses:["Darkvision"],resist:["5 fire"],powers:[{name:"Dimensional Window",action:"Trait",description:"The boggle can make Thievery checks against any creature within 10 squares of it that it is aware of"},{name:"Dimension Claw",action:"Standard",description:"Attack: Melee 10 (one creature); +11 vs. AC Hit: 2d6 + 5 damage."},{name:"Double Diversion Trick",action:"Standard",recharge:"Recharge when first bloodied",description:"Effect: The boggle uses dimension claw twice."},{name:"Dimension Hop",action:"Move",keywords:["teleportation"],description:"Effect: The boggle teleports up to 3 squares."},{name:"Teleport Trick",action:"Triggered",keywords:["teleportation"],recharge:"Encounter",description:"Trigger: The boggle takes damage from a melee attack. Effect (Immediate Reaction): The boggle teleports up to 3 squares. Skills Athletics +9, Stealth +12, Thievery +12"}],alignment:"Evil",languages:["Common","Goblin Monster Vault: Threats to the Nentir Vale","page(s) 29","Dungeon Magazine 217."] },
  { id:"mvttnv-boggle-chase-trickster",name:"Boggle Chase Trickster",source:"mvttnv",level:4,role:"Skirmisher",xp:175,size:"Small",origin:"Fey",type:"Humanoid",hp:53,ac:18,fort:16,ref:18,will:14,initiative:9,perception:9,speed:"6, climb 6",senses:["Darkvision"],resist:["5 fire"],powers:[{name:"Dimensional Window",action:"Trait",description:"The boggle can make Thievery checks against any creature within 10 squares of it that it is aware of"},{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +9 vs. AC Hit: 2d6 + 5 damage."},{name:"Dimension Hop",action:"Move",keywords:["teleportation"],description:"Effect: The boggle teleports up to 3 squares."},{name:"Foot-Snare Trick",action:"Minor",description:"1/round Effect: Melee 1 (one creature flanked by the boggle). If the target moves more than 3 squares during its next turn, it falls prone at the end of that turn."},{name:"Chase Trick",action:"Triggered",keywords:["charm"],recharge:"Recharge when first bloodied",description:"Trigger: A creature misses the boggle with a melee attack. Effect (Immediate Reaction): The boggle shifts up to 3 squares and then pulls the triggering creature to a square adjacent to it. The triggering creature's movement provokes opportunity attacks. If the creature ends this movement without taking damage from an attack, it can make a melee basic attack against the boggle as a free action. Skills Athletics +9, Stealth +12, Thievery +12"}],alignment:"Evil",languages:["Common","Goblin Monster Vault: Threats to the Nentir Vale","page(s) 29","Dungeon Magazine 217."] },
  { id:"mvttnv-daggerburg-ruffian",name:"Daggerburg Ruffian",source:"mvttnv",level:4,role:"Soldier",xp:175,size:"Small",origin:"Natural",type:"Humanoid",hp:58,ac:20,fort:18,ref:16,will:14,initiative:7,perception:8,speed:"5",senses:["Low-light vision"],powers:[{name:"Combat Adept At",action:"Trait",description:"the start of an encounter, the ruffian's attacks deal 1d10 extra damage against any enemy that has not yet acted during the encounter"},{name:"Daggerburg Tactics Whenever",action:"Trait",description:"an enemy misses the ruffian with a melee attack, the ruffian gains combat advantage against that enemy until the end of its next turn"},{name:"Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 1d8 + 8 damage."},{name:"Hand Crossbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10 (one creature); +9 vs. AC Hit: 1d6 + 5 damage."},{name:"Trip Up",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +7 vs. Reflex Hit: 1d8 + 8 damage, and the target falls prone."}],alignment:"Evil",languages:["Common","Goblin Equipment : chainmail","crossbow bolt x10","hand crossbow","light shield","spear . Monster Vault: Threats to the Nentir Vale","page(s) 38."] },
  { id:"mvttnv-emberdark-kobold-pillager",name:"Emberdark Kobold Pillager",source:"mvttnv",level:4,role:"Soldier",xp:175,size:"Small",origin:"Natural",type:"Humanoid",keywords:["reptile"],hp:55,ac:20,fort:17,ref:16,will:16,initiative:5,perception:8,speed:"6",senses:["Darkvision"],powers:[{name:"Flamebiter Spear",action:"Standard",keywords:["fire","weapon"],description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 2d8 + 3 fire damage. Effect: The target is marked until the start of the pillager's next turn. Until the mark ends, the target takes 5 fire damage whenever it makes an attack that doesn't include the pillager as a target."},{name:"Fire Dart",action:"Standard",keywords:["fire","weapon"],description:"Attack: Ranged 5 (one creature); +9 vs. AC Hit: 2d4 + 7 fire damage, and the target is marked until the end of the pillager's next turn."},{name:"Blaze of Glory",action:"Triggered",recharge:"Encounter",description:"Trigger: The pillager drops to 0 hit points. Effect (Free Action): The pillager makes a melee basic attack. Skills Stealth +8, Thievery +8"}],alignment:"Evil",languages:["Common","Draconic Equipment : 5 darts","scale armor","spear . Monster Vault: Threats to the Nentir Vale","page(s) 33."] },
  { id:"mvttnv-fell-court-hellmage",name:"Fell Court Hellmage",source:"mvttnv",level:4,role:"Artillery",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:42,ac:18,fort:14,ref:17,will:17,initiative:6,perception:12,speed:"6",senses:["Low-light vision"],resist:["5 fire"],powers:[{name:"Drake Regeneration",action:"Aura",keywords:["healing"],description:"Aura 3 Any bloodied drake ally in the aura regains 5 hit points at the start of its turn if it has at least 1 hit point."},{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +9 vs. AC. The hellmage has a +1 bonus to hit a bloodied target. Hit: 2d4 + 7 damage."},{name:"Infernal Bolt",action:"Standard",keywords:["fire","implement","radiant"],description:"Attack: Ranged 20 (one creature); +9 vs. Reflex. The hellmage has a +1 bonus to hit a bloodied target. Hit: 1d8 + 3 fire and radiant damage, and ongoing 5 fire and radiant damage (save ends)."},{name:"Infernal Wrath",action:"Triggered",keywords:["fire"],recharge:"Encounter",description:"Trigger: An enemy within 10 squares of the hellmage hits it with an attack. Effect (Free Action): The triggering enemy takes 1d6 + 5 fire damage."},{name:"See You in Hell",action:"Triggered",recharge:"Encounter",description:"Trigger: The hellmage drops to 0 hit points. Effect (Immediate Interrupt): The hellmage uses infernal bolt, and the attack does not provoke opportunity attacks. Skills Arcana +12, Bluff +10, History +12, Stealth +11"}],alignment:"Evil",languages:["Common","Supernal Equipment : dagger . Monster Vault: Threats to the Nentir Vale","page(s) 51","Dungeon Magazine 201."] },
  { id:"mvttnv-iron-circle-spy",name:"Iron Circle Spy",source:"mvttnv",level:4,role:"Lurker",xp:175,size:"Medium",origin:"Natural",type:"Humanoid",hp:44,ac:18,fort:16,ref:18,will:16,initiative:10,perception:9,speed:"6",powers:[{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 2d6 + 5 damage."},{name:"Devil's Flame",action:"Standard",keywords:["fire"],description:"Attack: Ranged 10 (one creature); +7 vs. Reflex Hit: 2d4 + 7 fire damage."},{name:"Infernal Strike",action:"Standard",keywords:["fire","weapon"],recharge:"Recharge when the spy uses veil of shadows",description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 4d6 + 10 fire damage. Miss: Half damage. Veil of Shadows (zone) ✦ Recharge when the spy uses infernal strike Effect: Close burst 1. The burst creates a zone that lasts until the end of the spy's next turn. The zone blocks line of sight for all creatures except the spy. While entirely within the zone, creatures other than the spy are blinded."},{name:"Diabolical Dodge",action:"Triggered",description:"Trigger: An enemy uses a power that pulls, pushes, or slides the spy while the spy is in the zone created by its veil of shadows. Effect (Immediate Interrupt): The spy makes a basic attack against the triggering enemy and then can shift up to 2 squares to another square in the zone. Skills Bluff +9, Diplomacy +9, Stealth +11, Thievery +11"}],alignment:"Evil",languages:["Common","Elven Equipment : leather armor","short sword . Monster Vault: Threats to the Nentir Vale","page(s) 75."] },
  { id:"mvttnv-lizardfolk-fen-spy",name:"Lizardfolk Fen Spy",source:"mvttnv",level:4,role:"Lurker",xp:175,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["reptile"],hp:41,ac:18,fort:14,ref:16,will:15,initiative:9,perception:9,speed:"6 (swamp walk)",powers:[{name:"Thorn Dagger",action:"Standard",keywords:["poison","weapon"],description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 1d8 + 7 poison damage, and the target takes a -2 penalty to AC and Reflex until the end of the fen spy's next turn."},{name:"Fastlight Strike",action:"Standard",keywords:["radiant"],description:"Requirement: The fen spy must be invisible. Attack: Ranged 5 (one creature); +7 vs. Will Hit: 3d6 + 8 radiant damage, and the target is blinded and takes ongoing 5 radiant damage (save ends both). Miss: Half damage, and the target is blinded until the end of its next turn. Witchlight Mists ✦ At-Will Effect: The fen spy becomes invisible until the end of its next turn or until immediately after it attacks. Skills Stealth +10, Thievery +10"}],alignment:"Unaligned",languages:["Draconic Equipment : thorn dagger Monster Vault: Threats to the Nentir Vale","page(s) 118","Dungeon Magazine 191","Halls of Undermountain","page(s) 95."] },
  { id:"mvttnv-lizardfolk-marsh-mystic",name:"Lizardfolk Marsh Mystic",source:"mvttnv",level:4,role:"Controller",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["reptile"],hp:53,ac:18,fort:15,ref:15,will:18,initiative:3,perception:10,speed:"6 (swamp walk)",powers:[{name:"Marsh Mist",action:"Aura",description:"Aura 10 While in the aura, the marsh mystic's allies cannot be surprised and have a +5 power bonus to Perception checks and Stealth checks."},{name:"Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 2d8 + 3 damage, and the marsh mystic can slide the target 1 square."},{name:"Fastlight Shock",action:"Standard",keywords:["lightning","radiant"],description:"Attack: Ranged 5 (one creature); +7 vs. Reflex Hit: 2d8 + 4 lightning and radiant damage, and the target is immobilized until the end of the marsh mystic's next turn. If the target was already immobilized, it is instead dazed. Miss: The target is slowed until the end of the marsh mystic's next turn."},{name:"Bog Cloud",action:"Standard",keywords:["poison"],recharge:"Encounter",description:"Attack: Area burst 1 within 10 (creatures in the burst); +7 vs. Fortitude Hit: 2d8 + 3 poison damage, and the target is dazed (save ends). Miss: Half damage, and the target grants combat advantage (save ends). Skills Nature +10, Stealth +8"}],alignment:"Unaligned",languages:["Draconic Equipment : spear . Monster Vault: Threats to the Nentir Vale","page(s) 119","Dungeon Magazine 191."] },
  { id:"mvttnv-peryton",name:"Peryton",source:"mvttnv",level:4,role:"Skirmisher",xp:175,size:"Medium",origin:"Natural",type:"Beast",hp:54,ac:18,fort:17,ref:16,will:15,initiative:6,perception:9,speed:"2, fly 8",powers:[{name:"Peryton's Prey At",action:"Trait",description:"the start of each of its turns, the peryton chooses one creature it can see"},{name:"That",action:"Trait",description:"creature is the peryton's prey until the start of the peryton's next turn"},{name:"Unhindered",action:"Trait",description:"When the peryton moves on its turn, it pulls with it any creature grabbed by it"},{name:"The",action:"Trait",description:"peryton can pull the creature vertically off a solid surface. During this movement, the creature remains grabbed, and this movement does not provoke an opportunity attack from the grabbed creature"},{name:"Antler Bash",action:"Standard",description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 2d6 + 3 damage, or 2d6 + 8 against the creature designated as the peryton's prey. In addition, the target falls prone."},{name:"Flyby Attack",action:"Standard",description:"Effect: The peryton flies up to its fly speed and uses antler bash once at any point during the movement. The peryton does not provoke opportunity attacks when moving away from the target of the attack."},{name:"Claw Snatch",action:"Standard",recharge:"Recharge when first bloodied",description:"Effect: Before and after the attack, the peryton can fly up to half its fly speed. Attack: Melee 1 (one Medium or smaller creature designated as the peryton's prey); +7 vs. Reflex Hit: 2d8 + 6 damage, and the target is grabbed (escape DC 14) until the end of the peryton's next turn."},{name:"Feast",action:"Standard",keywords:["healing"],recharge:"Encounter",description:"Effect: Melee 1 (one dying humanoid). The target dies, and the peryton regains 15 hit points."}],alignment:"Chaotic Evil",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 85."] },
  { id:"mvttnv-raven-roost-harrier",name:"Raven Roost Harrier",source:"mvttnv",level:4,role:"Skirmisher",xp:175,size:"Medium",origin:"Natural",type:"Humanoid",hp:53,ac:18,fort:16,ref:18,will:16,initiative:7,perception:4,speed:"6",powers:[{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 2d6 + 5 damage, and the target can't make opportunity attacks until the end of the harrier's next turn."},{name:"Hand Crossbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10/20 (one creature); +9 vs. AC Hit: 2d6 + 5 damage."},{name:"Moving Attack",action:"Standard",description:"Effect: The harrier moves up to its speed and uses short sword once at any point during this movement. After the attack, the harrier doesn't provoke opportunity attacks when moving away from the target of the attack. Skills Stealth +10"}],alignment:"Evil",languages:["Common Equipment : studded leather","crossbow bolt x20","hand crossbow","short sword . Monster Vault: Threats to the Nentir Vale","page(s) 91","Dungeon Magazine 201."] },
  { id:"mvttnv-tar-devil-guard",name:"Tar Devil Guard",source:"mvttnv",level:4,role:"Soldier",xp:175,size:"Medium",origin:"Immortal",type:"Humanoid",keywords:["devil"],hp:53,ac:20,fort:15,ref:17,will:15,initiative:7,perception:7,speed:"6",senses:["Darkvision"],resist:["10 fire"],vulnerable:["5 acid"],powers:[{name:"Hot Reek",action:"Aura",keywords:["fire"],description:"Aura 1 Any enemy that starts its turn in the aura takes 2 fire damage and cannot shift during that turn."},{name:"Khopesh",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 1d8 + 7 damage."},{name:"Tar Net",action:"Standard",keywords:["fire"],description:"Recharge if no creature is restrained by this power at the start of the devil guard's turn Attack: Ranged 5 (one creature); +7 vs. Reflex Hit: 1d6 + 4 fire damage, and the target is restrained (save ends). The devil guard can pull the target up to 4 squares to a square adjacent to it."}],alignment:"Evil",languages:["Supernal Equipment : khopesh","net . Monster Vault: Threats to the Nentir Vale","page(s) 75","Dungeon Master's Kit","Dungeon Magazine 205."] },
  { id:"mvttnv-tigerclaw-scout",name:"Tigerclaw Scout",source:"mvttnv",level:4,role:"Skirmisher",xp:175,size:"Medium",origin:"Natural",type:"Humanoid",hp:55,ac:18,fort:15,ref:17,will:15,initiative:8,perception:10,speed:"6",senses:["Low-light vision"],powers:[{name:"Adept Charger",action:"Trait",description:"The scout is not limited to taking only free actions immediately after a charge"},{name:"Razorclaw Flurry",action:"Trait",description:"While bloodied, the scout gains a +2 power bonus to speed and a +4 power bonus to all defenses against opportunity attacks"},{name:"Light Pick",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 2d6 + 4 damage, or 3d6 + 4 if the attack was part of a charge."},{name:"Sabertooth Strike",action:"Standard",keywords:["weapon"],description:"Recharge if the power misses every target Attack: Melee 1 (one or two creatures); +7 vs. Fortitude Hit: 1d6 + 5 damage, and ongoing 5 damage (save ends)."},{name:"Wild Instinct",action:"Triggered",description:"Trigger: An enemy ends its movement in a square where it flanks the scout. Effect (Immediate Reaction): The scout shifts up to 2 squares. Skills Athletics +9, Stealth +11"}],alignment:"Unaligned",languages:["Common Equipment : 2 light picks","hide armor . Monster Vault: Threats to the Nentir Vale","page(s) 102."] },
  { id:"mvttnv-tri-horned-felldrake",name:"Tri-Horned Felldrake",source:"mvttnv",level:4,role:"Soldier",xp:175,size:"Medium",origin:"Natural",type:"Beast",keywords:["reptile"],hp:58,ac:20,fort:18,ref:15,will:15,initiative:5,perception:3,speed:"5",immune:["fear"],powers:[{name:"Tri-Horn Charge",action:"Trait",description:"The felldrake gains a +3 bonus to damage rolls on charge attacks"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 1d10 + 7 damage."},{name:"Challenging Gore",action:"Standard",description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 2d6 + 5 damage, and the target is marked until the end of the felldrake's next turn."},{name:"Aggressive Warder",action:"Triggered",description:"Trigger: An enemy adjacent to the felldrake and marked by it uses an attack power that doesn't include it as a target. Effect (Immediate Reaction): Melee 1 (triggering enemy). The target takes 1d6 + 3 damage and falls prone. Skills Athletics +10"}],alignment:"Unaligned",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 53."] },
  { id:"mvttnv-battle-worg",name:"Battle Worg",source:"mvttnv",level:5,role:"Brute",xp:200,size:"Large",origin:"Natural",type:"Magical beast",keywords:["mount"],hp:78,ac:17,fort:18,ref:17,will:17,initiative:3,perception:6,speed:"8",powers:[{name:"Frightful Growl",action:"Aura",keywords:["fear"],description:"Aura 1 Enemies take a -1 penalty to attack rolls while in the aura"},{name:"Slavering Lunge",action:"Trait",keywords:["mount"],description:"When the worg's rider rolls initiative, the worg can move up to half its speed as a free action"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 1d10 + 5 damage, and ongoing 5 damage (save ends)."}],alignment:"Evil",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 38."] },
  { id:"mvttnv-blackfang-gravedigger",name:"Blackfang Gravedigger",source:"mvttnv",level:5,role:"Lurker",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",hp:48,ac:19,fort:19,ref:18,will:17,initiative:8,perception:9,speed:"6 (earth walk), burrow 2",senses:["Low-light vision"],powers:[{name:"Pack Attack",action:"Trait",description:"The gravedigger's attacks deal 5 extra damage to any enemy adjacent to two or more of the gravedigger's allies"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 2d6 + 4 damage."},{name:"Snatch from Below",action:"Standard",description:"Requirement: The gravedigger must be burrowing and must have no creature grabbed. Effect: The gravedigger reaches up through the ground and uses bite twice against one enemy, ignoring cover and concealment. If both attacks hit, the target is grabbed (escape DC 15). Until the grab ends, the target is restrained and takes ongoing 5 damage. Skills Dungeoneering +9, Stealth +9, Thievery +9"}],alignment:"Chaotic Evil",languages:["Abyssal","Common Monster Vault: Threats to the Nentir Vale","page(s) 25."] },
  { id:"mvttnv-bloodspear-krull",name:"Bloodspear Krull",source:"mvttnv",level:5,role:"Brute",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",hp:78,ac:17,fort:18,ref:16,will:17,initiative:3,perception:4,speed:"6",senses:["Low-light vision"],powers:[{name:"Glaive",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +10 vs. AC Hit: 2d10 + 5 damage."},{name:"Charging Sweep",action:"Standard",keywords:["weapon"],recharge:"Recharge 5-6",description:"Effect: The krull charges and makes the following attack in place of a melee basic attack. Attack: Close burst 2 (enemies in the burst); +10 vs. AC Hit: 2d10 + 5 damage, and the krull pushes the target 1 square and knocks it prone. Miss: Half damage."},{name:"Frenzied Strike",action:"Triggered",description:"1/round Trigger: The krull bloodies an enemy. Effect (Free Action): The krull uses glaive against the triggering enemy."},{name:"Charging Demise",action:"Triggered",recharge:"Encounter",description:"Trigger: The krull drops to 0 hit points. Effect (Free Action): Charging sweep recharges, and the krull uses it. Skills Endurance +11, Intimidate +7"}],alignment:"Chaotic Evil",languages:["Common","Giant Equipment : chainmail","glaive . Monster Vault: Threats to the Nentir Vale","page(s) 36."] },
  { id:"mvttnv-bloodspear-ogrillon",name:"Bloodspear Ogrillon",source:"mvttnv",level:5,role:"Brute",roleModifier:"Elite",xp:400,size:"Medium",origin:"Natural",type:"Humanoid",hp:156,ac:17,fort:18,ref:17,will:16,initiative:3,perception:2,speed:"6",senses:["Low-light vision"],powers:[{name:"Slam",action:"Standard",description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 2d10 + 5 damage, or 3d10 + 5 against a prone target. If the ogrillon scores a critical hit, it also knocks the target prone."},{name:"Double Attack",action:"Standard",description:"Effect: The ogrillon uses slam twice."},{name:"Brutish Retaliation",action:"Triggered",description:"Trigger: An enemy hits the ogrillon with a ranged or an area attack. Effect (Immediate Reaction): The ogrillon uses slam."}],alignment:"Chaotic Evil",languages:["Common","Giant Monster Vault: Threats to the Nentir Vale","page(s) 36."] },
  { id:"mvttnv-boggle-body-snatcher",name:"Boggle Body Snatcher",source:"mvttnv",level:5,role:"Controller",xp:200,size:"Small",origin:"Fey",type:"Humanoid",hp:61,ac:19,fort:17,ref:19,will:15,initiative:7,perception:9,speed:"6, climb 6",senses:["Darkvision"],resist:["5 fire"],powers:[{name:"Dimensional Window",action:"Trait",description:"The boggle can make Thievery checks against any creature within 10 squares of it that it is aware of"},{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +10 vs. AC Hit: 2d6 + 6 damage."},{name:"Body Snatch",action:"Standard",keywords:["charm"],recharge:"Recharge 3-6",description:"Attack: Ranged 5 (one creature); +8 vs. Will Hit: The target is dominated (save ends). Until the target saves against this effect, the boggle is removed from play, and the target gains a +2 bonus to attack rolls and damage rolls. When the effect ends, the boggle returns to play in an unoccupied space of its choice within 5 squares of the target."},{name:"Dimension Hop",action:"Move",keywords:["teleportation"],description:"Effect: The boggle teleports up to 3 squares."},{name:"Boggle Sweat Stain",action:"Minor",description:"1/round Effect: The boggle's current square is greased until the end of the encounter. Whenever any creature other than a boggle willingly enters the greased square, that creature falls prone. Skills Athletics +9, Stealth +12, Thievery +12"}],alignment:"Evil",languages:["Common","Goblin Monster Vault: Threats to the Nentir Vale","page(s) 29","Dungeon Magazine 217."] },
  { id:"mvttnv-daggerburg-theurge",name:"Daggerburg Theurge",source:"mvttnv",level:5,role:"Controller",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",hp:64,ac:19,fort:17,ref:17,will:16,initiative:3,perception:9,speed:"5",senses:["Low-light vision"],powers:[{name:"Combat Adept At",action:"Trait",description:"the start of an encounter, the theurge's attacks deal 1d10 extra damage against any enemy that has not yet acted during the encounter"},{name:"Daggerburg Tactics Whenever",action:"Trait",description:"an enemy misses the theurge with a melee attack, the theurge gains combat advantage against that enemy until the end of its next turn"},{name:"Spiked Club",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 2d6 + 6 damage."},{name:"Slimy Transformation",action:"Standard",keywords:["implement","polymorph"],description:"Attack: Ranged 5 (one creature not currently affected by slimy transformation); +8 vs. Fortitude Hit: The theurge alters the target's physical form to appear as a Tiny frog until the end of the theurge's next turn or until the target takes damage. While in this form, the target is slowed and cannot use powers."},{name:"Brimstone Rain",action:"Standard",keywords:["fire","implement"],recharge:"Encounter",description:"Attack: Area burst 2 within 10 (creatures in the burst); +8 vs. Reflex Hit: 1d8 + 4 fire damage, and ongoing 5 fire damage (save ends). Miss: Half damage. Skills Arcana +10"}],alignment:"Evil",languages:["Common","Goblin Equipment : spiked club","wand implement . Monster Vault: Threats to the Nentir Vale","page(s) 39."] },
  { id:"mvttnv-eveni-redblade",name:"Eveni Redblade",source:"mvttnv",level:5,role:"Skirmisher",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",hp:60,ac:19,fort:17,ref:17,will:18,initiative:6,perception:3,speed:"6",senses:["Low-light vision"],powers:[{name:"Wolf Runner's Bite Eveni",action:"Trait",description:"deals 1d6 extra damage to any target granting combat advantage to her"},{name:"Longsword",action:"Standard",keywords:["weapon"],description:"Effect: Eveni can shift 1 square before or after making the attack. Attack: Melee 1 (one creature); +10 vs. AC Hit: 1d8 + 9 damage."},{name:"Dazing Strike",action:"Standard",keywords:["weapon"],recharge:"Recharge 5-6",description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 2d8 + 6 damage, and the target is dazed until the end of Eveni's next turn."},{name:"Infernal Wrath",action:"Triggered",keywords:["fire"],recharge:"Encounter",description:"Trigger: An enemy within 10 squares of Eveni hits her with an attack. Effect (Free Action): The triggering enemy takes 1d6 + 3 fire damage. Skills Bluff +12, Diplomacy +10, Stealth +11, Streetwise +10"}],alignment:"Unaligned",languages:["Common","Elven Equipment : leather armor","longsword . Monster Vault: Threats to the Nentir Vale","page(s) 120."] },
  { id:"mvttnv-iron-circle-commander",name:"Iron Circle Commander",source:"mvttnv",level:5,role:"Soldier",roleModifier:"Elite",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:126,ac:21,fort:19,ref:16,will:17,initiative:4,perception:3,speed:"5",powers:[{name:"Flail",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 1d10 + 8 damage."},{name:"Devil's Tactics",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 1d10 + 7 damage, and the target grants combat advantage until the end of the commander's next turn. Effect: One of the commander's allies within 5 squares of the target can make a basic attack against the target as a free action."},{name:"Infernal Flames",action:"Standard",keywords:["fire"],recharge:"Encounter",description:"Attack: Close blast 5 (enemies in the blast); +8 vs. Reflex Hit: 2d6 + 5 fire damage, and the target is dazed (save ends). Effect: Allies in the blast gain 5 temporary hit points."},{name:"Tripping Flail",action:"Triggered",keywords:["weapon"],description:"Trigger: An enemy leaves a square adjacent to the commander. Attack (Opportunity Action): Melee 1 (the triggering enemy); +9 vs. Reflex Hit: The target falls prone. Skills Athletics +12, Intimidate +10"}],alignment:"Evil",languages:["Common Equipment : black surcoat","flail","heavy shield","scale armor . Monster Vault: Threats to the Nentir Vale","page(s) 73."] },
  { id:"mvttnv-kelson",name:"Kelson",source:"mvttnv",level:5,role:"Skirmisher",roleModifier:"Elite",xp:0,size:"Small",origin:"Natural",type:"Humanoid",hp:120,ac:20,fort:16,ref:19,will:16,initiative:9,perception:7,speed:"6",powers:[{name:"Gang Leader",action:"Aura",description:"Aura 3 Allies gain a +2 power bonus to saving throws while in the aura"},{name:"River Rat Tactics Kelson",action:"Trait",description:"has combat advantage against any enemy that is adjacent to at least one of his allies"},{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 2d6 + 6 damage."},{name:"Throwing Dagger",action:"Standard",keywords:["poison","weapon"],description:"Attack: Ranged 10 (one creature); +10 vs. AC Hit: 1d4 + 5 damage, and ongoing 5 poison damage (save ends). Flickering Blades ✦ At-Will Effect: Kelson uses short sword against one enemy, shifts up to 3 squares, and then uses throwing dagger against a different enemy. River Rat's Gambit ✦ Encounter Requirement: Kelson must be bloodied. Effect: Kelson makes a basic attack. If the attack hits, the target takes 2d6 extra damage. If the attack misses, Kelson takes 1d6 damage."},{name:"Second Chance",action:"Triggered",recharge:"Encounter",description:"Trigger: An enemy hits Kelson with an attack. Effect (Immediate Interrupt): The triggering enemy must reroll the attack and use the new result. Skills Acrobatics +12, Bluff +9, Stealth +12, Streetwise +9, Thievery +12"}],alignment:"Evil",languages:["Common Equipment : dagger x10","leather armor","short sword . Monster Vault: Threats to the Nentir Vale","page(s) 94."] },
  { id:"mvttnv-lizardfolk-dreadtail",name:"Lizardfolk Dreadtail",source:"mvttnv",level:5,role:"Soldier",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["reptile"],hp:62,ac:21,fort:17,ref:19,will:15,initiative:8,perception:2,speed:"6 (swamp walk)",powers:[{name:"Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 2d6 + 6 damage, and the target is slowed until the end of its next turn. Effect: The dreadtail marks the target until the end of the target's next turn."},{name:"Tail Slap",action:"Standard",description:"Attack: Melee 2 (one creature); +8 vs. Reflex Hit: 1d6 + 6 damage, and the target falls prone."},{name:"Slap Down",action:"Standard",recharge:"Recharge 3-6",description:"Effect: The dreadtail uses spear and tail slap."},{name:"Spirit Interference",action:"Triggered",description:"Trigger: An enemy within 5 squares of the dreadtail marks it. Effect (Free Action): Close burst 5 (triggering enemy). The dreadtail marks the target until the end of the target's next turn. Skills Athletics +9, Stealth +11"}],alignment:"Unaligned",languages:["Draconic Equipment : light shield","spear . Monster Vault: Threats to the Nentir Vale","page(s) 119","Dungeon Magazine 191."] },
  { id:"mvttnv-lizardfolk-shocker",name:"Lizardfolk Shocker",source:"mvttnv",level:5,role:"Artillery",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["reptile"],hp:50,ac:19,fort:17,ref:19,will:15,initiative:6,perception:2,speed:"6 (swamp walk)",powers:[{name:"Greatclub",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 1d6 + 5 damage."},{name:"Witch Lightning",action:"Standard",keywords:["lightning","radiant"],description:"Attack: Ranged 20 (one creature); +10 vs. Reflex Hit: 1d8 + 4 lightning and radiant damage, and each enemy within 2 squares of the target takes 5 lightning damage."},{name:"Ball of Lightning",action:"Standard",keywords:["lightning"],recharge:"Encounter",description:"Attack: Area burst 2 within 20 (creatures in the burst); +10 vs. Reflex Hit: 1d8 + 4 lightning damage, and ongoing 5 lightning damage (save ends). Miss: Half damage."},{name:"Sudden Jolt",action:"Triggered",keywords:["lightning","radiant"],description:"Trigger: An enemy within 20 squares of the shocker hits it with a ranged or an area attack. Effect (Immediate Reaction): Close burst 10 (triggering enemy in the burst). The target takes 5 lightning and radiant damage."}],alignment:"Unaligned",languages:["Draconic Equipment : greatclub . Monster Vault: Threats to the Nentir Vale","page(s) 118","Dungeon Magazine 191","Halls of Undermountain","page(s) 95."] },
  { id:"mvttnv-melech-ambrose",name:"Melech Ambrose",source:"mvttnv",level:5,role:"Skirmisher",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:68,ac:19,fort:17,ref:16,will:18,initiative:6,perception:10,speed:"5",senses:["Low-light vision"],resist:["5 fire"],powers:[{name:"Bloodthirsty",action:"Aura",description:"Aura 1 Bloodied enemies grant combat advantage while in the aura."},{name:"Drake Fervor",action:"Aura",description:"Aura 3 Drake allies gain a +2 power bonus to damage rolls and saving throws while in the aura"},{name:"Insufferable Antagonist",action:"Trait",description:"If Melech starts his turn subjected to one or more immobilizing, restraining, or slowing effects, he makes a saving throw"},{name:"If",action:"Trait",description:"he saves, those effects on him end"},{name:"Scimitar",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC. Melech has a +1 bonus to hit a bloodied target. Hit: 2d8 + 4 damage."},{name:"Fiendish Strike",action:"Standard",keywords:["weapon"],description:"Effect: Melech shifts up to 2 squares before the attack. Attack: Melee 1 (one creature); +8 vs. Reflex. Melech has a +1 bonus to hit a bloodied target. Hit: 2d8 + 4 damage. If Melech has combat advantage against the target, the target is also dazed until the end of Melech's next turn."},{name:"Hurl Flame",action:"Standard",keywords:["fire"],description:"Attack: Ranged 5 (one creature); +8 vs. Reflex. Melech has a +1 bonus to hit a bloodied target. Hit: 2d6 + 6 fire damage."},{name:"Infernal Wrath",action:"Triggered",keywords:["fire"],recharge:"Encounter",description:"Trigger: An enemy within 10 squares of Melech hits him with an attack. Effect (Free Action): The triggering enemy takes 1d6 + 6 fire damage. Skills Bluff +13, Diplomacy +13, History +11, Stealth +9, Streetwise +13"}],alignment:"Evil",languages:["Common","Supernal Equipment : chainmail","light shield","scimitar . Monster Vault: Threats to the Nentir Vale","page(s) 50."] },
  { id:"mvttnv-plague-demon-chaos-footsoldier",name:"Plague Demon Chaos Footsoldier",source:"mvttnv",level:5,role:"Soldier",roleModifier:"Minion",xp:50,size:"Medium",origin:"Elemental",type:"Beast",keywords:["demon"],hp:1,ac:21,fort:19,ref:17,will:15,initiative:6,perception:7,speed:"6",senses:["Darkvision"],powers:[{name:"Grabbing Claws",action:"Standard",description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 5 damage, and the target is grabbed (escape DC 15) if the plague demon has no creature grabbed."},{name:"Bite",action:"Standard",keywords:["disease"],description:"Attack: Melee 1 (one creature grabbed by the plague demon); +10 vs. AC Hit: 8 damage. At the end of the encounter, the target makes a saving throw. On a failure, the target contracts Abyssal plague (stage 1)."}],alignment:"Chaotic Evil",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 14","Halls of Undermountain","page(s) 96."] },
  { id:"mvttnv-plague-demon-chaos-hound",name:"Plague Demon Chaos Hound",source:"mvttnv",level:5,role:"Skirmisher",roleModifier:"Minion",xp:50,size:"Medium",origin:"Elemental",type:"Beast",keywords:["demon"],hp:1,ac:19,fort:18,ref:17,will:15,initiative:7,perception:3,speed:"8",senses:["Darkvision"],powers:[{name:"Pack Attack",action:"Trait",description:"The plague demon's attacks deal 2 extra damage for each other plague demon that is adjacent to the target"},{name:"Bite",action:"Standard",keywords:["disease"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 5 damage, and the plague demon can shift 1 square. At the end of the encounter, the target makes a saving throw. On a failure, the target contracts Abyssal plague (stage 1)."}],alignment:"Chaotic Evil",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 14","Dungeon Magazine 187."] },
  { id:"mvttnv-raven-roost-cutthroat",name:"Raven Roost Cutthroat",source:"mvttnv",level:5,role:"Lurker",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",hp:49,ac:19,fort:16,ref:19,will:16,initiative:11,perception:9,speed:"6",powers:[{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 3d4 + 6 damage."},{name:"Garrote",action:"Standard",keywords:["weapon"],description:"Requirement: The cutthroat must not be grabbing a creature. Attack: Melee 1 (one creature); +8 vs. Reflex Hit: The target is grabbed (escape DC 22) until the end of the cutthroat's next turn. Until the grab ends, the cutthroat has superior cover, and neither it nor the target can be pulled, pushed, or slid."},{name:"Arterial Cut",action:"Standard",keywords:["weapon"],description:"Effect: Melee 1 (one creature grabbed by the cutthroat). The target takes 2d10 + 5 damage, and ongoing 10 damage (save ends). The grab then ends."},{name:"Quick Cut",action:"Triggered",description:"Trigger: An enemy escapes the cutthroat's grab. Effect (Immediate Interrupt): The cutthroat uses dagger against the triggering enemy. Skills Athletics +9, Stealth +12"}],alignment:"Evil",languages:["Common Equipment : studded leather","dagger","garrote . Monster Vault: Threats to the Nentir Vale","page(s) 93","Dungeon Magazine 208","Dungeon Magazine 213."] },
  { id:"mvttnv-raven-roost-grenadier",name:"Raven Roost Grenadier",source:"mvttnv",level:5,role:"Controller",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",hp:61,ac:19,fort:16,ref:18,will:16,initiative:6,perception:4,speed:"6",vulnerable:["5 fire until the end of the encounter. Minor Actions Grenadier's Rush ✦ Encounter Effect: The grenadier moves up to its"],powers:[{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 2d6 + 6 damage."},{name:"Fire Bomb",action:"Standard",keywords:["fire"],description:"Attack: Area burst 1 within 5 (creatures in the burst); +8 vs. Fortitude Hit: 1d8 + 5 fire damage, and the target falls prone. Miss: Half damage."},{name:"Smoke Bomb",action:"Standard",recharge:"Encounter",description:"Attack: Area burst 1 within 5 (creatures in the burst); +8 vs. Fortitude Hit: The target is dazed and takes ongoing 10 damage (save ends both). Effect: Squares in the burst are lightly obscured until the end of the encounter."},{name:"Oil Slick",action:"Standard",recharge:"Encounter",description:"Attack: Area burst 1 within 5 (creatures in the burst); +8 vs. Reflex Hit: The target falls prone. Effect: Each target gains vulnerable 5 fire until the end of the encounter."},{name:"Grenadier's Rush",action:"Minor",recharge:"Encounter",description:"Effect: The grenadier moves up to its speed. Skills Athletics +9, Stealth +11"}],alignment:"Evil",languages:["Common Equipment : 8 fire bombs","flask of oil","smoke bomb","leather armor","short sword . Monster Vault: Threats to the Nentir Vale","page(s) 92."] },
  { id:"mvttnv-tigerclaw-fang-wielder",name:"Tigerclaw Fang-Wielder",source:"mvttnv",level:5,role:"Brute",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",hp:77,ac:17,fort:19,ref:17,will:15,initiative:5,perception:4,speed:"6",senses:["Low-light vision"],powers:[{name:"Heavy War Pick",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 2d8 + 7 damage, or 3d8 + 7 while the fang-wielder is bloodied."},{name:"Fang of the Sabertooth",action:"Standard",keywords:["weapon"],recharge:"Recharge 4-6",description:"Attack: Melee 1 (one creature); +8 vs. Fortitude Hit: 3d12 + 5 damage, and the target falls prone. If the fang-wielder scores a critical hit, the target also takes ongoing 5 damage (save ends)."},{name:"Winter's Rage",action:"Triggered",keywords:["weapon"],recharge:"Encounter",description:"Trigger: The fang-wielder first becomes bloodied. Attack (Immediate Reaction): Close burst 1 (enemies in the burst); +10 vs. AC Hit: 2d12 + 3 damage, and the target falls prone. Miss: Half damage. Effect: The fang-wielder can push each target 1 square. Skills Athletics +11"}],alignment:"Unaligned",languages:["Common Equipment : heavy war pick","hide armor . Monster Vault: Threats to the Nentir Vale","page(s) 102","Dungeon Magazine 220."] },
  { id:"mvttnv-tigerclaw-shaman",name:"Tigerclaw Shaman",source:"mvttnv",level:5,role:"Controller",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",hp:52,ac:19,fort:15,ref:17,will:19,initiative:5,perception:11,speed:"6",senses:["Low-light vision"],powers:[{name:"Razorclaw Healing",action:"Trait",description:"While the shaman is bloodied and has at least 1 hit point, it regains 4 hit points at the start of each of its turns"},{name:"Longspear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +10 vs. AC Hit: 1d10 + 8 damage, and the target is slowed until the end of its next turn."},{name:"Phantom Fangs",action:"Standard",keywords:["implement","psychic"],description:"Attack: Ranged 5 (one creature); +8 vs. Will Hit: 2d8 + 4 psychic damage, and the target is immobilized until the end of its next turn. Miss: The target is slowed until the end of its next turn."},{name:"Concussive Roar",action:"Minor",recharge:"Encounter",description:"Attack: Close blast 3 (enemies in the blast); +8 vs. Will Hit: The shaman pushes the target up to 3 squares, and the target is immobilized (save ends). Miss: The shaman can push the target 1 square. Skills Heal +11, Nature +11, Religion +9"}],alignment:"Unaligned",languages:["Common Equipment : hide armor","longspear","totem . Monster Vault: Threats to the Nentir Vale","page(s) 103","Dungeon Magazine 220."] },
  { id:"mvttnv-twig-blight-swarm",name:"Twig Blight Swarm",source:"mvttnv",level:5,role:"Brute",xp:200,size:"Large",origin:"Fey",type:"Humanoid",keywords:["plant","swarm"],hp:74,ac:17,fort:17,ref:18,will:15,initiative:6,perception:9,speed:"5 (forest walk), climb 5",senses:["Darkvision"],resist:["half damage from melee and ranged attacks"],vulnerable:["10 against close and area attacks"],powers:[{name:"Swarm Attack",action:"Aura",description:"Aura 1 Any enemy that ends its turn in the aura takes 3 damage"},{name:"Rooted",action:"Trait",description:"The swarm cannot be pulled, pushed, or slid"},{name:"Swarm",action:"Trait",description:"The swarm can occupy the same space as another creature, and an enemy can enter its space, which is difficult terrain"},{name:"It",action:"Trait",description:"can squeeze through any opening that is large enough for a Small creature"},{name:"Swarm of Claws",action:"Standard",keywords:["poison"],description:"Attack: Close burst 1 (enemies in the burst); +10 vs. AC Hit: 2d6 + 8 poison damage."}],alignment:"Chaotic Evil",languages:["Elven Monster Vault: Threats to the Nentir Vale","page(s) 109","Dungeon Magazine 212."] },
  { id:"mvttnv-wolf-runner-swiftarrow",name:"Wolf Runner Swiftarrow",source:"mvttnv",level:5,role:"Artillery",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",hp:50,ac:19,fort:16,ref:18,will:15,initiative:6,perception:3,speed:"6",powers:[{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 1d6 + 10 damage."},{name:"Longbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 20/40 (one or two creatures); +12 vs. AC Hit: 1d10 + 5 damage."},{name:"Close Shot",action:"Triggered",recharge:"Encounter",description:"Trigger: An enemy enters a square adjacent to the swiftarrow. Effect (Immediate Reaction): The swiftarrow makes a ranged basic attack against the triggering enemy. This attack does not provoke opportunity attacks. Skills Stealth +11, Streetwise +7, Thievery +11"}],alignment:"Unaligned",languages:["Common Equipment : arrow x12","leather armor","longbow","short sword . Monster Vault: Threats to the Nentir Vale","page(s) 121."] },
  { id:"mvttnv-blackfang-feaster",name:"Blackfang Feaster",source:"mvttnv",level:6,role:"Brute",xp:250,size:"Medium",origin:"Natural",type:"Humanoid",hp:89,ac:18,fort:19,ref:18,will:18,initiative:6,perception:4,speed:"7",senses:["Low-light vision"],powers:[{name:"Pack Attack",action:"Trait",description:"The feaster's attacks deal 5 extra damage to any enemy adjacent to two or more of the feaster's allies"},{name:"Ravening Bite",action:"Standard",keywords:["poison"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d10 + 4 poison damage, and the target is slowed (save ends)."},{name:"Devour",action:"Standard",description:"Attack: Melee 1 (one bloodied creature); +9 vs. Fortitude Hit: 3d10 + 5 damage, and the target falls prone. Skills Intimidate +11, Stealth +11"}],alignment:"Chaotic Evil",languages:["Abyssal","Common Equipment : bone armor Monster Vault: Threats to the Nentir Vale","page(s) 25","Dungeon Magazine 212."] },
  { id:"mvttnv-blackfang-hyena-pack",name:"Blackfang Hyena Pack",source:"mvttnv",level:6,role:"Brute",xp:250,size:"Large",origin:"Natural",type:"Beast",keywords:["swarm"],hp:85,ac:18,fort:18,ref:17,will:16,initiative:5,perception:9,speed:"7",senses:["Low-light vision"],resist:["half damage from melee and ranged attacks"],vulnerable:["10 to close and area attacks"],powers:[{name:"Swarm Attack",action:"Aura",description:"Aura 1 Any enemy that ends its turn in the aura takes 5 damage, or 10 if the enemy is adjacent to two or more of the pack's allies"},{name:"Swarm",action:"Trait",description:"The pack can occupy the same space as another creature, and an enemy can enter its space, which is difficult terrain"},{name:"The",action:"Trait",description:"pack cannot be pulled, pushed, or slid by melee or ranged attacks"},{name:"It",action:"Trait",description:"can squeeze through any opening that is large enough for a Medium creature"},{name:"Swarm of Grasping Jaws",action:"Standard",description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 1d10 + 7 damage, and the target is immobilized (save ends). If the pack is no longer adjacent to the target, this immobilized condition ends."}],alignment:"Unaligned",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 26."] },
  { id:"mvttnv-bloodspear-shiv",name:"Bloodspear Shiv",source:"mvttnv",level:6,role:"Skirmisher",xp:250,size:"Medium",origin:"Natural",type:"Humanoid",hp:75,ac:20,fort:19,ref:17,will:18,initiative:6,perception:6,speed:"6",senses:["Low-light vision"],powers:[{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d8 + 5 damage."},{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 5 (one creature); +11 vs. AC Hit: 2d8 + 5 damage."},{name:"Shifting Shank",action:"Standard",description:"Effect: The shiv shifts up to its speed and uses dagger once at any point during the movement. If the attack bloodies the target, the shiv uses dagger a second time against the same target as a free action."},{name:"Savage Demise",action:"Triggered",recharge:"Encounter",description:"Trigger: The shiv drops to 0 hit points. Effect (Free Action): The shiv takes a standard action. Skills Acrobatics +9"}],alignment:"Chaotic Evil",languages:["Common","Giant Equipment : dagger x12","leather armor . Monster Vault: Threats to the Nentir Vale","page(s) 37."] },
  { id:"mvttnv-daggerburg-slayer",name:"Daggerburg Slayer",source:"mvttnv",level:6,role:"Brute",xp:250,size:"Medium",origin:"Natural",type:"Humanoid",hp:85,ac:18,fort:19,ref:17,will:17,initiative:6,perception:6,speed:"6",senses:["Low-light vision"],powers:[{name:"Combat Adept At",action:"Trait",description:"the start of an encounter, the slayer's attacks deal 1d10 extra damage against any enemy that has not yet acted during the encounter"},{name:"Greataxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d12 + 3 damage, or 2d12 +8 while the slayer is bloodied. If this attack bloodies the target, the target takes 5 extra damage."},{name:"Hobgoblin Resilience",action:"Triggered",recharge:"Encounter",description:"Trigger: The slayer is subjected to an effect that a save can end. Effect (Immediate Reaction): The slayer makes a saving throw against the triggering effect."}],alignment:"Evil",languages:["Common Equipment : greataxe","hide armor . Monster Vault: Threats to the Nentir Vale","page(s) 40."] },
  { id:"mvttnv-daggerburg-war-mage",name:"Daggerburg War Mage",source:"mvttnv",level:6,role:"Artillery",xp:250,size:"Medium",origin:"Natural",type:"Humanoid",hp:58,ac:20,fort:17,ref:19,will:18,initiative:6,perception:7,speed:"6",senses:["Low-light vision"],powers:[{name:"Combat Adept At",action:"Trait",description:"the start of an encounter, the war mage's attacks deal 1d10 extra damage against any enemy that has not yet acted during the encounter"},{name:"Staff",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 1d8 + 5 damage."},{name:"Stabbing Flame",action:"Standard",keywords:["fire","implement"],description:"Attack: Ranged 15 (one creature); +11 vs. Fortitude Hit: 1d8 + 5 fire damage, and ongoing 5 fire damage (save ends)."},{name:"Icy Stream",action:"Standard",keywords:["cold","implement"],recharge:"Recharge 4-6",description:"Attack: Ranged 15 (one creature); +11 vs. Reflex Hit: 1d10 + 9 cold damage, and the war mage slides the target up to 3 squares. Skills Arcana +13"}],alignment:"Evil",languages:["Common","Goblin Equipment : staff implement . Monster Vault: Threats to the Nentir Vale","page(s) 40."] },
  { id:"mvttnv-elder-peryton",name:"Elder Peryton",source:"mvttnv",level:6,role:"Soldier",roleModifier:"Elite",xp:500,size:"Large",origin:"Natural",type:"Beast",hp:144,ac:22,fort:20,ref:18,will:16,initiative:9,perception:11,speed:"2, fly 10",powers:[{name:"Peryton's Prey At",action:"Trait",description:"the start of each of its turns, the peryton chooses one creature it can see"},{name:"That",action:"Trait",description:"creature is the peryton's prey until the start of the peryton's next turn"},{name:"Unhindered",action:"Trait",description:"When the peryton moves on its turn, it pulls with it any creature grabbed by it"},{name:"The",action:"Trait",description:"peryton can pull the creature vertically off a solid surface. During this movement, the creature remains grabbed, and this movement does not provoke an opportunity attack from the grabbed creature"},{name:"Antler Bash",action:"Standard",description:"Attack: Melee 2 (one creature); +11 vs. AC Hit: 2d8 + 3 damage, or 2d8 + 8 against a creature designated as the peryton's prey. In addition, the target falls prone."},{name:"Claw Snatch",action:"Standard",recharge:"Recharge 3-6",description:"Effect: Before and after the attack, the peryton can fly up to half its fly speed. Attack: Melee 1 (one Medium or smaller creature designated as the peryton's prey); +9 vs. Reflex Hit: 3d6 + 8 damage, and the target is grabbed (escape DC 15)."},{name:"Feast",action:"Standard",keywords:["healing"],recharge:"Encounter",description:"Effect: Melee 1 (one dying humanoid). The target dies, and the peryton regains 20 hit points."},{name:"Cursed Bite",action:"Minor",description:"1/round Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d6 + 7 damage. Effect: Until the end of the peryton's next turn, the target takes 5 damage whenever it attacks a creature other than the peryton."},{name:"Stealth Dive",action:"Triggered",recharge:"Encounter",description:"Trigger: The creature designated as the peryton's prey makes an attack that doesn't include the peryton as a target. Effect (Immediate Reaction): The peryton charges the triggering creature."}],alignment:"Chaotic Evil",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 85."] },
  { id:"mvttnv-geriesh",name:"Geriesh",source:"mvttnv",level:6,role:"Skirmisher",roleModifier:"Elite",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:136,ac:20,fort:17,ref:20,will:18,initiative:9,perception:11,speed:"6",senses:["Low-light vision"],powers:[{name:"Swiftshadow Master",action:"Aura",description:"Aura 5 Allies in the aura gain a +4 power bonus to initiative checks and Stealth checks"},{name:"Willing Prey Geriesh",action:"Trait",description:"has combat advantage against any creature marking him"},{name:"Katar",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d6 + 4 damage, or 3d6 + 7 against a target granting combat advantage to Geriesh. If this attack deals more than 20 damage to the target, it falls unconscious (save ends)."},{name:"Double Attack",action:"Standard",description:"Effect: Geriesh uses katar twice, and can move up to his speed after the first attack."},{name:"Shadow Leap",action:"Move",keywords:["teleportation"],recharge:"Recharge 4-6",description:"Effect: Geriesh teleports up to his speed."},{name:"Dagger Flick",action:"Minor",keywords:["poison","weapon"],recharge:"Encounter",description:"Attack: Ranged 3 (one creature); +9 vs. Fortitude Hit: 2d6 + 4 damage, and the target is immobilized and takes ongoing 5 poison damage (save ends both). Miss: The target is immobilized until the end of its next turn. Skills Bluff +11, Stealth +12"}],alignment:"Evil",languages:["Common Equipment : studded leather","dagger","katar . Monster Vault: Threats to the Nentir Vale","page(s) 92."] },
  { id:"mvttnv-gray-company-fallen-hero",name:"Gray Company Fallen Hero",source:"mvttnv",level:6,role:"Brute",xp:250,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:89,ac:18,fort:19,ref:17,will:16,initiative:5,perception:4,speed:"5",resist:["10 necrotic"],immune:["disease, poison"],vulnerable:["5 radiant"],powers:[{name:"Grim Solidarity",action:"Trait",description:"If the fallen hero starts its turn adjacent to a creature that has grim solidarity, it can make a saving throw against one effect that a save can end"},{name:"Longsword",action:"Standard",keywords:["necrotic","weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 3d8 + 4 necrotic damage, and the target gains vulnerable 5 necrotic until the end of the fallen hero's next turn."},{name:"Nerath's Vengeance",action:"Standard",recharge:"Recharge when first bloodied",description:"Effect: The fallen hero uses longsword against each enemy adjacent to it."}],alignment:"Evil",languages:["Common Equipment : breastplate","heavy shield","longsword . Monster Vault: Threats to the Nentir Vale","page(s) 62."] },
  { id:"mvttnv-hellghost-dark-drake",name:"Hellghost Dark Drake",source:"mvttnv",level:6,role:"Brute",xp:250,size:"Large",origin:"Natural",type:"Beast",keywords:["reptile"],hp:85,ac:18,fort:19,ref:19,will:17,initiative:7,perception:5,speed:"8",senses:["Darkvision"],resist:["5 fire"],vulnerable:["5 fire."],powers:[{name:"Ghostfire Radiance",action:"Aura",description:"Aura 1 Creatures in the aura gain vulnerable 5 fire."},{name:"Fiery Bite",action:"Standard",keywords:["fire"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d10 + 6 fire damage."},{name:"Ghostfire Rampage",action:"Standard",keywords:["fire"],recharge:"Encounter",description:"Effect: The drake moves up to its speed and can enter enemies' spaces during the move. Each time the drake enters an enemy's space for the first time during the move, it makes the following attack against that enemy. Attack: Melee 0 (enemy in the space); +9 vs. Reflex Hit: 2d10 + 2 fire damage. The enemy falls prone, and it takes ongoing 5 fire damage (save ends)."},{name:"Pulsing Ghostfire",action:"Triggered",keywords:["fire"],recharge:"Encounter",description:"Trigger: The drake is immobilized, restrained, or stunned. Effect (No Action): Close burst 2 (creatures in the burst); +9 vs. Reflex Hit: 3d10 + 4 fire damage, and the target falls prone. Miss: Half damage."}],alignment:"Evil",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 43."] },
  { id:"mvttnv-icicle-swarm",name:"Icicle Swarm",source:"mvttnv",level:6,role:"Skirmisher",xp:250,size:"Medium",origin:"Elemental",type:"Animate",keywords:["cold","swarm"],hp:68,ac:20,fort:19,ref:21,will:18,initiative:8,perception:3,speed:"0 (ice walk), fly 7 (hover)",resist:["10 cold, half damage from melee and ranged attacks"],immune:["disease, poison"],vulnerable:["10 fire,","10 against close and area attacks"],powers:[{name:"Swarm Attack",action:"Aura",keywords:["cold"],description:"Aura 1 Any enemy that ends its turn in the aura takes 5 cold damage"},{name:"Swarm",action:"Trait",description:"The swarm can occupy the same space as another creature, and an enemy can enter its space, which is difficult terrain"},{name:"The",action:"Trait",description:"swarm cannot be pulled, pushed, or slid by melee or ranged attacks"},{name:"It",action:"Trait",description:"can squeeze through any opening that is large enough for a Tiny creature"},{name:"Icicle Stab",action:"Standard",keywords:["cold"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 3d6 + 4 cold damage. On a critical hit, the target is immobilized (save ends). Effect: Before or after the attack, the swarm can shift up to 2 squares."}],alignment:"Evil",languages:["Primordial Monster Vault: Threats to the Nentir Vale","page(s) 55."] },
  { id:"mvttnv-phantom-brigade-squire",name:"Phantom Brigade Squire",source:"mvttnv",level:6,role:"Soldier",roleModifier:"Minion",xp:63,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:22,fort:20,ref:18,will:17,initiative:6,perception:4,speed:"6; phasing",senses:["Darkvision"],immune:["disease, poison"],powers:[{name:"Unrelenting Brigade Whenever",action:"Trait",description:"an ally who also has this trait drops to 0 hit points within 5 squares of the squire, the squire gains a +2 power bonus to attack rolls until the end of its next turn"},{name:"Soulbound Short Sword",action:"Standard",keywords:["psychic","weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 5 psychic damage."},{name:"Spectral Crossbow",action:"Standard",keywords:["psychic","weapon"],description:"Attack: Ranged 10 (one creature); +11 vs. AC Hit: 5 psychic damage."},{name:"Shielding Martyr",action:"Triggered",description:"Trigger: An enemy hits an ally adjacent to the squire with a melee attack. Effect (Immediate Interrupt): The squire becomes the target of the attack."}],alignment:"Lawful Good",languages:["Common Monster Vault: Threats to the Nentir Vale","page(s) 87."] },
  { id:"mvttnv-plague-demon-chaos-beast",name:"Plague Demon Chaos Beast",source:"mvttnv",level:6,role:"Skirmisher",xp:250,size:"Medium",origin:"Elemental",type:"Beast",keywords:["demon"],hp:76,ac:20,fort:19,ref:18,will:17,initiative:9,perception:6,speed:"8",senses:["Darkvision"],resist:["5 to the triggering damage type until the end of the encounter or until it uses variable resistance again. Skills Athletics +13, Stealth +12"],powers:[{name:"Chaotic Growl",action:"Aura",keywords:["fear"],description:"Aura 1 Enemies grant combat advantage while in the aura."},{name:"Bite",action:"Standard",keywords:["disease"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d8 + 3 damage. At the end of the encounter, the target makes a saving throw. On a failure, the target contracts Abyssal plague (stage 1)."},{name:"Claws",action:"Standard",description:"Attack: Melee 1 (one or two creatures); +11 vs. AC Hit: 2d6 + 2 damage, and the plague demon can shift 1 square."},{name:"Variable Resistance",action:"Triggered",recharge:"2/Encounter",description:"Trigger: The plague demon takes acid, cold, fire, lightning, or thunder damage. Effect (Free Action): The plague demon gains resist 5 to the triggering damage type until the end of the encounter or until it uses variable resistance again. Skills Athletics +13, Stealth +12"}],alignment:"Chaotic Evil",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 15."] },
  { id:"mvttnv-plague-demon-chaos-bender",name:"Plague Demon Chaos Bender",source:"mvttnv",level:6,role:"Controller",xp:250,size:"Large",origin:"Elemental",type:"Beast",keywords:["demon"],hp:72,ac:20,fort:17,ref:19,will:18,initiative:8,perception:7,speed:"8",senses:["Darkvision"],resist:["5 to the triggering damage type until the end of the encounter or until it uses variable resistance again."],powers:[{name:"Chaotic Field",action:"Aura",description:"Aura 2 When any enemy ends its turn in the aura, the plague demon slides it up to 2 squares as a free action."},{name:"Bite",action:"Standard",keywords:["disease"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d6 + 7 damage. At the end of the encounter, the target makes a saving throw. On a failure, the target contracts Abyssal plague (stage 1)."},{name:"Frenzy of Claws",action:"Standard",description:"Attack: Close burst 1 (enemies in the burst); +9 vs. Reflex Hit: 1d6 + 2 damage, and the target is slowed and takes ongoing 5 damage (save ends both)."},{name:"Variable Resistance",action:"Triggered",recharge:"2/Encounter",description:"Trigger: The plague demon takes acid, cold, fire, lightning, or thunder damage. Effect (Free Action): The plague demon gains resist 5 to the triggering damage type until the end of the encounter or until it uses variable resistance again."}],alignment:"Chaotic Evil",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 15","Dungeon Magazine 187."] },
  { id:"mvttnv-plague-demon-chaos-knight",name:"Plague Demon Chaos Knight",source:"mvttnv",level:6,role:"Soldier",xp:250,size:"Medium",origin:"Elemental",type:"Humanoid",keywords:["demon"],hp:78,ac:22,fort:21,ref:17,will:16,initiative:7,perception:4,speed:"5",senses:["Darkvision"],resist:["5 to the triggering damage type until the end of the encounter or until it uses variable resistance again."],powers:[{name:"Crimson Retribution",action:"Aura",description:"Aura 1 Whenever an enemy in the aura makes an attack that doesn't include the plague demon as a target, the enemy takes 5 damage."},{name:"Slam",action:"Standard",description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d6 + 7 damage, and the target falls prone."},{name:"Crystal Blade",action:"Standard",keywords:["disease","weapon"],recharge:"Recharge 3-6",description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 3d8 + 7 damage. At the end of the encounter, the target makes a saving throw. On a failure, the target contracts Abyssal plague (stage 1)."},{name:"Variable Resistance",action:"Triggered",recharge:"2/Encounter",description:"Trigger: The plague demon takes acid, cold, fire, lightning, or thunder damage. Effect (Free Action): The plague demon gains resist 5 to the triggering damage type until the end of the encounter or until it uses variable resistance again."}],alignment:"Chaotic Evil",languages:["Abyssal Monster Vault: Threats to the Nentir Vale","page(s) 16."] },
  { id:"mvttnv-raven-roost-outlaw-veteran",name:"Raven Roost Outlaw Veteran",source:"mvttnv",level:6,role:"Brute",xp:250,size:"Medium",origin:"Natural",type:"Humanoid",hp:86,ac:18,fort:20,ref:18,will:16,initiative:4,perception:3,speed:"6",powers:[{name:"Bastard Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d10 + 6 damage."},{name:"Mighty Blow",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d10 + 6 damage, and the veteran can push the target 1 square and then shift 1 square to a square the target vacated."},{name:"Swath of Death",action:"Standard",description:"Recharge if either attack misses Effect: The veteran uses mighty blow twice."},{name:"Forceful Shove",action:"Minor",description:"Attack: Melee 1 (one creature); +9 vs. Fortitude Hit: The veteran pushes the target 1 square. Skills Athletics +12, Stealth +9"}],alignment:"Evil",languages:["Common Equipment : studded leather","bastard sword . Monster Vault: Threats to the Nentir Vale","page(s) 93","Dungeon Magazine 213."] },
  { id:"mvttnv-raven-roost-sharpshooter",name:"Raven Roost Sharpshooter",source:"mvttnv",level:6,role:"Artillery",xp:250,size:"Medium",origin:"Natural",type:"Humanoid",hp:55,ac:20,fort:17,ref:19,will:17,initiative:7,perception:10,speed:"6",powers:[{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 1d6 + 7 damage."},{name:"Crossbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 15/30 (one creature); +13 vs. AC Hit: 2d8 + 5 damage."},{name:"Careful Aim",action:"Move",description:"Effect: The sharpshooter chooses an enemy it can see. If it can still see that enemy at the start of its next turn, its crossbow attack power targets the enemy's Reflex, instead of AC, and deals 5 extra damage against it. These benefits last until the end of that turn."},{name:"Archer's Decoy",action:"Free",recharge:"Recharge when first bloodied",description:"Effect: The sharpshooter gains a +2 bonus to AC and Reflex until the start of its next turn. Skills Stealth +12"}],alignment:"Evil",languages:["Common Equipment : studded leather","crossbow","crossbow bolt x20","short sword . Monster Vault: Threats to the Nentir Vale","page(s) 93","Dungeon Magazine 206","Dungeon Magazine 210","Dungeon Magazine 213."] },
  { id:"mvttnv-sabertooth-tiger",name:"Sabertooth Tiger",source:"mvttnv",level:6,role:"Soldier",xp:250,size:"Large",origin:"Natural",type:"Beast",keywords:["mount"],hp:72,ac:22,fort:19,ref:19,will:18,initiative:9,perception:11,speed:"8, climb 4",senses:["Low-light vision"],powers:[{name:"Charging Pounce",action:"Trait",description:"The tiger is not limited to taking only free actions immediately after a charge"},{name:"Tiger Charge",action:"Trait",keywords:["mount"],description:"The tiger's rider gains a +2 power bonus to damage rolls on charge attacks"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +11 vs. AC. If the tiger is grabbing a creature, it can make this attack only against that creature. Hit: 2d8 + 3 damage, or 3d8 + 3 if the attack was part of a charge. In addition, the target is grabbed (escape DC 15)."},{name:"Puncturing Fangs",action:"Standard",description:"Effect: Melee 1 (one creature grabbed by the tiger). The target takes 2d10 damage, and ongoing 5 damage (save ends). Skills Acrobatics +12, Athletics +12, Stealth +12"}],alignment:"Unaligned",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 103."] },
  { id:"mvttnv-scargash-tigerclaw-chief",name:"Scargash, Tigerclaw Chief",source:"mvttnv",level:6,role:"Brute",roleModifier:"Elite",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:176,ac:17,fort:18,ref:17,will:17,initiative:6,perception:5,speed:"6",senses:["Low-light vision"],powers:[{name:"Encircle the Prey",action:"Aura",description:"Aura 5 While in the aura, allies gain a +2 power bonus to damage rolls against enemies they are flanking"},{name:"Razorclaw Resilience",action:"Trait",description:"While bloodied, Scargash gains a +2 power bonus to all defenses"},{name:"War Pick",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d8 + 4 damage, and ongoing 5 damage (save ends). Double Attack ✦ At-Will Effect: Scargash uses war pick twice. If he hits the same target twice, the target takes a -2 penalty to all defenses and ongoing 5 damage (save ends both), rather than the normal ongoing damage."},{name:"Staggering Swipe",action:"Standard",keywords:["weapon"],recharge:"Encounter",description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d10 + 5 damage. Miss: Half damage. Effect: Scargash slides the target up to 3 squares to a square adjacent to one or more of his enemies. Each enemy that the target ends this movement adjacent to takes 10 damage and falls prone. Skills Athletics +12, Intimidate +11"}],alignment:"Unaligned",languages:["Common Equipment : hide armor","war pick x2. Monster Vault: Threats to the Nentir Vale","page(s) 100."] },
  { id:"mvttnv-sylish-kreed",name:"Sylish Kreed",source:"mvttnv",level:6,role:"Skirmisher",roleModifier:"Elite",xp:500,size:"Medium",origin:"Natural",type:"Humanoid",hp:144,ac:20,fort:19,ref:18,will:17,initiative:8,perception:10,speed:"6 (8 in wolf form)",senses:["Low-light vision"],powers:[{name:"Regeneration Kreed",action:"Trait",description:"regains 5 hit points whenever he starts his turn and has at least 1 hit point"},{name:"When",action:"Trait",description:"he takes damage from a silvered weapon, his regeneration does not function on his next turn"},{name:"Greatsword",action:"Standard",keywords:["weapon"],description:"Requirement: Kreed must be in human or hybrid form. Attack: Melee 1 (one creature); +11 vs. AC Hit: 1d10 + 9 damage."},{name:"Claw",action:"Standard",description:"Requirement: Kreed must be in wolf or hybrid form. Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d10 + 3 damage, or 2d10 + 8 against a bloodied target, and Kreed shifts up to 4 squares."},{name:"Bite",action:"Standard",keywords:["disease"],description:"Requirement: Kreed must be in wolf or hybrid form. Attack: Melee 1 (one creature); +11 vs. AC Hit: 1d10 + 9 damage, and the target falls prone. At the end of the encounter, the target makes a saving throw. On a failure, the target contracts werewolf moon frenzy (stage 1)."},{name:"Bloodmoon Fury",action:"Standard",description:"Effect: Kreed either uses claw and bite or uses greatsword twice."},{name:"Change Shape",action:"Minor",keywords:["polymorph"],description:"Effect: Kreed alters his physical form to appear as a Medium wolf, a unique human, or a hybrid until he uses change shape again or until he dies (whereupon he reverts to human form). He retains his statistics in his new form. His clothing, armor, and other possessions do not change. Skills Bluff +10, Diplomacy +10, Intimidate +10"}],alignment:"Unaligned",languages:["Common","Elven Equipment : chainmail","greatsword . Werewolf Moon Frenzy Level 6 Disease Stage 0 : The target recovers from the disease. Stage 1 : While affected by stage 1","the target takes a -2 penalty to Will. Stage 2 : While affected by stage 2","whenever the target becomes bloodied","it makes a melee basic attack as a free action against an ally adjacent to it. Stage 3 : While affected by stage 3","whenever the target is hit by an attack","it makes a melee basic attack as a free action against an ally adjacent to it. Check : At the end of each extended rest","the target makes an Endurance check if it is at stage 1 or 2. 10 or lower : The stage of the disease increases by one. 11-14 : No Change 15 or higher : The stage of the disease decreases by one. Monster Vault: Threats to the Nentir Vale","page(s) 120."] },
  { id:"mvttnv-tiktag",name:"Tiktag",source:"mvttnv",level:6,role:"Artillery",xp:0,size:"Small",origin:"Natural",type:"Humanoid",keywords:["reptile"],hp:56,ac:20,fort:16,ref:19,will:18,initiative:7,perception:7,speed:"6",senses:["Low-light vision"],powers:[{name:"Prophet",action:"Trait",description:"of the Elemental Eye While within 10 squares of Vestapalk, Tiktag rolls twice on saving throws, taking the better result"},{name:"Fetish-Adorned Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 1d8 + 5 damage."},{name:"Poison Orb",action:"Standard",keywords:["implement","poison"],description:"Attack: Ranged 15 (one creature); +11 vs. Reflex Hit: 2d8 + 5 poison damage."},{name:"Dragon Breath",action:"Standard",keywords:["poison"],recharge:"Encounter",description:"Attack: Close blast 3 (creatures in the blast); +9 vs. Fortitude Hit: 2d10 + 3 poison damage. Miss: Half damage."},{name:"Shifty",action:"Minor",description:"Effect: Tiktag shifts 1 square."},{name:"Incite Faith",action:"Minor",recharge:"Encounter",description:"Effect: Close burst 10 (kobold allies in the burst). Each target gains 5 temporary hit points and can take a free action to shift 1 square."},{name:"Fierce Rebuke",action:"Triggered",keywords:["fear"],recharge:"Encounter",description:"Trigger: An enemy ends its movement adjacent to Tiktag. Attack (Free Action): Melee 1 (the triggering enemy); +9 vs. Will Hit: Tiktag pushes the target up to 3 squares, and it is immobilized (save ends). Miss: Tiktag pushes the target up to 3 squares, and it is slowed (save ends). Skills Religion +8, Stealth +12"}],alignment:"Evil",languages:["Common","Draconic Equipment : spear (implement)","bone mask","hide armor . Monster Vault: Threats to the Nentir Vale","page(s) 112."] },
  { id:"mvttnv-adderbrood-dark-drake",name:"Adderbrood Dark Drake",source:"mvttnv",level:7,role:"Skirmisher",xp:300,size:"Medium",origin:"Natural",type:"Beast",keywords:["reptile"],hp:79,ac:21,fort:19,ref:21,will:18,initiative:10,perception:5,speed:"8, burrow 4",senses:["Darkvision"],resist:["5 poison"],powers:[{name:"Adder's Mobility",action:"Trait",description:"While an enemy is slowed or immobilized by the drake, that enemy cannot make opportunity attacks against the drake, and the drake can enter its space"},{name:"Bite",action:"Standard",keywords:["poison"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 2d10 + 4 damage, and the target is slowed until the end of the drake's next turn."},{name:"Venomous Strike",action:"Standard",keywords:["poison"],description:"Attack: Melee 1 (one creature slowed by the drake); +10 vs. Fortitude Hit: 2d10 + 4 damage, and ongoing 5 poison damage (save ends). First Failed Saving Throw: The target is immobilized and takes ongoing 5 poison damage (save ends both). Skills Stealth +13"}],alignment:"Evil",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 43."] },
  { id:"mvttnv-blackfang-howler",name:"Blackfang Howler",source:"mvttnv",level:7,role:"Skirmisher",xp:300,size:"Medium",origin:"Natural",type:"Humanoid",hp:77,ac:21,fort:17,ref:21,will:19,initiative:10,perception:9,speed:"7",senses:["Low-light vision"],powers:[{name:"Pack Attack",action:"Trait",description:"The howler's attacks deal 5 extra damage to any enemy adjacent to two or more of the howler's allies"},{name:"Whip",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +12 vs. AC Hit: 2d8 + 6 damage."},{name:"Whip Trip",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +12 vs. AC Hit: 1d8 + 6 damage, and the target falls prone."},{name:"Skulk",action:"Move",description:"Effect: The howler shifts up to 4 squares."},{name:"Howl of Dread",action:"Minor",keywords:["fear"],recharge:"Recharge when first bloodied",description:"Attack: Close burst 3 (enemies in the burst); +10 vs. Will Hit: The target is immobilized (save ends). Skills Intimidate +12, Stealth +13"}],alignment:"Chaotic Evil",languages:["Abyssal","Common Monster Vault: Threats to the Nentir Vale","page(s) 25."] },
  { id:"mvttnv-bloodfire-ooze",name:"Bloodfire Ooze",source:"mvttnv",level:7,role:"Brute",roleModifier:"Elite",xp:600,size:"Large",origin:"Elemental",type:"Beast",keywords:["fire","ooze"],hp:196,ac:19,fort:21,ref:18,will:17,initiative:4,perception:8,speed:"6",senses:["Blindsight 20"],immune:["fire"],vulnerable:["10 cold"],powers:[{name:"Bloodfire Aura",action:"Aura",keywords:["fire"],description:"Aura 2 Any creature that ends its turn in the aura takes 10 fire damage"},{name:"Demonic Fire Fire",action:"Trait",description:"damage dealt by the bloodfire ooze ignores 10 points of a target's fire resistance"},{name:"Ooze",action:"Trait",description:"While squeezing, the ooze moves at full speed rather than half speed, it doesn't take the -5 penalty to attack rolls, and it doesn't grant combat advantage for squeezing"},{name:"Slam",action:"Standard",keywords:["fire"],description:"Attack: Melee 2 (one creature); +12 vs. AC Hit: 2d10 + 7 fire damage."},{name:"Fiery Eruption",action:"Standard",keywords:["fire"],recharge:"Recharge 4-6",description:"Attack: Close burst 3 (creatures in the burst); +10 vs. Reflex Hit: 2d8 + 2 fire damage, and ongoing 5 fire damage (save ends)."},{name:"Sulfuric Breath",action:"Minor",keywords:["poison"],description:"1/round Attack: Close blast 3 (creatures in the blast); +10 vs. Fortitude Hit: 2d6 + 4 poison damage."},{name:"Boiling Blood",action:"Triggered",keywords:["fire"],recharge:"Encounter",description:"Trigger: The bloodfire ooze is bloodied. Effect (Immediate Reaction): The bloodfire ooze recharges fiery eruption and uses it."}],alignment:"Chaotic Evil",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 27","Dungeon Magazine 197","Dungeon Magazine 212."] },
  { id:"mvttnv-daggerburg-captain",name:"Daggerburg Captain",source:"mvttnv",level:7,role:"Soldier",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:78,ac:23,fort:18,ref:19,will:20,initiative:6,perception:8,speed:"5",senses:["Low-light vision"],powers:[{name:"Bastard Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 1d10 + 10 damage. Effect: The target is marked until the end of the captain's next turn. Until this mark ends, the target grants combat advantage."},{name:"Follow Me",action:"Standard",recharge:"Recharge when first bloodied",description:"Effect: The captain charges an enemy. One or two allies within 5 squares of the captain can each take a free action to charge different enemies."},{name:"Daggerburg Resilience",action:"Triggered",recharge:"Encounter",description:"Trigger: The captain or an ally within 5 squares of it is subjected to an effect that a save can end. Effect (Immediate Reaction): The creature subjected to the effect can make a saving throw against it. Skills Athletics +11, History +12, Intimidate +12"}],alignment:"Evil",languages:["Common","Goblin Equipment : bastard sword","heavy shield","scale armor . Monster Vault: Threats to the Nentir Vale","page(s) 40."] },
  { id:"mvttnv-daggerburg-reaper",name:"Daggerburg Reaper",source:"mvttnv",level:7,role:"Lurker",xp:300,size:"Medium",origin:"Natural",type:"Humanoid",hp:64,ac:21,fort:18,ref:20,will:17,initiative:12,perception:5,speed:"6",senses:["Low-light vision"],powers:[{name:"Combat Adept At",action:"Trait",description:"the start of an encounter, the reaper's attacks deal 1d10 extra damage against any enemy that has not yet acted during the encounter"},{name:"Scythe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 2d6 + 8 damage."},{name:"Blinding Sweep",action:"Standard",keywords:["weapon"],recharge:"Encounter",description:"Attack: Close burst 1 (enemies in the burst); +10 vs. Reflex Hit: 3d6 + 5 damage, and the target is blinded until the end of the reaper's next turn. Miss: Half damage."},{name:"Stalk",action:"Move",keywords:["illusion"],description:"1/round Effect: The reaper shifts 1 square and then can move up to its speed. If it ends this movement at least 3 squares from all enemies, the reaper becomes invisible until the start of its next turn or until it makes an attack. Skills Stealth +13"}],alignment:"Evil",languages:["Common","Goblin Equipment : leather armor","scythe . Monster Vault: Threats to the Nentir Vale","page(s) 41."] },
  { id:"mvttnv-daggerburg-zealot",name:"Daggerburg Zealot",source:"mvttnv",level:7,role:"Skirmisher",xp:300,size:"Medium",origin:"Natural",type:"Humanoid",hp:78,ac:21,fort:19,ref:20,will:19,initiative:6,perception:6,speed:"6",senses:["Low-light vision"],powers:[{name:"Combat Adept At",action:"Trait",description:"the start of an encounter, the zealot's attacks deal 1d10 extra damage against any enemy that has not yet acted during the encounter"},{name:"Glaive",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +12 vs. AC Hit: 2d6 + 8 damage."},{name:"Mobile Attack",action:"Standard",description:"Effect: The zealot shifts up to half its speed and uses glaive once at any point during this movement."},{name:"Daggerburg Zealotry",action:"Triggered",recharge:"Encounter",description:"Trigger: An enemy within 5 squares of the zealot attacks an ally of the zealot. Effect (Immediate Reaction): The zealot shifts up to its speed to a square adjacent to the triggering enemy and uses glaive against that enemy."}],alignment:"Evil",languages:["Common","Goblin Equipment : glaive","hide armor . Monster Vault: Threats to the Nentir Vale","page(s) 40."] },
  { id:"mvttnv-erzoun",name:"Erzoun",source:"mvttnv",level:7,role:"Controller",roleModifier:"Elite",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:152,ac:21,fort:17,ref:20,will:19,initiative:6,perception:5,speed:"6",senses:["Low-light vision"],powers:[{name:"Quickshadow Aura",action:"Aura",description:"Aura 5 Any ally that shifts while in the aura can shift 1 additional square."},{name:"Blackfire Touch",action:"Standard",keywords:["fire","necrotic"],description:"Attack: Melee 1 (one creature); +10 vs. Reflex Hit: 3d6 + 5 fire and necrotic damage. Effect: Erzoun can slide the target 1 square."},{name:"Beshadowed Mind",action:"Standard",keywords:["necrotic","psychic"],description:"Attack: Ranged 5 (one or two creatures); +10 vs. Will Hit: 3d6 + 5 necrotic and psychic damage, and the target can't see more than 2 squares away from itself (save ends)."},{name:"Witch's Prophecy",action:"Standard",keywords:["charm"],description:"Recharge if the power misses Attack: Ranged 10 (one creature); +10 vs. Will Hit: Erzoun chooses an ally within 10 squares of her (the ally cannot be an elite or a solo). The target is weakened when attacking any enemy other than the chosen ally. This effect lasts until the end of the encounter or until the chosen ally drops to 0 hit points."},{name:"Deep Shadow",action:"Standard",keywords:["necrotic","zone"],recharge:"Recharge when first bloodied",description:"Effect: Area burst 1 within 10. The burst creates a zone that lasts until the end of Erzoun's next turn. The zone is difficult terrain for her enemies. Any enemy that enters the zone or ends its turn there takes 10 necrotic damage. Sustain Minor: The zone persists until the end of Erzoun's next turn, and Erzoun can move the zone up to 4 squares."},{name:"Shadow Jaunt",action:"Move",keywords:["teleportation"],recharge:"Encounter",description:"Effect: Erzoun teleports up to 3 squares and becomes insubstantial until the start of her next turn."},{name:"Shadow Augury",action:"Triggered",recharge:"Encounter",description:"Trigger: An attack hits Erzoun while she is bloodied. Effect (Immediate Interrupt): Shadow jaunt recharges, and Erzoun uses it. Skills Arcana +12, Religion +12"}],alignment:"Evil",languages:["Common Monster Vault: Threats to the Nentir Vale","page(s) 91."] },
  { id:"mvttnv-gray-company-recruit",name:"Gray Company Recruit",source:"mvttnv",level:7,role:"Artillery",roleModifier:"Minion",xp:75,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:21,fort:19,ref:20,will:18,initiative:7,perception:4,speed:"6",powers:[{name:"Grim Solidarity",action:"Trait",description:"If the recruit starts its turn adjacent to a creature that has grim solidarity, it can make a saving throw against one effect that a save can end"},{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 6 damage."},{name:"Shortbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 20 (one creature); +14 vs. AC Hit: 6 damage."},{name:"Inspired Fervor",action:"Triggered",description:"1/round Trigger: The recruit scores a critical hit against an enemy. Effect (Free Action): The recruit makes a basic attack against the enemy, with a +2 power bonus to the attack roll."}],alignment:"Unaligned",languages:["Common Equipment : studded leather","arrow x20","short sword","shortbow . Monster Vault: Threats to the Nentir Vale","page(s) 62","Dungeon Magazine 206."] },
  { id:"mvttnv-harken-s-heart-acolyte",name:"Harken's Heart Acolyte",source:"mvttnv",level:7,role:"Skirmisher",roleModifier:"Minion",xp:75,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:21,fort:20,ref:19,will:18,initiative:7,perception:9,speed:"7 (forest walk)",senses:["Low-light vision"],powers:[{name:"Wild Step",action:"Trait",description:"The acolyte ignores difficult terrain whenever it shifts"},{name:"Claw",action:"Standard",description:"Requirement: The acolyte must be in beast form. Attack: Melee 1 (one creature); +12 vs. AC Hit: 7 damage. Effect: The acolyte can shift 1 square before or after the attack."},{name:"Quarterstaff",action:"Standard",keywords:["weapon"],description:"Requirement: The acolyte must be in humanoid form. Attack: Melee 1 (one creature); +12 vs. AC Hit: 5 damage."},{name:"Change Shape",action:"Minor",keywords:["polymorph"],description:"Effect: The acolyte alters its physical form to appear as a Medium beast until it uses change shape again or until it dies. It can also use this power to return to its humanoid form."}],alignment:"Unaligned",languages:["Common","Elven Equipment : quarterstaff . Monster Vault: Threats to the Nentir Vale","page(s) 64."] },
  { id:"mvttnv-harken-s-heart-druid",name:"Harken's Heart Druid",source:"mvttnv",level:7,role:"Controller",xp:300,size:"Medium",origin:"Natural",type:"Humanoid",hp:78,ac:21,fort:18,ref:19,will:20,initiative:6,perception:12,speed:"7 (forest walk)",senses:["Low-light vision"],powers:[{name:"Wild Step",action:"Trait",description:"The druid ignores difficult terrain whenever it shifts"},{name:"Lunge",action:"Standard",description:"Requirement: The druid must be in beast form. Attack: Melee 1 (one creature); +10 vs. Reflex Hit: 2d8 + 6 damage. Effect: The druid slides the target up to 2 squares."},{name:"Quarterstaff",action:"Standard",keywords:["weapon"],description:"Requirement: The druid must be in humanoid form. Attack: Melee 1 (one creature); +12 vs. AC Hit: 2d8 + 6 damage."},{name:"Entangle",action:"Standard",description:"Attack: Ranged 5 (one creature); +10 vs. Reflex Hit: The target is immobilized (save ends)."},{name:"Wall of Thorns",action:"Standard",keywords:["zone"],recharge:"Recharge when first bloodied",description:"Requirement: The druid must be in humanoid form. Attack: Area burst wall 8 within 10 (creatures in the wall); +10 vs. Reflex Hit: 1d10 + 5 damage, and ongoing 5 damage (save ends). Effect: The wall creates a zone up to 4 squares high that lasts until the end of the encounter. The zone is difficult terrain for creatures without forest walk. Any creature without forest walk that enters the zone or ends its turn there takes 5 damage."},{name:"Change Shape",action:"Minor",keywords:["polymorph"],description:"Effect: The druid alters its physical form to appear as a Medium beast until it uses change shape again or until it dies. It can also use this power to return to its humanoid form. Skills Nature +12, Stealth +11"}],alignment:"Unaligned",languages:["Common","Elven Equipment : quarterstaff . Monster Vault: Threats to the Nentir Vale","page(s) 64."] },
  { id:"mvttnv-hound-of-ill-omen",name:"Hound of Ill Omen",source:"mvttnv",level:7,role:"Soldier",xp:300,size:"Medium",origin:"Shadow",type:"Beast",keywords:["undead"],hp:80,ac:23,fort:19,ref:20,will:18,initiative:10,perception:10,speed:"8; phasing",senses:["Darkvision"],immune:["disease, poison"],powers:[{name:"Ill Omen",action:"Aura",description:"Aura 2 Any enemy that spends a healing surge while in the aura is slowed until the end of its next turn"},{name:"Insubstantial",action:"Trait",description:"The hound takes half damage from any damage source, except those that deal force damage or radiant damage. In addition, if the hound takes radiant damage, it loses the insubstantial trait until the end of its next turn"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 2d8 + 6 damage. Effect: The target is marked until the end of the hound's next turn."},{name:"Howl of Doom",action:"Standard",keywords:["psychic","thunder"],recharge:"Encounter",description:"Attack: Close blast 5 (enemies in the blast); +10 vs. Will Hit: 2d10 + 11 thunder damage, and the target is cursed. Until the target is no longer cursed, it takes 3 psychic damage whenever it misses every target with an attack power. At the end of each of the target's extended rests, it makes a DC 16 Religion check to try to end the curse. First Failed Check: The psychic damage increases to 6. Second Failed Check: The psychic damage increases to 9. Third Failed Check: The target dies. Miss: Half damage."},{name:"Howl of the Pack",action:"Triggered",keywords:["fear","thunder"],description:"Trigger: An enemy within 3 squares of the hound and marked by it willingly moves away from it. Attack (Immediate Interrupt): Close blast 3 (the triggering enemy in the blast); +10 vs. Fortitude Hit: 2d10 + 4 thunder damage, and the target grants combat advantage until the end of its next turn."}],alignment:"Unaligned",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 66","Dungeon Magazine 211."] },
  { id:"mvttnv-lingering-warrior-spirit",name:"Lingering Warrior Spirit",source:"mvttnv",level:7,role:"Soldier",roleModifier:"Minion",xp:75,size:"Medium",origin:"Shadow",type:"Humanoid",keywords:["undead"],hp:1,ac:23,fort:18,ref:20,will:18,initiative:8,perception:4,speed:"6",senses:["Darkvision"],resist:["15 all except radiant"],immune:["disease, fear"],powers:[{name:"Phantom Strike",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 6 damage, and the target is immobilized until the start of the spirit's next turn."}],alignment:"Unaligned",languages:["Common Monster Vault: Threats to the Nentir Vale","page(s) 17","Dungeon Magazine 218."] },
  { id:"mvttnv-lizardfolk-chief",name:"Lizardfolk Chief",source:"mvttnv",level:7,role:"Soldier",roleModifier:"Elite",xp:0,size:"Large",origin:"Natural",type:"Humanoid",keywords:["reptile"],hp:156,ac:23,fort:20,ref:19,will:18,initiative:8,perception:10,speed:"6 (swamp walk)",powers:[{name:"Battleaxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +12 vs. AC Hit: 2d10 + 4 damage, and the target is slowed until the end of its next turn."},{name:"Double Attack",action:"Standard",description:"Effect: The chief uses battleaxe twice."},{name:"Fighting Spirit",action:"Minor",recharge:"Encounter",description:"Effect: 2 (allies in the burst)Each target can make a basic attack as a free action."},{name:"Tail Lash",action:"Triggered",description:"Trigger: An enemy adjacent to the chief shifts. Attack (Opportunity Action): Melee 1 (the triggering enemy); +10 vs. Reflex Hit: 2d6 damage, and the target falls prone. Skills Athletics +12, Intimidate +10"}],alignment:"Unaligned",languages:["Draconic Equipment : bone breastplate","battleaxe . Monster Vault: Threats to the Nentir Vale","page(s) 119."] },
  { id:"mvttnv-lizardfolk-dreadnought",name:"Lizardfolk Dreadnought",source:"mvttnv",level:7,role:"Brute",roleModifier:"Elite",xp:0,size:"Large",origin:"Natural",type:"Humanoid",keywords:["reptile"],hp:190,ac:19,fort:21,ref:17,will:19,initiative:4,perception:6,speed:"6 (swamp walk)",powers:[{name:"Dreadnought's Wrath",action:"Aura",description:"Aura 2 While in the aura, bloodied allies have a +2 power bonus to attack rolls and damage rolls"},{name:"Staggering Critical Whenever",action:"Trait",description:"the dreadnought scores a critical hit, the target is stunned until the end of the target's next turn"},{name:"Greatclub",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +12 vs. AC Hit: 2d10 + 8 damage. The dreadnought pushes the target up to 2 squares and then shifts up to 2 squares to a square adjacent to the target."},{name:"Low Blow",action:"Minor",description:"1/round Attack: Melee 2 (one creature); +10 vs. Fortitude Hit: 3d6 + 8 damage, and the target falls prone."},{name:"You Fight Now!",action:"Minor",recharge:"Recharge when first bloodied",description:"Effect: Ranged 5 (one ally). The target can charge as a free action. Skills Athletics +14, Intimidate +7"}],alignment:"Unaligned",languages:["Draconic Equipment : bone breastplate","greatclub . Monster Vault: Threats to the Nentir Vale","page(s) 119","Dungeon Magazine 191."] },
  { id:"mvttnv-phantom-brigade-armiger",name:"Phantom Brigade Armiger",source:"mvttnv",level:7,role:"Brute",xp:300,size:"Medium",origin:"Natural",type:"Humanoid",hp:71,ac:19,fort:21,ref:16,will:18,initiative:4,perception:6,speed:"6; phasing",senses:["Darkvision"],immune:["disease, poison"],powers:[{name:"Insubstantial",action:"Trait",description:"The armiger takes only half damage from any damage source, except force damage"},{name:"Unrelenting Brigade Whenever",action:"Trait",description:"an ally who also has this trait drops to 0 hit points within 5 squares of the armiger, the armiger gains a +2 power bonus to attack rolls until the end of its next turn"},{name:"Soulbound Bardiche",action:"Standard",keywords:["psychic","weapon"],description:"Attack: Melee 2 (one creature); +12 vs. AC Hit: 3d8 + 5 psychic damage."},{name:"Charging Rebuke",action:"Standard",keywords:["psychic","weapon"],description:"Effect: The armiger charges and makes the following attack in place of a melee basic attack. Attack: Melee 2 (one creature); +12 vs. AC Hit: 3d8 + 5 psychic damage, and the armiger can push the target up to 1 square and knock it prone."},{name:"Furious Sweep",action:"Standard",keywords:["psychic","weapon"],description:"Attack: Close blast 2 (creatures in the blast); +10 vs. Reflex Hit: 2d8 + 5 psychic damage."}],alignment:"Lawful Good",languages:["Common Monster Vault: Threats to the Nentir Vale","page(s) 88."] },
  { id:"mvttnv-phantom-brigade-justiciar",name:"Phantom Brigade Justiciar",source:"mvttnv",level:7,role:"Skirmisher",xp:300,size:"Medium",origin:"Natural",type:"Humanoid",hp:54,ac:21,fort:18,ref:20,will:19,initiative:9,perception:6,speed:"6; phasing",senses:["Darkvision"],immune:["disease, poison"],powers:[{name:"Blind Justice",action:"Aura",description:"Aura 1 Enemies take a -2 penalty to attack rolls while in the aura"},{name:"Insubstantial",action:"Trait",description:"The justiciar takes only half damage from any damage source, except force damage"},{name:"Unrelenting Brigade Whenever",action:"Trait",description:"an ally who also has this trait drops to 0 hit points within 5 squares of the justiciar, the justiciar gains a +2 power bonus to attack rolls until the end of its next turn"},{name:"Soulbound Hammer",action:"Standard",keywords:["psychic","weapon"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 2d8 + 6 psychic damage."},{name:"Hurled Hammer",action:"Standard",keywords:["psychic","weapon"],description:"Attack: Ranged 5 (one creature); +12 vs. AC Hit: 2d8 + 6 psychic damage."},{name:"Evade and Strike",action:"Standard",keywords:["psychic","weapon"],description:"Effect: Any marks on the justiciar end, and the justiciar shifts up to 4 squares before making the following attack. Attack: Melee 1 (one creature); +12 vs. AC Hit: 2d8 + 6 psychic damage. Skills Insight +11"}],alignment:"Lawful Good",languages:["Common Monster Vault: Threats to the Nentir Vale","page(s) 88."] },
  { id:"mvttnv-raven-roost-highwayman",name:"Raven Roost Highwayman",source:"mvttnv",level:7,role:"Soldier",xp:300,size:"Medium",origin:"Natural",type:"Humanoid",hp:77,ac:23,fort:18,ref:21,will:18,initiative:9,perception:10,speed:"6",powers:[{name:"Rapier",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 2d8 + 6 damage. Effect: The target is marked until the end of the highwayman's next turn."},{name:"Bolt to the Gut",action:"Standard",keywords:["weapon"],recharge:"Encounter",description:"Attack: Ranged 5 (one creature); +12 vs. AC. This attack doesn't provoke opportunity attacks. Hit: 3d6 + 5 damage, and the target is immobilized and takes ongoing 5 damage (save ends both). Miss: The target is immobilized until the end of its next turn."},{name:"Stand, You Coward",action:"Triggered",description:"Trigger: An enemy within 5 squares of the highwayman and marked by it uses an attack power that doesn't include it as a target. Effect (Immediate Reaction): Bolt to the gut recharges, and the highwayman uses it against the triggering enemy. Skills Bluff +11, Intimidate +11, Stealth +12"}],alignment:"Evil",languages:["Common Equipment : studded leather","crossbow bolt x10","hand crossbow","rapier . Monster Vault: Threats to the Nentir Vale","page(s) 93","Dungeon Magazine 200."] },
  { id:"mvttnv-adrian-iceheart-reginold",name:"Adrian 'Iceheart' Reginold",source:"mvttnv",level:8,role:"Controller",xp:350,size:"Medium",origin:"Natural",type:"Humanoid",hp:86,ac:22,fort:19,ref:22,will:20,initiative:6,perception:7,speed:"6",senses:["Darkvision"],resist:["10 cold,","10 necrotic"],immune:["disease, fear"],vulnerable:["5 fire,","5 radiant"],powers:[{name:"Frost Staff",action:"Standard",keywords:["cold","weapon"],description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d8 + 7 cold damage."},{name:"Ice Bolts",action:"Standard",keywords:["cold","implement","necrotic"],description:"Attack: Ranged 5 (one or two creatures); +13 vs. AC Hit: 2d6 + 5 cold and necrotic damage, and the target is slowed until the end of Iceheart's next turn."},{name:"Deep Freeze",action:"Standard",keywords:["cold","implement"],recharge:"Recharge 4-6",description:"Attack: Close blast 3 (creatures in the blast); +11 vs. Fortitude Hit: 4d6 + 4 cold damage, and the target is restrained until the end of Iceheart's next turn."},{name:"Vortex of Ice",action:"Standard",keywords:["cold","implement"],recharge:"Encounter",description:"Attack: Area burst 1 within 10 (creatures in the burst); +11 vs. Reflex Hit: 4d6 + 4 cold damage, and Iceheart slides the target up to 3 squares and knocks it prone. Miss: Half damage, and Iceheart can slide the target 1 square. Skills Arcana +14, Dungeoneering +14"}],alignment:"Evil",languages:["Common Equipment : tattered robes","staff implement . Monster Vault: Threats to the Nentir Vale","page(s) 18."] },
  { id:"mvttnv-blackfang-render",name:"Blackfang Render",source:"mvttnv",level:8,role:"Soldier",xp:350,size:"Medium",origin:"Natural",type:"Humanoid",hp:87,ac:24,fort:21,ref:20,will:19,initiative:8,perception:5,speed:"7",senses:["Darkvision"],powers:[{name:"Pack Attack",action:"Trait",description:"The render's attacks deal 5 extra damage to any enemy adjacent to two or more of the render's allies"},{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +13 vs. AC Hit: 2d8 + 7 damage, and the target is marked until the end of the render's next turn."},{name:"Feral Grasp",action:"Standard",description:"Requirement: The render must have no creature grabbed. Attack: Melee 2 (one creature); +11 vs. Reflex Hit: 1d12 + 8 damage, and the target is grabbed (escape DC 16)."},{name:"Blinding Fury",action:"Minor",recharge:"Recharge when first bloodied",description:"Attack: Melee 1 (one creature grabbed by the render); +11 vs. Fortitude Hit: 1d6 + 3 damage, and the target is blinded (save ends)."}],alignment:"Chaotic Evil",languages:["Abyssal","Common Monster Vault: Threats to the Nentir Vale","page(s) 26."] },
  { id:"mvttnv-bloodspear-half-troll",name:"Bloodspear Half-Troll",source:"mvttnv",level:8,role:"Soldier",xp:350,size:"Medium",origin:"Natural",type:"Humanoid",hp:92,ac:24,fort:21,ref:20,will:19,initiative:8,perception:6,speed:"7",senses:["Low-light vision"],powers:[{name:"Regeneration",action:"Trait",description:"The half-troll regains 5 hit points whenever it starts its turn and has at least 1 hit point"},{name:"When",action:"Trait",description:"the half-troll takes fire or acid damage, its regeneration does not function on its next turn"},{name:"Troll Healing Whenever",action:"Trait",description:"an attack that doesn't deal acid or fire damage reduces the half-troll to 0 hit points, the half-troll does not die and instead falls unconscious until the start of its next turn, when it becomes conscious with 11 hit points"},{name:"If",action:"Trait",description:"an attack hits the half-troll and deals any acid or fire damage while it is unconscious, it does not return to life in this way"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d6 + 9 damage. Effect: The target is grabbed (escape DC 16) if the half-troll has fewer than two creatures grabbed."},{name:"Bite",action:"Triggered",description:"Trigger: A creature grabbed by the half-troll attacks it or escapes from the grab. Attack (Free Action): Melee 1 (the triggering creature); +11 vs. Reflex Hit: 1d8 + 4 damage. Savage Demise ✦ Encounter Trigger: The half-troll drops to 0 hit points. Effect (Free Action): The half-troll takes a standard action. Skills Endurance +14"}],alignment:"Chaotic Evil",languages:["Common","Giant Monster Vault: Threats to the Nentir Vale","page(s) 37."] },
  { id:"mvttnv-dark-drake-of-the-moon-hills",name:"Dark Drake of the Moon Hills",source:"mvttnv",level:8,role:"Lurker",roleModifier:"Elite",xp:700,size:"Large",origin:"Natural",type:"Beast",keywords:["reptile"],hp:148,ac:22,fort:22,ref:20,will:20,initiative:11,perception:12,speed:"6",senses:["Darkvision"],powers:[{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d10 + 5 damage."},{name:"Double Attack",action:"Standard",description:"Effect: The drake uses bite twice."},{name:"Unseen Killer",action:"Standard",keywords:["psychic"],description:"Requirement: The drake must be invisible as a result of ghost drake. Attack: Melee 1 (one or two creatures); +11 vs. Will Hit: 3d10 + 16 psychic damage. Ghost Drake (illusion) ✦ At-Will Effect: The drake is insubstantial and phasing until the end of its turn, then moves up to its speed. After moving, it becomes invisible until the end of the encounter or until it hits or misses with an attack."},{name:"Terrible Aspect",action:"Minor",keywords:["fear"],recharge:"Recharge when the drake hits with a melee",description:"attack other than this one Attack: Melee 1 (one creature that can see the drake); +11 vs. Will Hit: The drake pushes the target 1 square, and the target is immobilized until the end of its next turn. Skills Stealth +12"}],alignment:"Evil",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 43."] },
  { id:"mvttnv-frost-witch",name:"Frost Witch",source:"mvttnv",level:8,role:"Controller",xp:350,size:"Medium",origin:"Natural",type:"Humanoid",hp:87,ac:22,fort:20,ref:21,will:21,initiative:6,perception:12,speed:"6 (ice walk)",resist:["10 cold"],vulnerable:["5 fire"],powers:[{name:"Frost Aura",action:"Aura",description:"Aura 1 Enemies have vulnerable 5 cold while in the aura."},{name:"Frost Staff",action:"Standard",keywords:["cold","weapon"],description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 3d6 + 3 cold damage, and the witch slides the target up to 2 squares."},{name:"Snow Blindness",action:"Standard",keywords:["cold","implement","radiant"],description:"Attack: Ranged 5 (one creature); +11 vs. Fortitude Hit: 3d6 + 6 cold and radiant damage, and the target can't see any creature that is more than 3 squares away from it (save ends)."},{name:"Icy Blast",action:"Standard",keywords:["cold","implement","zone"],recharge:"Encounter",description:"Attack: Close blast 5 (creatures in the blast); +11 vs. Fortitude Hit: 3d8 + 5 cold damage. Miss: Half damage. Effect: The blast creates a zone that lasts until the end of the witch's next turn. The ground of the zone is difficult terrain for creatures without ice walk. Sustain Minor: The zone persists until the end of the witch's next turn. Skills Arcana +12, Bluff +10, Diplomacy +10, Nature +12"}],alignment:"Evil",languages:["Common","Elven","Primordial Equipment : staff implement . Monster Vault: Threats to the Nentir Vale","page(s) 56."] },
  { id:"mvttnv-halvath-cormarrin",name:"Halvath Cormarrin",source:"mvttnv",level:8,role:"Brute",roleModifier:"Elite",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:214,ac:20,fort:21,ref:18,will:19,initiative:6,perception:6,speed:"5",powers:[{name:"Until the Last Breath",action:"Aura",description:"Aura 5 Whenever an ally in the aura drops to 0 hit points, that ally can immediately make a melee basic attack as a free action"},{name:"Grim Solidarity",action:"Trait",description:"If Cormarrin starts his turn adjacent to a creature that has grim solidarity, he can make a saving throw against one effect that a save can end"},{name:"Ancient Rune Flail",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 3d10 + 4 damage."},{name:"Double Attack",action:"Standard",description:"Effect: Cormarrin uses ancient rune flail twice."},{name:"Rune Flail's Arc",action:"Standard",keywords:["thunder","weapon"],recharge:"Recharge 4-6",description:"Attack: Close burst 1 (enemies in the burst); +11 vs. Reflex Hit: 3d10 + 4 thunder damage, and Cormarrin pushes the target 1 square and knocks it prone. Miss: Half damage, and Cormarrin pushes the target 1 square."},{name:"Cry of Glory",action:"Triggered",recharge:"Encounter",description:"Trigger: An ally within 10 squares of Cormarrin hits with an attack that isn't a critical hit. Effect (Free Action): Close burst 10 (triggering ally in the burst). The ally instead scores a critical hit. Skills Arcana +11, Athletics +14, History +11"}],alignment:"Evil",languages:["Common","Draconic Equipment : ancient flail","heavy shield","plate armor . Monster Vault: Threats to the Nentir Vale","page(s) 61."] },
  { id:"mvttnv-hill-clan-apparition",name:"Hill Clan Apparition",source:"mvttnv",level:8,role:"Soldier",roleModifier:"Minion",xp:88,size:"Medium",origin:"Shadow",type:"Humanoid",keywords:["undead"],hp:1,ac:24,fort:20,ref:21,will:18,initiative:11,perception:4,speed:"6, fly 6 (hover)",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, poison"],powers:[{name:"Chill",action:"Trait",description:"of the Grave Any enemy that starts its turn adjacent to the apparition is slowed until the start of its next turn"},{name:"Shadow Blade",action:"Standard",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 6 damage."},{name:"Call of the Dead",action:"Standard",keywords:["psychic"],description:"Attack: Ranged 5 (one creature); +11 vs. Will Hit: 6 psychic damage, and the apparition pulls the target up to 4 squares."}],alignment:"Evil",languages:["Common Monster Vault: Threats to the Nentir Vale","page(s) 67."] },
  { id:"mvttnv-joplin-the-sly",name:"Joplin the Sly",source:"mvttnv",level:8,role:"Lurker",xp:350,size:"Medium",origin:"Natural",type:"Humanoid",hp:68,ac:22,fort:19,ref:22,will:19,initiative:13,perception:10,speed:"6",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, fear"],vulnerable:["5 radiant"],powers:[{name:"Nimble Reaction Joplin",action:"Trait",description:"gains a +2 bonus to AC against opportunity attacks"},{name:"Vanishing Strike",action:"Standard",keywords:["illusion","weapon"],description:"Attack: Melee 1 (one creature); +11 vs. Reflex Hit: 2d6 + 9 damage, or 3d6 + 9 if Joplin has combat advantage against the target, and Joplin turns invisible until the start of her next turn."},{name:"Swift Rebuke",action:"Triggered",recharge:"Encounter",description:"Trigger: An adjacent enemy hits or misses Joplin with a melee attack. Effect (Immediate Interrupt): Joplin uses vanishing strike against the triggering enemy and has combat advantage against it for that attack. Skills Acrobatics +14, Stealth +14, Thievery +14"}],alignment:"Evil",languages:["Common Equipment : leather armor","short sword . Monster Vault: Threats to the Nentir Vale","page(s) 18."] },
  { id:"mvttnv-maldrick-scarmaker",name:"Maldrick Scarmaker",source:"mvttnv",level:8,role:"Artillery",roleModifier:"Elite",xp:700,size:"Medium",origin:"Natural",type:"Humanoid",hp:148,ac:22,fort:21,ref:20,will:17,initiative:8,perception:5,speed:"7, fly 9",senses:["Darkvision"],powers:[{name:"Pack Attack Maldrick's",action:"Trait",description:"attacks deal 5 extra damage to any enemy adjacent to two or more of Maldrick's allies"},{name:"Mace",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d8 + 7 damage."},{name:"Eldritch Blast",action:"Standard",keywords:["implement"],description:"Attack: Ranged 10 (one creature); +13 vs. Reflex Hit: 2d10 + 5 damage."},{name:"Dire Radiance",action:"Standard",keywords:["implement","radiant"],description:"Attack: Ranged 10 (one or two creatures); +13 vs. Fortitude Hit: 2d6 + 5 radiant damage. If the target moves closer to Maldrick on its next turn, it takes 10 radiant damage."},{name:"Infernal Moon Curse",action:"Standard",keywords:["implement","poison"],recharge:"Encounter",description:"Attack: Ranged 10 (one or two creatures); +13 vs. Fortitude Hit: 3d8 + 10 poison damage, and the target is held immobilized 5 feet off the ground until the end of Maldrick's next turn. Miss: Half damage."},{name:"Blackfang Curse",action:"Minor",description:"1/round Effect: Maldrick chooses one enemy he can see. Until the end of Maldrick's turn, his implement attacks deal 1d6 extra damage against the chosen enemy."},{name:"Spined Tail",action:"Triggered",description:"Trigger: An enemy enters a square adjacent to Maldrick. Attack (Opportunity Action): Melee 1 (the triggering enemy); +13 vs. AC Hit: 1d10 + 11 damage. Skills Arcana +9, Intimidate +10, Religion +9, Thievery +13"}],alignment:"Chaotic Evil",languages:["Abyssal","Common Equipment : leather armor","mace","rod implement . Monster Vault: Threats to the Nentir Vale","page(s) 25."] },
  { id:"mvttnv-mistmane-bugbear",name:"Mistmane Bugbear",source:"mvttnv",level:8,role:"Soldier",roleModifier:"Elite",xp:700,size:"Large",origin:"Natural",type:"Humanoid",hp:172,ac:24,fort:21,ref:20,will:22,initiative:9,perception:9,speed:"6",senses:["Low-light vision"],powers:[{name:"Arcane Mist",action:"Aura",description:"Aura 2 Creatures cannot teleport while in the aura"},{name:"Combat Adept At",action:"Trait",description:"the start of an encounter, the bugbear's attacks deal 1d10 extra damage against any enemy that has not yet acted during the encounter"},{name:"Rake",action:"Standard",keywords:["necrotic"],description:"Attack: Melee 2 (one creature); +13 vs. AC Hit: 2d6 + 9 damage. Effect: The target is marked until the end of the bugbear's next turn. While marked by the bugbear, the target takes 5 necrotic damage whenever it uses an attack power that doesn't include the bugbear as a target."},{name:"Double Attack",action:"Standard",description:"Effect: The bugbear uses rake twice."},{name:"Bewildering Mist",action:"Minor",recharge:"Encounter",description:"Attack: Close burst 1 (enemies in the burst); +11 vs. Will Effect: The target is dazed until the end of the bugbear's next turn."}],alignment:"Evil",languages:["Common","Goblin Monster Vault: Threats to the Nentir Vale","page(s) 38."] },
  { id:"mvttnv-penanggalan-head-swarm",name:"Penanggalan Head Swarm",source:"mvttnv",level:8,role:"Soldier",xp:350,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["swarm","undead"],hp:87,ac:24,fort:22,ref:20,will:19,initiative:10,perception:5,speed:"6, fly 6 (hover)",senses:["Darkvision"],resist:["10 necrotic, half damage from melee and ranged attacks"],immune:["disease, poison"],vulnerable:["5 radiant,","5 to close and area attacks"],powers:[{name:"Swarm Attack",action:"Aura",description:"Aura 1 Any enemy that starts its turn in the aura is slowed until the start of its next turn"},{name:"Swarm",action:"Trait",description:"The swarm can occupy the same space as another creature, and an enemy can enter its space, which is difficult terrain"},{name:"The",action:"Trait",description:"swarm cannot be pulled, pushed, or slid by melee or ranged attacks"},{name:"It",action:"Trait",description:"can squeeze through any opening that is large enough for a Small creature"},{name:"Swarm of Entrails",action:"Standard",keywords:["poison"],description:"Attack: Close burst 2 (enemies in the burst); +13 vs. AC Hit: 1d8 + 5 poison damage, plus 1d8 poison damage if the target is slowed. The swarm can slide the target 1 square to a square adjacent to it."}],alignment:"Evil",languages:["Common Monster Vault: Threats to the Nentir Vale","page(s) 83."] },
  { id:"mvttnv-phantom-brigade-banneret",name:"Phantom Brigade Banneret",source:"mvttnv",level:8,role:"Soldier",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:60,ac:24,fort:22,ref:21,will:19,initiative:8,perception:7,speed:"6; phasing",senses:["Darkvision"],immune:["disease, poison"],powers:[{name:"Gift of Grace",action:"Aura",description:"Aura 3 Allies gain a +5 power bonus to saving throws while in the aura"},{name:"Insubstantial",action:"Trait",description:"The banneret takes only half damage from any damage source, except force damage"},{name:"Unrelenting Brigade Whenever",action:"Trait",description:"an ally who also has this trait drops to 0 hit points within 5 squares of the banneret, the banneret gains a +2 power bonus to attack rolls until the end of its next turn"},{name:"Soulbound Tulwar",action:"Standard",keywords:["psychic","radiant","weapon"],description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d6 + 9 psychic and radiant damage. Effect: The target is marked and slowed until the end of the banneret's next turn."},{name:"Stalwart Restraint",action:"Triggered",keywords:["psychic"],description:"Trigger: An enemy marked by the banneret and within 5 squares of it makes an attack that doesn't include it as a target. Effect (Immediate Reaction): Close burst 5 (triggering enemy in the burst). The target is immobilized and takes ongoing 10 psychic damage (save ends both)."}],alignment:"Lawful Good",languages:["Common Monster Vault: Threats to the Nentir Vale","page(s) 88."] },
  { id:"mvttnv-primal-sabertooth-tiger",name:"Primal Sabertooth Tiger",source:"mvttnv",level:8,role:"Soldier",roleModifier:"Elite",xp:700,size:"Huge",origin:"Natural",type:"Beast",keywords:["mount"],hp:178,ac:24,fort:21,ref:21,will:19,initiative:11,perception:12,speed:"8, climb 4",senses:["Low-light vision"],powers:[{name:"Charging Pounce",action:"Trait",description:"The sabertooth is not limited to taking only free actions immediately after a charge"},{name:"Threatening Reach",action:"Trait",description:"The sabertooth can make opportunity attacks against enemies within 2 squares of it"},{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +13 vs. AC Hit: 1d10 + 5 damage, and ongoing 5 damage (save ends). If the target is already taking ongoing damage, it takes ongoing 10 damage (save ends)."},{name:"Go for the Kill",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Melee 2 (one creature); +11 vs. Reflex Hit: 3d12 + 6 damage, and the target falls prone. If this attack bloodies the target, the sabertooth gains 5 temporary hit points. Miss: Half damage."},{name:"Bite",action:"Minor",recharge:"Recharge when no creature is grabbed by this power",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 1d10 + 5 damage, and the target is grabbed (escape DC 20). Until the grab ends, the target takes ongoing 10 damage. When the sabertooth moves willingly, it can pull the target with it, keeping the target adjacent to it. When the sabertooth pulls the target in this way, the sabertooth's movement doesn't provoke opportunity attacks from the target."},{name:"Fierce Spirit",action:"Triggered",recharge:"Encounter",description:"Trigger: An attack reduces the sabertooth to 0 hit points. Effect (Immediate Interrupt): Go for the kill recharges, and the sabertooth shifts up to its speed and uses it against an enemy. If the sabertooth reduces the enemy to 0 hit points or fewer, the sabertooth does not drop to 0 hit points and instead has 20 hit points. Skills Acrobatics +14, Athletics +14, Nature +12, Stealth +14"}],alignment:"Unaligned",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 103."] },
  { id:"mvttnv-samminel",name:"Samminel",source:"mvttnv",level:8,role:"Soldier",roleModifier:"Elite",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:172,ac:24,fort:22,ref:21,will:23,initiative:7,perception:7,speed:"5",senses:["Low-light vision"],powers:[{name:"Deathshadow Fervor",action:"Aura",description:"Aura 5 Whenever an ally in the aura scores a critical hit against an enemy, that enemy is also dazed (save ends)."},{name:"Halberd",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +13 vs. AC Hit: 2d10 + 5 damage. Effect: Samminel marks the target until the end of his next turn."},{name:"Double Attack",action:"Standard",description:"Effect: Samminel uses halberd twice."},{name:"Sundering Sweep",action:"Standard",keywords:["weapon"],recharge:"Recharge 4-6",description:"Attack: Close burst 2 (enemies in the burst); +13 vs. AC Hit: 2d10 + 7 damage, and the target takes a -2 penalty to AC (save ends)."},{name:"Shadow Jaunt",action:"Move",keywords:["teleportation"],recharge:"Encounter",description:"Effect: Samminel teleports up to 3 squares and becomes insubstantial until the start of his next turn."},{name:"Deathtrap",action:"Triggered",description:"Trigger: An enemy within 2 squares of Samminel that is marked by him either moves or uses an attack power that doesn't include him as a target. Effect (Immediate Interrupt): Samminel uses halberd against the triggering enemy. The attack can score a critical hit on a roll of 17-20. Skills Diplomacy +13, Intimidate +13"}],alignment:"Evil",languages:["Common Equipment : chainmail","halberd . Monster Vault: Threats to the Nentir Vale","page(s) 91."] },
  { id:"mvttnv-saruun-apprentice",name:"Saruun Apprentice",source:"mvttnv",level:8,role:"Controller",roleModifier:"Minion",xp:88,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:22,fort:18,ref:22,will:20,initiative:7,perception:6,speed:"6",powers:[{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 6 damage."},{name:"Ice Patch",action:"Standard",keywords:["cold","implement"],description:"Attack: Ranged 5 (one creature); +11 vs. Reflex Hit: The target falls prone. If the apprentice scores a critical hit, the target also takes 6 cold damage and is immobilized until the end of its next turn."}],alignment:"Unaligned",languages:["Common","Elven Equipment : dagger","wand implement . Monster Vault: Threats to the Nentir Vale","page(s) 78."] },
  { id:"mvttnv-satyr-vassal",name:"Satyr Vassal",source:"mvttnv",level:8,role:"Artillery",roleModifier:"Elite",xp:700,size:"Medium",origin:"Fey",type:"Humanoid",hp:136,ac:22,fort:19,ref:21,will:20,initiative:7,perception:7,speed:"6 (ice walk)",senses:["Low-light vision"],resist:["5 cold"],powers:[{name:"Cold Wind Song",action:"Aura",description:"Aura 5 The satyr gains a +5 power bonus to all defenses against attacks made by creatures outside the aura."},{name:"Gore",action:"Standard",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 1d8 + 7 damage, and the target falls prone."},{name:"North Wind Bow",action:"Standard",keywords:["cold","weapon"],description:"Attack: Ranged 20 (one or two creatures); +15 vs. AC Hit: 2d10 + 5 cold damage, and the satyr pushes the target up to 3 squares."},{name:"Diving Dragon Shot",action:"Standard",keywords:["cold","weapon","zone"],recharge:"Encounter",description:"Attack: Area burst 2 within 20 (creatures in the burst); +13 vs. Reflex Hit: 2d8 + 3 cold damage, and the target is slowed (save ends). Miss: Half damage. Effect: The burst creates a zone that lasts until the end of the encounter. Any creature that ends its turn in the zone takes 5 cold damage."},{name:"Bitter Vengeance",action:"Triggered",keywords:["cold"],recharge:"Encounter",description:"Trigger: An enemy within 5 squares of the satyr hits it with an attack. Effect (Free Action): Close burst 5 (triggering enemy in the burst). The target takes 10 cold damage, and the satyr pushes it up to 2 squares. Skills Nature +12"}],alignment:"Unaligned",languages:["Common","Elven","Draconic Equipment : arrow x30","longbow . Monster Vault: Threats to the Nentir Vale","page(s) 22."] },
  { id:"mvttnv-tigerclaw-vassal",name:"Tigerclaw Vassal",source:"mvttnv",level:8,role:"Skirmisher",roleModifier:"Elite",xp:700,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["shapechanger"],hp:178,ac:22,fort:19,ref:22,will:20,initiative:12,perception:13,speed:"6 (ice walk)",senses:["Low-light vision"],resist:["5 cold"],powers:[{name:"Charging Pounce",action:"Trait",description:"The vassal's charge attacks deal 1d6 extra damage, and the vassal is not limited to taking only free actions after charging"},{name:"Light Pick",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 3d6 + 6 damage. On a critical hit, the target also takes ongoing 5 damage (save ends)."},{name:"Double Attack",action:"Standard",description:"Effect: The vassal uses light pick twice."},{name:"Bitterstrike's Slash",action:"Standard",keywords:["cold","weapon"],recharge:"Encounter",description:"Attack: Melee 1 (one or two creatures); +11 vs. Fortitude Hit: 3d6 + 8 damage, and ongoing 5 cold damage (save ends). First Failed Saving Throw: The target is slowed and takes ongoing 5 cold damage (save ends both). Miss: Half damage."},{name:"Wild Instinct",action:"Triggered",description:"Trigger: An enemy ends its movement flanking the vassal. Effect (Immediate Reaction): The vassal either shifts 1 square or moves up to its speed. Bitter Vengeance (cold) ✦ Encounter Trigger: An enemy within 5 squares of the vassal hits it with an attack. Effect (Free Action): Close burst 5 (triggering enemy in the burst). The target takes 10 cold damage, and the vassal pushes it up to 2 squares. Skills Athletics +12, Nature +13, Stealth +15"}],alignment:"Unaligned",languages:["Common","Draconic Equipment : 2 light picks","hide armor . Monster Vault: Threats to the Nentir Vale","page(s) 22."] },
  { id:"mvttnv-treant-vassal",name:"Treant Vassal",source:"mvttnv",level:8,role:"Soldier",roleModifier:"Elite",xp:700,size:"Large",origin:"Fey",type:"Magical beast",keywords:["plant"],hp:182,ac:24,fort:21,ref:18,will:22,initiative:7,perception:9,speed:"8 (forest walk, ice walk)",senses:["Low-light vision"],resist:["5 cold"],powers:[{name:"Threatening Reach",action:"Trait",description:"The treant can make opportunity attacks against creatures within 2 squares of it"},{name:"Wooden Body Whenever",action:"Trait",description:"the treant takes fire damage, it also takes ongoing 5 fire damage (save ends)"},{name:"Slam",action:"Standard",description:"Attack: Melee 2 (one creature); +13 vs. AC Hit: 1d12 + 10 damage."},{name:"Double Attack",action:"Standard",description:"Effect: The treant uses slam twice."},{name:"Bitterwind Blast",action:"Standard",keywords:["cold"],recharge:"Recharge when first bloodied",description:"Attack: Close blast 3 (creatures in the blast); +11 vs. Reflex Hit: 2d12 + 5 cold damage, and the target is slowed (save ends). Miss: Half damage."},{name:"Pounding Branches",action:"Triggered",description:"Trigger: An enemy within 2 squares of the treant uses an attack power that doesn't include the treant as a target. Attack (Opportunity Action): Melee 2 (the triggering enemy); +11 vs. Reflex Hit: 2d12 + 3 damage. Bitter Vengeance (cold) ✦ Encounter Trigger: An enemy within 5 squares of the treant hits it with an attack. Effect (Free Action): Close burst 5 (triggering enemy in the burst). The target takes 10 cold damage, and the treant pushes it up to 2 squares."}],alignment:"Unaligned",languages:["Common","Draconic","Elven Monster Vault: Threats to the Nentir Vale","page(s) 21."] },
  { id:"mvttnv-uthelyn-the-mad",name:"Uthelyn the Mad",source:"mvttnv",level:8,role:"Skirmisher",xp:350,size:"Medium",origin:"Natural",type:"Humanoid",hp:86,ac:21,fort:19,ref:20,will:18,initiative:9,perception:10,speed:"6",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, fear"],vulnerable:["5 radiant"],powers:[{name:"Maniacal Laughter",action:"Aura",description:"Aura 1 Enemies in the aura take a -2 penalty to attack rolls."},{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 1d6 + 9 damage."},{name:"Mad Slash",action:"Standard",keywords:["necrotic","weapon"],description:"Effect: Before and after the attack, Uthelyn can shift up to 2 squares. Attack: Melee 1 (one creature); +13 vs. AC Hit: 1d6 + 9 damage, plus 2d6 necrotic damage if Uthelyn has combat advantage against the target."},{name:"Ghostly Escape",action:"Triggered",recharge:"Encounter",description:"Trigger: Uthelyn is subjected to an effect that immobilizes, slows, or restrains her. Effect (Immediate Reaction): The triggering effect ends, and Uthelyn is insubstantial and phasing until the end of her next turn. Skills Acrobatics +12, Diplomacy +11"}],alignment:"Evil",languages:["Common","Elven Equipment : leather armor","short sword . Monster Vault: Threats to the Nentir Vale","page(s) 17."] },
  { id:"mvttnv-wild-coldscale-drake",name:"Wild Coldscale Drake",source:"mvttnv",level:8,role:"Lurker",xp:350,size:"Medium",origin:"Natural",type:"Beast",keywords:["reptile"],hp:70,ac:22,fort:20,ref:21,will:18,initiative:14,perception:7,speed:"8 (ice walk)",resist:["5 cold"],powers:[{name:"Ice Hunter's Bite",action:"Trait",description:"The drake's attacks deal 4d6 extra damage to any creature that can't see it"},{name:"Snow Camouflage",action:"Trait",description:"While it is in icy or snowy terrain, the drake has partial concealment"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d8 + 3 damage. Snow Stalker ✦ At-Will Requirement: The drake must be in icy or snowy terrain or within 10 squares of a white dragon. Effect: The drake becomes invisible until immediately after it attacks or until the end of its next turn. Skills Stealth +15"}],alignment:"Unaligned",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 23."] },
  { id:"mvttnv-bloodspear-savage-throng",name:"Bloodspear Savage Throng",source:"mvttnv",level:9,role:"Brute",xp:400,size:"Huge",origin:"Natural",type:"Humanoid",hp:117,ac:21,fort:22,ref:21,will:20,initiative:6,perception:4,speed:"6",senses:["Low-light vision"],resist:["half damage from melee and ranged attacks"],vulnerable:["10 to close and area attacks"],powers:[{name:"Swarm Attack",action:"Aura",description:"Aura 1 Any enemy that ends its turn in the aura takes 4 damage"},{name:"Swarm",action:"Trait",description:"The swarm can occupy the same space as another creature, and an enemy can enter its space, which is difficult terrain"},{name:"The",action:"Trait",description:"swarm cannot be pulled, pushed, or slid by melee or ranged attacks"},{name:"It",action:"Trait",description:"can squeeze through any opening that is large enough for a Medium creature"},{name:"Mob of Swinging Axes",action:"Standard",description:"Attack: Melee 1 (one creature); +14 vs. AC Hit: 2d12 + 4 damage."},{name:"Savage Frenzy",action:"Standard",recharge:"Encounter",description:"Attack: Close burst 1 (enemies in the burst); +14 vs. AC Hit: 2d10 + 8 damage, and the target is dazed (save ends). Miss: Half damage."},{name:"Trample",action:"Move",recharge:"Recharge when first bloodied",description:"Effect: The savage throng moves up to half its speed and can move through enemies' spaces during the move. Each time the throng enters an enemy's space for the first time during the move, it makes the following attack against that enemy. Attack: Melee 0 (enemy in the space); +12 vs. Reflex Hit: 3d6 + 5 damage, and the enemy falls prone."}],alignment:"Chaotic Evil",languages:["Common","Giant Monster Vault: Threats to the Nentir Vale","page(s) 37."] },
  { id:"mvttnv-boldos-grimehammer",name:"Boldos Grimehammer",source:"mvttnv",level:9,role:"Brute",xp:400,size:"Medium",origin:"Natural",type:"Humanoid",hp:122,ac:21,fort:20,ref:19,will:19,initiative:5,perception:10,speed:"5",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, fear"],vulnerable:["5 radiant"],powers:[{name:"Stand Your Ground",action:"Trait",description:"When an effect forces Boldos to move—through a pull, a push, or a slide—he can move 1 square fewer than the effect specifies. In addition, when an attack would knock Boldos prone, he can immediately make a saving throw to avoid falling prone"},{name:"Battleaxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +14 vs. AC Hit: 2d10 + 10 damage."},{name:"Mighty Swing",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one or two creatures); +14 vs. AC Hit: 2d10 + 5 damage, and Boldos either pushes the target 1 square or knocks it prone."},{name:"Soldier of Fortune",action:"Triggered",description:"Trigger: Boldos is hit by an attack that pulls, pushes, or slides him. Effect (Immediate Interrupt): Boldos uses battleaxe and gains a +5 bonus to the damage roll. Skills Athletics +13, Dungeoneering +10, Endurance +17"}],alignment:"Evil",languages:["Common","Dwarven Equipment : tarnished chain armor","broken shield","battleaxe . Monster Vault: Threats to the Nentir Vale","page(s) 19."] },
  { id:"mvttnv-cadaver-collector",name:"Cadaver Collector",source:"mvttnv",level:9,role:"Soldier",roleModifier:"Elite",xp:800,size:"Large",origin:"Natural",type:"Animate",keywords:["construct"],hp:200,ac:25,fort:23,ref:20,will:20,initiative:8,perception:11,speed:"8",senses:["Darkvision"],resist:["10 lightning"],immune:["charm, disease, poison"],powers:[{name:"Thunder Shakes Whenever",action:"Trait",description:"the cadaver collector takes thunder damage, it is slowed (save ends)"},{name:"Slam",action:"Standard",description:"Attack: Melee 2 (one creature); +14 vs. AC, or +16 vs. AC against an immobilized target. Hit: 2d10 + 6 damage, and the target is grabbed (escape DC 20). The collector can grab no more than one Large creature or four Medium or smaller creatures at a time."},{name:"Double Slam",action:"Standard",description:"Effect: The cadaver collector uses slam twice."},{name:"Impale",action:"Standard",description:"Attack: Melee 1 (one Large or smaller creature grabbed by the collector); +12 vs. Reflex Hit: 4d10 + 12 damage, and the target is pulled into the collector's space and restrained (save ends). Until this effect ends, the target takes ongoing 10 damage. Also, when the collector moves, it pulls with it any creature restrained by it, and the creature remains in the collector's space. When a creature saves against this effect, it appears in the nearest unoccupied space of its choice adjacent to the collector."},{name:"Trample",action:"Standard",recharge:"Encounter",description:"Effect: The collector moves up to its speed and can move through enemies' spaces during the move. Each time the collector enters an enemy's space for the first time during the move, it makes the following attack a against that enemy. Attack: Melee 0 (enemy in the space); +12 vs. Reflex Hit: 3d12 + 6 damage, and the enemy falls prone."},{name:"Breath Weapon",action:"Minor",recharge:"Recharge 4-6",description:"Attack: Close blast 3 (creatures in the blast); +12 vs. Fortitude Hit: The target is immobilized (save ends)."}],alignment:"Unaligned",languages:["Common Monster Vault: Threats to the Nentir Vale","page(s) 30","Dungeon Magazine 214."] },
  { id:"mvttnv-cassian-d-cherevan",name:"Cassian d'Cherevan",source:"mvttnv",level:9,role:"Soldier",roleModifier:"Elite",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:192,ac:25,fort:22,ref:20,will:21,initiative:8,perception:9,speed:"5",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, fear"],vulnerable:["5 radiant"],powers:[{name:"Greatsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +14 vs. AC Hit: 2d10 + 6 damage."},{name:"Double Attack",action:"Standard",description:"Effect: Cassian uses greatsword twice."},{name:"Call of War",action:"Standard",recharge:"Encounter",description:"Effect: Cassian uses greatsword, and each ally within 5 squares of him can take a free action to shift up to 2 squares and make a melee basic attack."},{name:"Bolstering Presence",action:"Minor",recharge:"Recharge 4-6",description:"Effect: Close burst 3 (allies in the burst). Each target gains a +5 power bonus to damage rolls until the end of Cassian's next turn."},{name:"Relentless Assault",action:"Triggered",description:"Trigger: An enemy adjacent to Cassian uses an attack power that doesn't include him as a target. Effect (Free Action): Melee 1 (triggering enemy). The target takes 12 damage. Skills Athletics +13, Intimidate +12"}],alignment:"Evil",languages:["Common Equipment : greatsword","plate armor . Monster Vault: Threats to the Nentir Vale","page(s) 19."] },
  { id:"mvttnv-chillborn-vampiric-mist",name:"Chillborn Vampiric Mist",source:"mvttnv",level:9,role:"Soldier",xp:400,size:"Medium",origin:"Shadow",type:"Animate",keywords:["undead"],hp:85,ac:25,fort:22,ref:21,will:20,initiative:10,perception:7,speed:"0, fly 5 (altitude limit 2)",senses:["Darkvision"],resist:["10 cold,","10 necrotic,","10 poison"],immune:["disease"],vulnerable:["5 radiant"],powers:[{name:"Siphoning Presence",action:"Aura",keywords:["cold","necrotic"],description:"Aura 1 Enemies can't spend healing surges in the aura"},{name:"When",action:"Trait",description:"an enemy ends its turn in the aura, it takes 5 cold and necrotic damage, and the mist gains 5 temporary hit points"},{name:"Insubstantial",action:"Trait",description:"The mist takes half damage from any damage source, except those that deal fire, force, or radiant damage"},{name:"When",action:"Trait",description:"it takes fire or radiant damage, it loses this trait until the start of its next turn"},{name:"Mist Form",action:"Trait",description:"The mist can move through openings of any size"},{name:"It",action:"Trait",description:"can also enter other creatures' spaces and end its turn there"},{name:"Bite",action:"Standard",keywords:["cold","necrotic"],description:"Attack: Melee 1 (one creature); +12 vs. Fortitude Hit: 3d6 + 7 cold and necrotic damage, and the target is slowed until the end of the mist's next turn."},{name:"Grasp of the Cold Grave",action:"Standard",keywords:["cold","necrotic"],description:"Attack: Melee 1 (one creature); +12 vs. Fortitude Hit: 3d6 + 7 cold and necrotic damage, and the target is immobilized until the end of the mist's next turn."}],alignment:"Evil",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 111."] },
  { id:"mvttnv-gokof-hobgoblin-necromancer",name:"Gokof, Hobgoblin Necromancer",source:"mvttnv",level:9,role:"Controller",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:85,ac:23,fort:20,ref:20,will:22,initiative:7,perception:14,speed:"6",senses:["Low-light vision"],powers:[{name:"Staff",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +14 vs. AC Hit: 2d8 + 8 damage."},{name:"Necrotic Ray",action:"Standard",keywords:["implement","necrotic"],description:"Attack: Ranged 5 (one creature); +12 vs. Fortitude Hit: 3d8 + 5 necrotic damage. Effect: The target is slowed until the end of Gokof's next turn. Command Animate ✦ At-Will Effect: One allied animate that Gokof can see makes a melee basic attack as a free action."},{name:"Sapping Tendrils",action:"Standard",keywords:["implement","necrotic"],recharge:"Recharge 4-6",description:"Attack: Area burst 1 within 5 (creatures in the burst); +12 vs. Fortitude Hit: 2d10 + 4 necrotic damage, and the target is immobilized and takes ongoing 5 necrotic damage (save ends both)."},{name:"Dark Healing",action:"Triggered",keywords:["healing","necrotic"],recharge:"Encounter",description:"Trigger: An enemy within 5 squares of Gokof regains hit points. Effect (Immediate Reaction): The triggering enemy takes 3d8 + 12 necrotic damage, and Gokof regains 24 hit points. Skills Intimidate +11, Stealth +12, Thievery +12"}],alignment:"Evil",languages:["Common","Goblin Equipment : staff implement . Monster Vault: Threats to the Nentir Vale","page(s) 31."] },
  { id:"mvttnv-gray-company-mist-mage",name:"Gray Company Mist Mage",source:"mvttnv",level:9,role:"Controller",xp:400,size:"Medium",origin:"Natural",type:"Humanoid",hp:95,ac:23,fort:20,ref:23,will:21,initiative:8,perception:7,speed:"6",resist:["5 cold"],powers:[{name:"Grim Solidarity",action:"Trait",description:"If the mage starts its turn adjacent to a creature that has grim solidarity, it can make a saving throw against one effect that a save can end"},{name:"Ice Dagger",action:"Standard",keywords:["cold","weapon"],description:"Attack: Melee 1 (one creature); +14 vs. AC Hit: 2d4 + 12 cold damage, and the target is slowed until the end of the mage's next turn."},{name:"Misty Tendrils",action:"Standard",keywords:["cold","implement"],description:"Attack: Close blast 3 (enemies in the blast); +12 vs. Reflex Hit: 2d6 + 6 cold damage. Effect: The mage can slide the target 1 square. Gray Mist (zone) ✦ Encounter Effect: Area burst 2 within 10. The burst creates a zone that lasts until the end of the mage's next turn. Any creature that ends its turn in the zone takes a -2 penalty to attack rolls and is slowed until the end of its next turn. Sustain Minor: The zone persists until the end of the mage's next turn."},{name:"Freeze Mist",action:"Minor",description:"1/round Attack: Ranged 5 (one slowed creature); +12 vs. Reflex Hit: The target is immobilized until the end of the mage's next turn. Skills Arcana +14, History +14"}],alignment:"Unaligned",languages:["Common Equipment : robes","dagger","wand implement . Monster Vault: Threats to the Nentir Vale","page(s) 61."] },
  { id:"mvttnv-harken-s-heart-defender",name:"Harken's Heart Defender",source:"mvttnv",level:9,role:"Soldier",xp:400,size:"Medium",origin:"Natural",type:"Humanoid",hp:95,ac:25,fort:20,ref:22,will:20,initiative:11,perception:11,speed:"7 (forest walk)",senses:["Low-light vision"],powers:[{name:"Wild Step",action:"Trait",description:"The defender ignores difficult terrain whenever it shifts"},{name:"Mangle",action:"Standard",description:"Requirement: The defender must be in beast form. Attack: Melee 1 (one creature); +14 vs. AC Hit: 2d8 + 8 damage, and the target is slowed until the end of its next turn."},{name:"Quarterstaff",action:"Standard",keywords:["weapon"],description:"Requirement: The defender must be in humanoid form. Attack: Melee 1 (one creature); +14 vs. AC Hit: 2d8 + 8 damage."},{name:"Primal Flurry",action:"Standard",recharge:"Recharge when first bloodied",description:"Requirement: The defender must be in beast form. Attack: Close burst 1 (enemies in the burst); +12 vs. Reflex Hit: 2d8 + 8 damage, and the target falls prone. If the target stands up during its next turn, the defender can make a melee basic attack against it as a free action. Miss: Half damage, and the target falls prone."},{name:"Beast's Pursuit",action:"Move",recharge:"Encounter",description:"Requirement: The defender must be in beast form. Effect: The defender shifts up to its speed to a square adjacent to an enemy and gains a +2 power bonus to attack rolls until the end of its turn."},{name:"Change Shape",action:"Minor",keywords:["polymorph"],description:"Effect: The defender alters its physical form to appear as a Medium beast until it uses change shape again or until it dies. It can also use this power to return to its humanoid form. Skills Acrobatics +14, Athletics +12, Stealth +14"}],alignment:"Unaligned",languages:["Common","Elven Equipment : quarterstaff . Monster Vault: Threats to the Nentir Vale","page(s) 65."] },
  { id:"mvttnv-hurly-burly",name:"Hurly/Burly",source:"mvttnv",level:9,role:"Brute",roleModifier:"Elite",xp:800,size:"Large",origin:"Natural",type:"Humanoid",hp:240,ac:21,fort:22,ref:20,will:18,initiative:8,perception:11,speed:"8",powers:[{name:"Bound",action:"Trait",description:"by Blood If Hurly or Burly is reduced to 0 hit points by damage that isn't acid or fire, he does not die and instead falls unconscious until the start of his next turn, when he returns to life with 30 hit points"},{name:"If",action:"Trait",description:"an attack hits him and deals any acid or fire damage while he is unconscious and within 5 squares of his brother, he does not return to life in this way"},{name:"When",action:"Trait",description:"one brother dies, the other loses this trait"},{name:"Regeneration Hurly",action:"Trait",description:"or Burly regains 10 hit points whenever he starts his turn and has at least 1 hit point"},{name:"When",action:"Trait",description:"he takes acid or fire damage, his regeneration does not function on his next turn"},{name:"Battleaxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +14 vs. AC Hit: 2d8 + 12 damage."},{name:"Cleave",action:"Standard",keywords:["weapon"],description:"Attack: Close burst 2 (enemies in the burst); +14 vs. AC Hit: 2d8 + 7 damage, and Hurly/Burly can push the target 1 square. Skills Athletics +15, Nature +11"}],alignment:"Chaotic Evil",languages:["Common","Giant Equipment : battleaxe . Monster Vault: Threats to the Nentir Vale","page(s) 71."] },
  { id:"mvttnv-kabo-bomble",name:"Kabo Bomble",source:"mvttnv",level:9,role:"Brute",xp:400,size:"Medium",origin:"Natural",type:"Humanoid",hp:116,ac:21,fort:22,ref:20,will:18,initiative:7,perception:3,speed:"5",senses:["Low-light vision"],powers:[{name:"Combat Adept At",action:"Trait",description:"the start of an encounter, Kabo's attacks deal 1d10 extra damage against any enemy that has not yet acted during the encounter"},{name:"Daggerburg Tactics Whenever",action:"Trait",description:"an enemy misses Kabo with a melee attack, he gains combat advantage against that enemy until the end of his next turn"},{name:"Morningstar",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +14 vs. AC Hit: 2d10 + 10 damage."},{name:"Spiked Gauntlet",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +12 vs. Reflex Hit: 3d6 + 10 damage. On a critical hit, the target is also dazed (save ends)."},{name:"Furious Attack",action:"Standard",recharge:"Recharge when first bloodied",description:"Effect: Kabo uses morningstar and spiked gauntlet. If both attacks hit the same target, the target is dazed until the end of Kabo's next turn."},{name:"Roar",action:"Minor",keywords:["fear"],recharge:"Encounter",description:"Attack: Close burst 2 (enemies in the burst); +12 vs. Will Hit: The target takes a -2 penalty to all defenses (save ends)."}],alignment:"Evil",languages:["Common","Goblin Equipment : chainmail","morningstar","spiked gauntlet . Monster Vault: Threats to the Nentir Vale","page(s) 41."] },
  { id:"mvttnv-lingering-monster-spirit",name:"Lingering Monster Spirit",source:"mvttnv",level:9,role:"Brute",roleModifier:"Minion",xp:100,size:"Large",origin:"Shadow",type:"Beast",keywords:["undead"],hp:1,ac:21,fort:20,ref:22,will:20,initiative:8,perception:4,speed:"8, climb 6",senses:["Darkvision"],resist:["20 all except radiant"],immune:["disease, fear"],powers:[{name:"Savage Strike",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +14 vs. AC Hit: 7 damage."}],alignment:"Unaligned",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 17."] },
  { id:"mvttnv-penanggalan-bodiless-head",name:"Penanggalan Bodiless Head",source:"mvttnv",level:9,role:"Skirmisher",xp:400,size:"Small",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:94,ac:23,fort:20,ref:22,will:22,initiative:11,perception:6,speed:"6, fly 8 (hover)",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, poison"],vulnerable:["5 radiant"],powers:[{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +14 vs. AC Hit: 3d8 + 4 damage. If the target is granting combat advantage to the penanggalan, the target is slowed (save ends)."},{name:"Flailing Entrails",action:"Standard",keywords:["poison"],description:"Attack: Melee 2 (one or two creatures); +12 vs. Reflex Hit: 2d8 + 3 poison damage, and the penanggalan can slide the target 1 square."},{name:"Malleable Rush",action:"Move",recharge:"Recharge when first bloodied",description:"Effect: The penanggalan is phasing until the end of its next turn and shifts up to its speed."},{name:"Death Burst",action:"Triggered",keywords:["disease","poison"],recharge:"Encounter",description:"Trigger: The penanggalan dies. Attack (No Action): Close burst 1 (creatures in the burst); +12 vs. Fortitude Hit: 3d8 + 6 poison damage. At the end of the encounter, the target makes a saving throw. On a failure, the target contracts blistering corruption (stage 1). Skills Stealth +14"}],alignment:"Evil",languages:["Common Blistering Corruption Level 10 Disease Stage 0 : The target recovers from the disease. Stage 1 : While affected by this stage","the target takes a -2 penalty to Fortitude. Stage 2 : While affected by this stage","the target takes a -2 penalty to Fortitude. In addition","the target regains only half the normal number of hit points from spending a healing surge","and the target's hit point total cannot exceed its bloodied value. Stage 3 : While affected by this stage","the target suffers the effects of stage 2 and has an aura 2 (poison) that cannot be deactivated. Any creature that ends its turn in the aura loses a healing surge. Check : At the end of each extended rest","the target makes an Endurance check if it is at stage 1 or 2. 12 or lower : The stage of the disease increases by one. 13-17 : No Change 18 or higher : The stage of the disease decreases by one. Monster Vault: Threats to the Nentir Vale","page(s) 83."] },
  { id:"mvttnv-plague-demon-chaos-vanguard",name:"Plague Demon Chaos Vanguard",source:"mvttnv",level:9,role:"Soldier",xp:400,size:"Large",origin:"Elemental",type:"Beast",keywords:["demon"],hp:100,ac:25,fort:24,ref:19,will:19,initiative:8,perception:6,speed:"6",senses:["Darkvision"],resist:["5 to the triggering damage type until the end of the encounter or until it uses variable resistance again."],powers:[{name:"Crimson Retribution",action:"Aura",description:"Aura 2 Whenever an enemy in the aura makes an attack that doesn't include the plague demon as a target, the enemy takes 10 damage."},{name:"Slam",action:"Standard",description:"Attack: Melee 2 (one creature); +14 vs. AC Hit: 3d6 + 6 damage, and the plague demon pushes the target up to 2 squares."},{name:"Sweeping Crystal Blade",action:"Standard",keywords:["disease","weapon"],recharge:"Recharge 3-6",description:"Attack: Close blast 3 (enemies in the blast); +14 vs. AC Hit: 2d12 + 6 damage. At the end of the encounter, the target makes a saving throw. On a failure, the target contracts Abyssal plague (stage 1)."},{name:"Variable Resistance",action:"Triggered",recharge:"2/Encounter",description:"Trigger: The plague demon takes acid, cold, fire, lightning, or thunder damage. Effect (Free Action): The plague demon gains resist 5 to the triggering damage type until the end of the encounter or until it uses variable resistance again."}],alignment:"Chaotic Evil",languages:["Abyssal Monster Vault: Threats to the Nentir Vale","page(s) 16."] },
  { id:"mvttnv-vampiric-mist",name:"Vampiric Mist",source:"mvttnv",level:9,role:"Skirmisher",xp:400,size:"Medium",origin:"Shadow",type:"Animate",keywords:["undead"],hp:85,ac:23,fort:21,ref:21,will:19,initiative:11,perception:7,speed:"0, fly 5 (altitude limit 2)",senses:["Darkvision"],resist:["10 necrotic,","10 poison"],immune:["disease"],vulnerable:["5 radiant"],powers:[{name:"Siphoning Presence",action:"Aura",keywords:["necrotic"],description:"Aura 1 Enemies can't spend healing surges in the aura"},{name:"When",action:"Trait",description:"an enemy ends its turn in the aura, it takes 5 necrotic damage, and the mist gains 5 temporary hit points"},{name:"Insubstantial",action:"Trait",description:"The mist takes half damage from any damage source, except those that deal fire, force, or radiant damage"},{name:"When",action:"Trait",description:"it takes fire or radiant damage, it loses this trait until the start of its next turn"},{name:"Mist Form",action:"Trait",description:"The mist can move through openings of any size"},{name:"It",action:"Trait",description:"can also enter other creatures' spaces and end its turn there"},{name:"Life Drain",action:"Standard",keywords:["necrotic"],description:"Attack: Melee 1 (one creature); +12 vs. Fortitude Hit: 3d6 + 7 necrotic damage, and the target gains vulnerable 5 necrotic until the end of the mist's next turn."},{name:"Wave of Lethargy",action:"Standard",keywords:["necrotic","psychic"],recharge:"Recharge 4-6",description:"Attack: Close burst 2 (creatures in the burst); +12 vs. Fortitude Hit: 2d10 + 2 necrotic and psychic damage, and the target is slowed until the end of the mist's next turn."},{name:"Shifting Mists",action:"Move",description:"Effect: The mist shifts up to its speed."}],alignment:"Evil",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 110","Dungeon Magazine 207","Dungeon Magazine 221."] },
  { id:"mvttnv-bitterstrike",name:"Bitterstrike",source:"mvttnv",level:10,role:"Brute",roleModifier:"Solo",xp:2500,size:"Large",origin:"Natural",type:"Magical beast",keywords:["dragon"],hp:520,ac:22,fort:23,ref:20,will:21,initiative:6,perception:12,speed:"6 (ice walk), fly 6",senses:["Darkvision"],resist:["10 cold"],powers:[{name:"Action Recovery Whenever Bitterstrike",action:"Trait",description:"ends her turn, any dazing, stunning, or dominating effect on her ends"},{name:"Instinctive Rampage On",action:"Trait",description:"an initiative of 10 + Bitterstrike's initiative check, Bitterstrike can move up to her speed as a free action. During the move, Bitterstrike can move through enemies' spaces and has resist 5 to all damage"},{name:"Each",action:"Trait",description:"time Bitterstrike enters an enemy's space for the first time during the move, she can use claw against that enemy"},{name:"If",action:"Trait",description:"the attack hits, the target also falls prone"},{name:"If Bitterstrike",action:"Trait",description:"cannot use a free action to take this move due to a dominating or a stunning effect, then that effect ends instead of Bitterstrike taking this move"},{name:"Savage Blood",action:"Trait",description:"While bloodied, Bitterstrike can score a critical hit on a roll of 17–20"},{name:"Bite",action:"Standard",keywords:["cold"],description:"Attack: Melee 2 (one creature); +15 vs. AC Hit: 3d10 + 6 cold damage. Miss: Half damage."},{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one or two creatures); +15 vs. AC Hit: 3d8 + 9 damage."},{name:"Breath Weapon",action:"Standard",keywords:["cold"],recharge:"Recharge 4-6",description:"Attack: Close blast 5 (creatures in the blast); +13 vs. Reflex Hit: 2d10 + 9 cold damage, and the target is slowed (save ends). Miss: Half damage, and the target is slowed until the end of Bitterstrike's next turn."},{name:"Tail Slap",action:"Triggered",description:"Trigger: An enemy flanking Bitterstrike hits her. Attack (Free Action): Melee 2 (the triggering enemy); +13 vs. Fortitude Hit: 3d6 + 8 damage, and Bitterstrike pushes the target up to 5 squares."},{name:"Bloodied Breath",action:"Triggered",recharge:"Encounter",description:"Trigger: Bitterstrike is first bloodied. Effect (Free Action): Breath weapon recharges, and Bitterstrike uses it."},{name:"Bitter Vengeance",action:"Triggered",keywords:["cold"],recharge:"Encounter",description:"Trigger: An enemy within 5 squares of Bitterstrike hits her with an attack. Effect (Free Action): Close burst 5 (triggering enemy in the burst). The target takes 10 cold damage, and Bitterstrike pushes it up to 2 squares. Skills Athletics +15"}],alignment:"Evil",languages:["Common","Draconic Monster Vault: Threats to the Nentir Vale","page(s) 21."] },
  { id:"mvttnv-bregga-hound-of-ill-omen",name:"Bregga, Hound of Ill Omen",source:"mvttnv",level:10,role:"Skirmisher",roleModifier:"Elite",xp:1000,size:"Large",origin:"Shadow",type:"Beast",keywords:["undead"],hp:212,ac:24,fort:22,ref:23,will:20,initiative:13,perception:12,speed:"8; phasing",senses:["Darkvision"],immune:["disease, poison"],powers:[{name:"Ill Omen",action:"Aura",description:"Aura 2 Any enemy that spends a healing surge while in the aura is slowed until the end of its next turn"},{name:"Insubstantial Bregga",action:"Trait",description:"takes half damage from any damage source, except those that deal force damage or radiant damage. In addition, if she takes radiant damage, she loses the insubstantial trait until the end of her next turn"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 3d8 + 5 damage."},{name:"Clamping Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 3d8 + 5 damage, and Bregga can shift up to half her speed, pulling the target with her. The target remains adjacent to Bregga during this movement."},{name:"Drag and Snap",action:"Standard",description:"Effect: Bregga uses clamping bite and then bite against the same target."},{name:"Howl of Doom",action:"Standard",keywords:["psychic","thunder"],recharge:"Encounter",description:"Attack: Close blast 5 (enemies in the blast); +13 vs. Will Hit: 3d10 + 11 thunder damage, and the target is cursed. Until the target is no longer cursed, it takes 3 psychic damage whenever it misses every target with an attack power. At the end of each of the target's extended rests, it makes a DC 18 Religion check to try to end the curse. First Failed Check: The psychic damage increases to 6. Second Failed Check: The psychic damage increases to 9. Third Failed Check: The target dies. Miss: Half damage."},{name:"Ghostly Travel",action:"Move",keywords:["illusion"],recharge:"Recharge when first bloodied",description:"Effect: Bregga becomes invisible and moves up to her speed. She remains invisible until the end of her turn."}],alignment:"Unaligned",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 66."] },
  { id:"mvttnv-bronze-warder",name:"Bronze Warder",source:"mvttnv",level:10,role:"Soldier",roleModifier:"Elite",xp:1000,size:"Large",origin:"Natural",type:"Animate",keywords:["construct"],hp:168,ac:26,fort:24,ref:21,will:21,initiative:7,perception:4,speed:"5",senses:["Darkvision"],resist:["5 all"],immune:["charm, fear, poison"],powers:[{name:"Inexorable Movement",action:"Trait",description:"The bronze warder can enter the spaces of Medium or Small enemies"},{name:"Ponderous",action:"Trait",description:"The bronze warder cannot shift"},{name:"Greataxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +15 vs. AC Hit: 2d12 + 5 damage. Effect: The target is marked until the end of the bronze warder's next turn."},{name:"Double Attack",action:"Standard",description:"Effect: The bronze warder uses greataxe twice."},{name:"Rampage",action:"Standard",keywords:["weapon"],recharge:"Recharge when first bloodied",description:"Effect: The bronze warder can move up to 3 squares. Whenever the bronze warder enters an enemy's space during this movement, that enemy falls prone. At the end of the movement, the bronze warder then makes the following attack. Attack: Close burst 2 (enemies in the burst); +15 vs. AC Hit: 3d12 + 10 damage, and ongoing 5 damage (save ends)."},{name:"Guard",action:"Triggered",description:"Trigger: The bronze warder's master is damaged by an attack and is within 2 squares of the warder. Effect (Immediate Interrupt): The bronze warder takes half of the triggering attack's damage, and its master takes the other half."}],alignment:"Unaligned",languages:["- Equipment : greataxe . Monster Vault: Threats to the Nentir Vale","page(s) 77."] },
  { id:"mvttnv-dythan-s-legion-archer",name:"Dythan's Legion Archer",source:"mvttnv",level:10,role:"Artillery",xp:500,size:"Medium",origin:"Natural",type:"Humanoid",hp:84,ac:24,fort:23,ref:23,will:20,initiative:9,perception:6,speed:"6",powers:[{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +15 vs. AC. The archer has a +2 bonus to hit while bloodied. Hit: 3d6 + 8 damage."},{name:"Longbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 20 (one creature); +17 vs. AC. The archer has a +2 bonus to hit while bloodied. Hit: 2d10 + 7 damage."},{name:"Arrow Volley",action:"Standard",keywords:["weapon"],recharge:"Recharge 3-6",description:"Attack: Area burst 1 within 20 (enemies in the burst); +17 vs. AC. The archer gains a +2 bonus to hit while bloodied. Hit: 1d10 + 8 damage."},{name:"Dragon Breath",action:"Minor",keywords:["cold"],recharge:"Encounter",description:"Attack: Close blast 3 (creatures in the blast); +13 vs. Reflex. The archer has a +2 bonus to hit while bloodied. Hit: 1d6 + 6 cold damage, and the archer can push the target 1 square."}],alignment:"Evil",languages:["Common","Draconic Equipment : arrow x20","leather armor","longbow","short sword . Monster Vault: Threats to the Nentir Vale","page(s) 47","Dungeon Magazine 202."] },
  { id:"mvttnv-dythan-s-legion-warrior",name:"Dythan's Legion Warrior",source:"mvttnv",level:10,role:"Skirmisher",roleModifier:"Minion",xp:125,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:24,fort:23,ref:22,will:22,initiative:10,perception:6,speed:"6",powers:[{name:"Phalanx Formation",action:"Trait",description:"The warrior gains a +1 power bonus to AC for each ally adjacent to it, up to a maximum power bonus of +4"},{name:"Spear",action:"Standard",keywords:["weapon"],description:"Effect: Before and after the attack, the warrior can shift 1 square. Attack: Melee 1 (one creature); +15 vs. AC Hit: 8 damage, or 10 while the warrior has combat advantage against the target."},{name:"Javelin",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10 (one creature); +15 vs. AC Hit: 8 damage."},{name:"Dragon Breath",action:"Minor",keywords:["lightning"],recharge:"Encounter",description:"Attack: Close blast 3 (creatures in the blast); +13 vs. Reflex Hit: 9 lightning damage."}],alignment:"Evil",languages:["Common","Draconic Equipment : heavy shield","javelin x4","leather armor","spear . Monster Vault: Threats to the Nentir Vale","page(s) 47","Dungeon Magazine 202."] },
  { id:"mvttnv-frost-witch-vassal",name:"Frost Witch Vassal",source:"mvttnv",level:10,role:"Controller",roleModifier:"Elite",xp:1000,size:"Medium",origin:"Natural",type:"Humanoid",hp:204,ac:24,fort:20,ref:23,will:21,initiative:9,perception:7,speed:"6 (ice walk)",senses:["Low-light vision"],resist:["10 cold"],powers:[{name:"Chill Aura",action:"Aura",description:"Aura 1 Any enemy that ends its turn in the aura is slowed until the end of its next turn."},{name:"Frost Touch",action:"Standard",keywords:["cold"],description:"Attack: Melee 1 (one creature); +13 vs. Reflex Hit: 2d6 + 8 cold damage, and the witch slides the target up to 2 squares."},{name:"Icicle Shard",action:"Standard",keywords:["cold","implement"],description:"Attack: Ranged 5 (one or two creatures); +15 vs. AC Hit: 3d6 + 8 cold damage, and the target is immobilized until the end of the witch's next turn."},{name:"Hailstone Hex",action:"Standard",keywords:["cold","implement","psychic"],recharge:"Recharge when first bloodied",description:"Attack: Ranged 5 (one creature); +13 vs. Fortitude Hit: 3d8 + 6 cold and psychic damage, and the target grants combat advantage and takes ongoing 5 cold and psychic damage (save ends both). While this effect persists, any enemy of the witch that starts its turn adjacent to the target takes 5 cold and psychic damage. Miss: Half damage, and ongoing 5 cold and psychic damage (save ends)."},{name:"Bitter Vengeance",action:"Triggered",keywords:["cold"],recharge:"Recharge when first bloodied",description:"Trigger: An enemy within 5 squares of the witch hits it with an attack. Effect (Free Action): Close burst 5 (triggering enemy in the burst). The target takes 10 cold damage, and the witch pushes it up to 2 squares. Skills Arcana +15, Bluff +13, Nature +12"}],alignment:"Evil",languages:["Common","Draconic","Elven Equipment : wand implement . Monster Vault: Threats to the Nentir Vale","page(s) 23."] },
  { id:"mvttnv-harken-s-heart-hierophant",name:"Harken's Heart Hierophant",source:"mvttnv",level:10,role:"Artillery",roleModifier:"Elite",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:166,ac:24,fort:20,ref:22,will:24,initiative:9,perception:14,speed:"7 (forest walk)",senses:["Low-light vision"],powers:[{name:"Wild Step",action:"Trait",description:"The Hierophant ignores difficult terrain whenever it shifts"},{name:"Quarterstaff",action:"Standard",keywords:["weapon"],description:"Requirement: The Hierophant must be in humanoid form. Attack: Melee 1 (one creature); +15 vs. AC Hit: 2d8 + 9 damage."},{name:"Earth Slam",action:"Standard",description:"Requirement: The Hierophant must be in humanoid form. Attack: Ranged 20 (one or two creatures); +15 vs. Fortitude Hit: 3d6 + 9 damage. On a critical hit, the target falls prone."},{name:"Frenzied Escape",action:"Standard",recharge:"Recharge when first bloodied",description:"Requirement: The Hierophant must be in beast form. Attack: Close burst 1 (enemies in the burst); +13 vs. Reflex Hit: 3d10 + 12 damage, and ongoing 10 damage (save ends). Effect: The Hierophant shifts up to its speed to a square that is not adjacent to an enemy. It gains a +4 power bonus to all defenses during this movement."},{name:"Lightning Storm",action:"Standard",keywords:["lightning","thunder","zone"],recharge:"Recharge 4-6",description:"Requirement: The Hierophant must be in humanoid form. Attack: Area burst 1 within 20 (creatures in the burst); +15 vs. Reflex Hit: 4d8 + 10 lightning damage, and ongoing 10 thunder damage (save ends). Effect: The burst creates a zone that lasts until the end of the Hierophant's next turn. Any creature that ends its turn in the zone takes 10 lightning damage."},{name:"Change Shape",action:"Minor",keywords:["polymorph"],description:"Effect: The Hierophant alters its physical form to appear as a Medium beast until it uses change shape again or until it dies. It can also use this power to return to its humanoid form."},{name:"Guardian of the Forest",action:"Minor",description:"1/round Attack: Ranged 20 (one creature); +13 vs. Will Hit: The Hierophant chooses an ally within 20 squares of it. The target is now marked by that ally (save ends). Skills Diplomacy +15, Insight +14, Nature +14"}],alignment:"Unaligned",languages:["Common","Elven Equipment : quarterstaff . Monster Vault: Threats to the Nentir Vale","page(s) 65."] },
  { id:"mvttnv-mooncalf",name:"Mooncalf",source:"mvttnv",level:10,role:"Controller",xp:500,size:"Large",origin:"Aberrant",type:"Magical beast",hp:112,ac:24,fort:24,ref:21,will:22,initiative:8,perception:13,speed:"6, fly 8",senses:["Darkvision"],resist:["10 lightning,","10 thunder"],powers:[{name:"Tentacle Snare",action:"Trait",description:"When the mooncalf moves, all creatures grabbed by it are pulled with it"},{name:"Tentacle Rake",action:"Standard",description:"Attack: Melee 4 (one creature not grabbed by the mooncalf); +15 vs. AC Hit: 2d10 + 7 damage."},{name:"Tentacle Grab",action:"Standard",description:"Attack: Melee 4 (one Large or smaller creature not grabbed by the mooncalf); +13 vs. Reflex Hit: 2d10 + 2 damage, the mooncalf pulls the target up to 3 squares, and the target is grabbed (escape DC 18). The target takes ongoing 5 damage until the grab ends. Special: The mooncalf can grab up to two creatures at once. It can release a grabbed creature as a free action."},{name:"Vile Bite",action:"Standard",description:"Attack: Melee 1 (one creature grabbed by the mooncalf); +15 vs. AC Hit: 2d8 + 9 damage, and the target cannot spend healing surges until the start of the mooncalf's next turn."},{name:"Lure",action:"Minor",keywords:["charm"],description:"1/round Attack: Close burst 10 (one creature in the burst); +13 vs. Will Hit: The mooncalf pulls the target up to 5 squares."},{name:"Stormwrack",action:"Minor",keywords:["lightning","thunder","zone"],recharge:"Encounter",description:"Effect: Area burst 2 within 10. The burst creates a zone that lasts until the end of the mooncalf's next turn. Any creature that ends its turn in the zone takes 10 lightning and thunder damage. Sustain Minor: The zone persists until the end of the mooncalf's next turn. Skills Stealth +13"}],alignment:"Evil",languages:["understands Deep Speech","telepathy 20 Monster Vault: Threats to the Nentir Vale","page(s) 80."] },
  { id:"mvttnv-mooncalf-harvester",name:"Mooncalf Harvester",source:"mvttnv",level:10,role:"Skirmisher",xp:500,size:"Large",origin:"Aberrant",type:"Magical beast",hp:107,ac:24,fort:22,ref:23,will:22,initiative:12,perception:13,speed:"6, fly 8",senses:["Darkvision"],resist:["10 lightning,","10 thunder"],powers:[{name:"Tentacle Snare",action:"Trait",description:"When the mooncalf moves, all creatures grabbed by it are pulled with it"},{name:"Tentacle Rake",action:"Standard",description:"Attack: Melee 4 (one creature not grabbed by the mooncalf); +15 vs. AC Hit: 2d8 + 9 damage."},{name:"Tentacle Grab",action:"Standard",description:"Attack: Melee 4 (one Large or smaller creature not grabbed by the mooncalf); +13 vs. Reflex Hit: 2d8 + 4 damage, the mooncalf pulls the target up to 3 squares, and the target is grabbed (escape DC 18). The target takes ongoing 5 damage until the grab ends. Special: The mooncalf can grab up to two creatures at once. It can release a grabbed creature as a free action."},{name:"Vile Bite",action:"Standard",description:"Attack: Melee 1 (one creature grabbed by the mooncalf); +15 vs. AC Hit: 2d6 + 11 damage, and the target cannot spend healing surges until the start of the mooncalf's next turn."},{name:"Teleport",action:"Move",keywords:["teleportation"],recharge:"Encounter",description:"Effect: The mooncalf teleports up to 10 squares. Any creatures grabbed by the mooncalf teleport with it. Skills Stealth +15"}],alignment:"Evil",languages:["understands Deep Speech","telepathy 20 Monster Vault: Threats to the Nentir Vale","page(s) 80."] },
  { id:"mvttnv-penanggalan",name:"Penanggalan",source:"mvttnv",level:10,role:"Lurker",roleModifier:"Elite",xp:1000,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["shapechanger","undead"],hp:162,ac:24,fort:19,ref:22,will:23,initiative:15,perception:13,speed:"6, fly 8 (hover) only in head form",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, poison"],vulnerable:["5 radiant"],powers:[{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Requirement: The penanggalan must be in maiden form. Attack: Melee 1 (one creature); +15 vs. AC Hit: 2d4 + 4 damage."},{name:"Soothing Voice",action:"Standard",keywords:["charm"],recharge:"Encounter",description:"Requirement: The penanggalan must be in maiden form. Attack: Close burst 1 (creatures in the burst); +13 vs. Will Hit: The target is slowed (save ends). First Failed Saving Throw: The target is unconscious instead of slowed (save ends)."},{name:"Horrific Transformation",action:"Standard",keywords:["fear","psychic"],recharge:"Encounter",description:"Requirement: The penanggalan must be in maiden form. Attack: Close burst 2 (enemies in the burst); +13 vs. Will Hit: 4d6 + 6 psychic damage, and the target is dazed until the end of its next turn. Effect: The penanggalan changes from maiden form to head form. While the creature is in head form, its headless body is considered a corpse. Unless the body is utterly destroyed, the creature can take a standard action to return to maiden form, but only if it is in the same square as at least one part of the body."},{name:"Bite",action:"Standard",keywords:["poison"],description:"Requirement: The penanggalan must be in head form. Attack: Melee 1 (one creature); +15 vs. AC Hit: 3d6 + 3 damage, and ongoing 5 poison damage (save ends)."},{name:"Grasping Entrails",action:"Standard",keywords:["disease","necrotic","poison"],recharge:"Recharge 3-6",description:"Requirement: The penanggalan must be in head form. Attack: Melee 2 (one or two creatures); +13 vs. Reflex Hit: 3d12 + 8 necrotic and poison damage, and the target is grabbed (escape DC 22). Until the grab ends, the target grants combat advantage. At the end of the encounter, the target makes a saving throw. On a failure, the target contracts blistering corruption (stage 1). Malleable Form ✦ At-Will Requirement: The penanggalan must be in head form. Effect: The penanggalan is phasing until the end of its next turn and shifts up to its speed. If it starts its next turn hidden from all enemies, grasping entrails recharges, and on that turn it can use that power and bite with a single standard action. Skills Bluff +17, Diplomacy +17, Religion +15, Stealth +16"}],alignment:"Evil",languages:["Common Equipment : dagger . Blistering Corruption Level 10 Disease Stage 0 : The target recovers from the disease. Stage 1 : While affected by this stage","the target takes a -2 penalty to Fortitude. Stage 2 : While affected by this stage","the target takes a -2 penalty to Fortitude. In addition","the target regains only half the normal number of hit points from spending a healing surge","and the target's hit point total cannot exceed its bloodied value. Stage 3 : While affected by this stage","the target suffers the effects of stage 2 and has an aura 2 (poison) that cannot be deactivated. Any creature that ends its turn in the aura loses a healing surge. Check : At the end of each extended rest","the target makes an Endurance check if it is at stage 1 or 2. 12 or lower : The stage of the disease increases by one. 13-17 : No Change 18 or higher : The stage of the disease decreases by one. Monster Vault: Threats to the Nentir Vale","page(s) 82."] },
  { id:"mvttnv-queen-msuga",name:"Queen Msuga",source:"mvttnv",level:10,role:"Soldier",roleModifier:"Elite",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:212,ac:26,fort:23,ref:21,will:22,initiative:8,perception:9,speed:"6 (8 while charging)",senses:["Low-light vision"],powers:[{name:"Greataxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 2d12 + 5 damage. Effect: Msuga marks the target until the end of her next turn."},{name:"Sweeping Blade",action:"Standard",keywords:["weapon"],recharge:"Recharge 4-6",description:"Attack: Close burst 1 (enemies in the burst); +15 vs. AC Hit: 3d12 + 5 damage, or 3d12 + 10 against a bloodied target, and Msuga marks the target until the end of her next turn."},{name:"Furious Onslaught",action:"Minor",description:"1/round Effect: One ally within 10 squares of Msuga can charge or make a basic attack as a free action."},{name:"Focused Riposte",action:"Triggered",description:"Trigger: An enemy that is marked by Msuga and within 5 squares of her makes an attack against one of her allies. Effect (Immediate Reaction): Msuga shifts up to 5 squares to a square adjacent to the triggering enemy and then uses greataxe against it. Queen's Demise ✦ Encounter Trigger: Msuga drops to 0 hit points. Effect (Free Action): Msuga or one ally within 10 squares of her takes a standard action as a free action. Skills Athletics +17, Insight +14, Intimidate +15"}],alignment:"Chaotic Evil",languages:["Common","Giant Equipment : greataxe","scale armor . Monster Vault: Threats to the Nentir Vale","page(s) 34."] },
  { id:"mvttnv-rohka-the-blood-witch",name:"Rohka the Blood Witch",source:"mvttnv",level:10,role:"Controller",roleModifier:"Elite",xp:1000,size:"Medium",origin:"Natural",type:"Humanoid",hp:216,ac:24,fort:22,ref:21,will:23,initiative:7,perception:11,speed:"6",senses:["Low-light vision"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 2d8 + 9 damage."},{name:"Baleful Eye of Gruumsh",action:"Standard",keywords:["charm","psychic"],recharge:"Recharge 4-6",description:"Attack: Ranged 5 (one or two creatures); +13 vs. Will Hit: 2d10 + 11 psychic damage. Effect: The target is slowed (save ends). First Failed Saving Throw: The target is immobilized instead of slowed (save ends). Second Failed Saving Throw: The target is dominated instead of immobilized (save ends)."},{name:"Chaos Displacement",action:"Standard",keywords:["psychic"],description:"Attack: Area burst 1 within 5 (enemies in the burst); +13 vs. Fortitude Hit: 2d10 + 7 psychic damage, and Rohka slides the target up to 3 squares."},{name:"Teleport",action:"Move",keywords:["teleportation"],recharge:"Encounter",description:"Effect: Rohka teleports up to 10 squares."},{name:"I Need a Volunteer",action:"Triggered",keywords:["teleportation"],recharge:"Encounter",description:"Trigger: An enemy makes a melee or a ranged attack against Rohka, and an ally of hers is adjacent to her. Effect (Immediate Interrupt): The ally and Rohka teleport, swapping positions. The triggering attack targets the ally instead."},{name:"Savage Demise",action:"Triggered",recharge:"Encounter",description:"Trigger: Rohka drops to 0 hit points. Effect (Free Action): Rohka takes a standard action. Skills Arcana +13, Bluff +16, Insight +11"}],alignment:"Chaotic Evil",languages:["Common","Giant","telepathy 10 Monster Vault: Threats to the Nentir Vale","page(s) 35."] },
  { id:"mvttnv-saruun-bat",name:"Saruun Bat",source:"mvttnv",level:10,role:"Skirmisher",roleModifier:"Minion",xp:125,size:"Tiny",origin:"Natural",type:"Beast",hp:1,ac:24,fort:22,ref:24,will:21,initiative:13,perception:5,speed:"2, fly 6 (hover)",senses:["Blindsight 5"],powers:[{name:"See the Unseen",action:"Aura",description:"Aura 1 Enemies cannot benefit from any concealment while in the aura."},{name:"Shrieking Dive",action:"Standard",keywords:["thunder"],description:"Effect: The bat flies up to its fly speed. At any point during its movement, it makes the following attack once. This movement does not provoke opportunity attacks. Attack: Melee 0 (one creature); +13 vs. Will Hit: 8 thunder damage, and the target takes a -2 penalty to attack rolls until the end of its next turn."},{name:"Shielding Familiar",action:"Triggered",recharge:"Encounter",description:"Trigger: An attack damages an ally in the bat's space or adjacent to it. Effect (Immediate Interrupt): The triggering attack deals only half damage to the ally, and the bat drops to 0 hit points."}],alignment:"Unaligned",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 78."] },
  { id:"mvttnv-saruun-underdark-adept",name:"Saruun Underdark Adept",source:"mvttnv",level:10,role:"Artillery",xp:500,size:"Medium",origin:"Natural",type:"Humanoid",hp:79,ac:24,fort:20,ref:24,will:22,initiative:8,perception:8,speed:"6",senses:["Darkvision"],powers:[{name:"Shadow Whip",action:"Standard",description:"Attack: Melee 2 (one creature); +13 vs. Reflex Hit: 2d4 + 5 damage. Effect: The adept slides the target 1 square."},{name:"Darkfire Bolt",action:"Standard",keywords:["fire","implement","necrotic"],description:"Attack: Ranged 15 (one creature); +15 vs. FortitudeThe attack can score a critical hit on a roll of 18-20. Hit: 2d10 + 2 fire and necrotic damage. If the adept scores a critical hit, the target is weakened (save ends)."},{name:"Corrupting Ray",action:"Standard",keywords:["implement","necrotic"],recharge:"Encounter",description:"Attack: Ranged 15 (one creature); +15 vs. Fortitude Hit: 4d8 + 9 necrotic damage, and the target is blinded (save ends). Miss: Half damage."},{name:"Force Shield",action:"Minor",recharge:"Recharge when an enemy damages the adept with a ranged or an area",description:"attack power Effect: The adept takes no damage from ranged or area attacks until the end of its next turn. Skills Arcana +15, Dungeoneering +13"}],alignment:"Unaligned",languages:["Common","Dwarven","Elven Equipment : wand implement . Monster Vault: Threats to the Nentir Vale","page(s) 78."] },
  { id:"mvttnv-warlord-delderosh",name:"Warlord Delderosh",source:"mvttnv",level:10,role:"Skirmisher",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:100,ac:24,fort:22,ref:23,will:22,initiative:11,perception:12,speed:"6",senses:["Low-light vision"],powers:[{name:"Ambush Leader At",action:"Trait",description:"the start of an encounter, any ally within 5 squares of Delderosh gains a +5 power bonus to its initiative check"},{name:"Combat Advantage Delderosh",action:"Trait",description:"deals 1d6 extra damage against any creature granting combat advantage to him"},{name:"Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 2d8 + 9 damage. Effect: Delderosh can shift 1 square."},{name:"Shortbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 15 (one creature); +15 vs. AC Hit: 2d6 + 5 damage."},{name:"Skewer",action:"Standard",keywords:["weapon"],recharge:"Recharge 4-6",description:"Attack: Melee 1 (one creature); +13 vs. Reflex Hit: 2d8 + 8 damage, and ongoing 10 damage (save ends). Effect: The target grants combat advantage until the end of its next turn."},{name:"Daggerburg Resilience",action:"Triggered",recharge:"Encounter",description:"Trigger: Delderosh or an ally within 5 squares of him is subjected to an effect that a save can end. Effect (Immediate Reaction): The creature subjected to the effect makes a saving throw against it. Skills Acrobatics +14, Bluff +14, Nature +12, Stealth +14"}],alignment:"Evil",languages:["Common","Goblin Equipment : arrow x20","chainmail","shortbow","spear . Monster Vault: Threats to the Nentir Vale","page(s) 39."] },
  { id:"mvttnv-dythan-s-legion-vanguard",name:"Dythan's Legion Vanguard",source:"mvttnv",level:11,role:"Soldier",xp:600,size:"Medium",origin:"Natural",type:"Humanoid",hp:111,ac:27,fort:25,ref:21,will:23,initiative:8,perception:9,speed:"6",powers:[{name:"Phalanx Formation",action:"Trait",description:"The vanguard gains a +1 power bonus to AC for each ally adjacent to it, up to a maximum power bonus of +4"},{name:"Longsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +16 vs. AC. The vanguard has a +2 bonus to hit while bloodied. Hit: 2d8 + 10 damage, and the target is marked until the end of the vanguard's next turn."},{name:"Shield Bash",action:"Minor",keywords:["weapon"],description:"1/round Attack: Melee 1 (one creature marked by the vanguard); +16 vs. AC. The vanguard has a +2 bonus to hit while bloodied. Hit: The target is dazed until the end of the vanguard's next turn. Vanguard's Mark ✦ Recharge when first bloodied Effect: Close burst 5 (one enemy in the burst). The target is marked until the end of the vanguard's next turn. If the target doesn't end its next turn adjacent to the vanguard, the vanguard can immediately charge the target as a free action and doesn't provoke opportunity attacks for the charge's movement."},{name:"Dragon Breath",action:"Minor",keywords:["poison"],recharge:"Encounter",description:"Attack: Close blast 3 (creatures in the blast); +14 vs. Reflex. The vanguard has a +2 bonus to hit while bloodied. Hit: 1d6 + 6 poison damage."}],alignment:"Evil",languages:["Common","Draconic Equipment : heavy shield","longsword","plate armor . Monster Vault: Threats to the Nentir Vale","page(s) 45","Dungeon Magazine 202."] },
  { id:"mvttnv-vampiric-mist-corruptor",name:"Vampiric Mist Corruptor",source:"mvttnv",level:11,role:"Controller",xp:600,size:"Medium",origin:"Shadow",type:"Animate",keywords:["undead"],hp:100,ac:25,fort:24,ref:23,will:23,initiative:9,perception:9,speed:"0, fly 5 (altitude limit 2)",senses:["Darkvision"],resist:["10 necrotic,","10 poison"],immune:["disease"],vulnerable:["5 radiant"],powers:[{name:"Siphoning Presence",action:"Aura",keywords:["necrotic","psychic"],description:"Aura 1 Enemies can't spend healing surges in the aura"},{name:"When",action:"Trait",description:"an enemy ends its turn in the aura, it takes 10 necrotic and psychic damage, and the mist gains 5 temporary hit points"},{name:"Insubstantial",action:"Trait",description:"The mist takes half damage from any damage source, except those that deal fire, force, or radiant damage"},{name:"When",action:"Trait",description:"it takes fire or radiant damage, it loses this trait until the start of its next turn"},{name:"Mist Form",action:"Trait",description:"The mist can move through openings of any size"},{name:"It",action:"Trait",description:"can also enter other creatures' spaces and end its turn there"},{name:"Bite",action:"Standard",keywords:["necrotic"],description:"Attack: Melee 1 (one creature); +14 vs. Fortitude Hit: 3d6 + 9 necrotic damage, and the mist slides the target up to 2 squares."},{name:"Corrupting Gaze",action:"Standard",keywords:["charm","gaze","psychic","necrotic"],recharge:"Recharge when no creature is dominated by this power",description:"Attack: Ranged 10 (one creature); +14 vs. Will Hit: The target is dominated (save ends). Aftereffect: The target takes 2d8 + 10 necrotic and psychic damage."},{name:"Deathly Howl",action:"Triggered",recharge:"Encounter",description:"Trigger: The mist is first bloodied. Attack (Free Action): Close burst 5 (enemies in the burst); +14 vs. Fortitude Hit: The mist pushes the target up to 3 squares, and the target can't spend healing surges (save ends)."}],alignment:"Evil",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 110","Dungeon Magazine 196."] },
  { id:"mvttnv-winterbole-sapling",name:"Winterbole Sapling",source:"mvttnv",level:11,role:"Soldier",roleModifier:"Minion",xp:150,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:27,fort:24,ref:21,will:23,initiative:9,perception:9,speed:"6 (forest walk, ice walk)",senses:["Low-light vision"],resist:["10 cold"],powers:[{name:"Numbing Branches",action:"Aura",keywords:["cold"],description:"Aura 1 Whenever an immobilized enemy starts its turn in the aura, the enemy takes 3 cold damage."},{name:"Slam",action:"Standard",description:"Attack: Melee 1 (one creature); +16 vs. AC Hit: 8 damage, and the target is immobilized until the end of its next turn."}],alignment:"Unaligned",languages:["Elven Monster Vault: Threats to the Nentir Vale","page(s) 105."] },
  { id:"mvttnv-dythan-s-legion-dragoon",name:"Dythan's Legion Dragoon",source:"mvttnv",level:12,role:"Controller",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:119,ac:26,fort:25,ref:24,will:24,initiative:8,perception:8,speed:"6",powers:[{name:"Masterful Rider Whenever",action:"Trait",description:"the dragoon is mounted and subjected to a pull, push, or slide, it can move 1 square fewer than the effect specifies"},{name:"Lance",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +17 vs. AC. The dragoon has a +2 bonus to hit while bloodied. Hit: 2d12 + 7 damage. If the dragoon is mounted, the target also falls prone."},{name:"Battlefield Mastery",action:"Minor",recharge:"Recharge 3-6",description:"Effect: Close burst 2 (allies in the burst). Each target can shift 1 square as a free action."},{name:"Dragon Breath",action:"Minor",keywords:["acid"],recharge:"Encounter",description:"Attack: Close blast 3 (creatures in the blast); +15 vs. Reflex. The dragoon has a +2 bonus to hit while bloodied. Hit: 1d6 + 6 acid damage."},{name:"Incensed Mount",action:"Triggered",description:"Trigger: An enemy's attack damages the dragoon while the dragoon is mounted. Effect (Immediate Reaction): Melee 1 (the dragoon's mount). The target can make a basic attack against the triggering enemy as a free action."}],alignment:"Evil",languages:["Common","Draconic Equipment : lance","leather armor . Monster Vault: Threats to the Nentir Vale","page(s) 47."] },
  { id:"mvttnv-frost-witch-harpy",name:"Frost Witch Harpy",source:"mvttnv",level:12,role:"Controller",xp:700,size:"Medium",origin:"Fey",type:"Humanoid",hp:123,ac:26,fort:23,ref:23,will:25,initiative:9,perception:13,speed:"6 (ice walk), fly 8 (clumsy)",resist:["10 cold,","10 thunder"],vulnerable:["5 fire"],powers:[{name:"Frost Aura",action:"Aura",description:"Aura 2 Enemies have vulnerable 5 cold while in the aura."},{name:"Frost Claw",action:"Standard",keywords:["cold"],description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 3d8 + 4 cold damage."},{name:"Icy Stare",action:"Standard",keywords:["cold"],description:"Attack: Ranged 5 (one or two creatures); +15 vs. Will Hit: 3d6 + 2 cold damage, and the target is slowed until the end of the harpy's next turn."},{name:"Chilling Screech",action:"Standard",keywords:["cold","thunder"],recharge:"Encounter",description:"Attack: Close burst 2 (creatures in the burst); +15 vs. Fortitude Hit: 4d8 + 2 cold and thunder damage. If the target is slowed or immobilized, it takes ongoing 10 cold damage (save ends). Skills Arcana +15, Bluff +17, Diplomacy +17, Nature +13"}],alignment:"Evil",languages:["Common","Elven","Primordial Monster Vault: Threats to the Nentir Vale","page(s) 56","Dungeon Magazine 196."] },
  { id:"mvttnv-mage-of-saruun",name:"Mage of Saruun",source:"mvttnv",level:12,role:"Controller",xp:700,size:"Medium",origin:"Natural",type:"Humanoid",hp:116,ac:26,fort:22,ref:27,will:24,initiative:8,perception:9,speed:"6",powers:[{name:"Quarterstaff",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 2d8 + 3 damage. Effect: The mage can slide the target 1 square."},{name:"Empowered Magic Missile",action:"Standard",keywords:["force","implement"],description:"Effect: Ranged 10 (one creature). The target takes 10 force damage, and the mage pushes the target up to 2 squares."},{name:"Noxious Shroud",action:"Standard",keywords:["implement","poison","zone"],description:"Attack: Close blast 3 (creatures in the blast); +15 vs. Fortitude Hit: 3d6 + 6 poison damage. Effect: The blast creates a zone that lasts until the end of the mage's next turn. Any creature that ends its turn in the zone is slowed and takes ongoing 5 poison damage (save ends both)."},{name:"Cloying Flames",action:"Standard",keywords:["fire","implement"],recharge:"Recharge when first bloodied",description:"Attack: Area burst 2 within 10 (creatures in the burst); +15 vs. Reflex Hit: 3d10 + 9 fire damage, and the target is immobilized and takes ongoing 5 fire damage (save ends both). Miss: Half damage. Skills Arcana +17"}],alignment:"Unaligned",languages:["Common","Elven","Dwarven Equipment : quarterstaff . Monster Vault: Threats to the Nentir Vale","page(s) 77."] },
  { id:"mvttnv-mooncalf-sire",name:"Mooncalf Sire",source:"mvttnv",level:12,role:"Controller",roleModifier:"Elite",xp:1400,size:"Huge",origin:"Aberrant",type:"Magical beast",hp:262,ac:26,fort:26,ref:23,will:25,initiative:9,perception:15,speed:"6, fly 8",senses:["Darkvision"],resist:["10 lightning,","10 thunder"],powers:[{name:"Tentacle Snare",action:"Trait",description:"When the mooncalf moves, all creatures grabbed by it are pulled with it"},{name:"Tentacle Rake",action:"Standard",description:"Attack: Melee 6 (one creature not grabbed by the mooncalf); +17 vs. AC Hit: 2d12 + 7 damage."},{name:"Tentacle Grab",action:"Standard",description:"Attack: Melee 6 (one Huge or smaller creature not grabbed by the mooncalf); +15 vs. Reflex Hit: 1d12 + 4 damage, the mooncalf pulls the target up to 5 squares, and the target is grabbed (escape DC 20). The target takes ongoing 10 damage until the grab ends. Special: The mooncalf can grab up to two creatures at once. It can release a grabbed creature as a free action."},{name:"Vile Bite",action:"Standard",description:"Attack: Melee 1 (one creature grabbed by the mooncalf); +17 vs. AC Hit: 2d10 + 9 damage, and the target cannot spend healing surges until the start of the mooncalf's next turn. Double Attack ✦ At-Will Effect: The mooncalf makes two melee attacks, each against a different target."},{name:"Call Lightning",action:"Standard",keywords:["lightning"],recharge:"Encounter",description:"Attack: Close blast 5 (enemies in the blast); +15 vs. Reflex Hit: 3d8 + 9 lightning damage, and the target is slowed until the end of the mooncalf's next turn."},{name:"Lure",action:"Minor",keywords:["charm"],description:"1/round Attack: Close burst 10 (one creature in the burst); +15 vs. Will Hit: The mooncalf pulls the target up to 5 squares."},{name:"Fury of the Storm",action:"Triggered",keywords:["aura","lightning","thunder"],recharge:"Encounter",description:"Trigger: The mooncalf is bloodied. Effect (Immediate Reaction): The mooncalf activates an aura 1 that lasts until the end of the encounter. Any creature that ends its turn in the aura takes 10 lightning and thunder damage. Skills Stealth +14"}],alignment:"Evil",languages:["understands Deep Speech","telepathy 20 Monster Vault: Threats to the Nentir Vale","page(s) 81."] },
  { id:"mvttnv-phantom-brigade-templar",name:"Phantom Brigade Templar",source:"mvttnv",level:12,role:"Controller",xp:700,size:"Medium",origin:"Natural",type:"Humanoid",hp:85,ac:26,fort:23,ref:22,will:25,initiative:8,perception:12,speed:"6; phasing",senses:["Darkvision"],powers:[{name:"Insubstantial",action:"Trait",description:"The templar takes only half damage from any damage source, except force damage"},{name:"Unrelenting Brigade Whenever",action:"Trait",description:"an ally who also has this trait drops to 0 hit points within 5 squares of the templar, the templar gains a +2 power bonus to attack rolls until the end of its next turn"},{name:"Soulbound Morningstar",action:"Standard",keywords:["psychic","weapon"],description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 2d8 + 11 psychic damage, and the templar slides the target up to 2 squares."},{name:"Righteous Strike",action:"Standard",keywords:["cold","radiant"],description:"Attack: Ranged 5 (one or two creatures); +15 vs. Fortitude Hit: 3d6 + 5 cold and radiant damage, and the target is slowed (save ends)."},{name:"Frightful Majesty",action:"Standard",keywords:["fear"],recharge:"Recharge when first bloodied",description:"Attack: Close burst 1 (enemies in the burst); +15 vs. Will Hit: The target is dazed until the end of the templar's next turn. Effect: The templar can push each target 1 square. Skills Religion +14"}],alignment:"Lawful Good",languages:["Common Monster Vault: Threats to the Nentir Vale","page(s) 88."] },
  { id:"mvttnv-vincent-gravelstoke",name:"Vincent Gravelstoke",source:"mvttnv",level:12,role:"Lurker",xp:700,size:"Medium",origin:"Natural",type:"Humanoid",hp:90,ac:26,fort:21,ref:25,will:23,initiative:16,perception:12,speed:"6",senses:["Darkvision"],powers:[{name:"Stone Cold Slayer",action:"Trait",description:"Any creature killed by Vincent is petrified"},{name:"As",action:"Trait",description:"long as the creature remains petrified, it cannot be raised from the dead"},{name:"Vincent",action:"Trait",description:"can end the effect by touching the petrified creature"},{name:"The",action:"Trait",description:"effect can also be ended by spilling one or more drops of Vincent's blood on the petrified creature"},{name:"Poisoned Rapier",action:"Standard",keywords:["necrotic","poison","weapon"],description:"Attack: Melee 1 (one creature); +15 vs. Fortitude Hit: 2d6 + 8 necrotic and poison damage. If the target is granting combat advantage to Vincent, it also takes ongoing 10 damage (save ends)."},{name:"Shadow Strike",action:"Standard",keywords:["weapon"],recharge:"Recharge when Vincent is first bloodied",description:"Effect: Vincent is removed from play. At the start of his next turn, he reappears in a square within 10 squares of his previous location and can make the following attack as a standard action. Attack: Melee 1 (one creature); +17 vs. AC Hit: 4d8 + 12 damage, and the target cannot spend healing surges (save ends). Miss: Half damage."},{name:"Fade into the Shadows",action:"Minor",keywords:["illusion"],recharge:"Encounter",description:"Effect: Vincent becomes insubstantial and gains partial concealment until the start of his next turn. The effect ends immediately if Vincent attacks or takes radiant damage. While insubstantial, he takes half damage from all attacks except those that deal force damage."},{name:"Parry",action:"Triggered",description:"Trigger: An enemy hits Vincent with a melee attack. Effect (Immediate Interrupt): Vincent gains a +4 power bonus to all defenses against the triggering attack. Skills Stealth +17"}],alignment:"Evil",languages:["Common","Elven Equipment : leather armor","rapier . Monster Vault: Threats to the Nentir Vale","page(s) 58."] },
  { id:"mvttnv-winterbole-rimeneedle",name:"Winterbole Rimeneedle",source:"mvttnv",level:12,role:"Skirmisher",xp:700,size:"Large",origin:"Natural",type:"Humanoid",hp:122,ac:26,fort:24,ref:23,will:24,initiative:10,perception:10,speed:"8 (forest walk, ice walk)",senses:["Low-light vision"],resist:["10 cold"],powers:[{name:"Wooden Body Whenever",action:"Trait",description:"the rimeneedle takes fire damage, it also takes ongoing 5 fire damage (save ends)"},{name:"Slam",action:"Standard",description:"Attack: Melee 2 (one creature); +17 vs. AC Hit: 2d12 + 7 damage."},{name:"Tree Stomp",action:"Standard",description:"Effect: The rimeneedle shifts up to its speed and can move through enemies' spaces during this movement. At any point during that movement, it uses slam once. If the attack hits, the target also falls prone."},{name:"Winter's Step",action:"Move",keywords:["cold","teleportation"],recharge:"Encounter",description:"Effect: Before the attack, the rimeneedle can teleport up to 5 squares. Attack: Close burst 2 (enemies in the burst); +15 vs. Fortitude Hit: 2d10 + 9 cold damage. Miss: Half damage. Skills Nature +15, Stealth +13"}],alignment:"Unaligned",languages:["Elven Monster Vault: Threats to the Nentir Vale","page(s) 105."] },
  { id:"mvttnv-arkhosian-siege-tower",name:"Arkhosian Siege Tower",source:"mvttnv",level:13,role:"Brute",roleModifier:"Elite",xp:1600,size:"Huge",origin:"Natural",type:"Animate",keywords:["construct"],hp:336,ac:25,fort:28,ref:25,will:22,initiative:11,perception:7,speed:"4 All-around vision",resist:["15 to all damage from outside the tower"],immune:["charm, disease, poison"],powers:[{name:"All-Around Vision",action:"Trait",description:"Enemies can't gain combat advantage by flanking the siege tower"},{name:"Juggernaut",action:"Trait",description:"The siege tower ignores difficult terrain and does not provoke opportunity attacks"},{name:"It",action:"Trait",description:"cannot squeeze, make opportunity attacks, or grab creatures"},{name:"Living Building",action:"Trait",description:"The tower can end its movement in other creatures' spaces, and other creatures can end their movements in its space"},{name:"The",action:"Trait",description:"tower is 30 feet high (Athletics DC 20 to climb it)"},{name:"It",action:"Trait",description:"has two levels, each with a 15-foot-high ceiling"},{name:"The",action:"Trait",description:"lower level has two reinforced iron doors (break DC 25), which the tower can open or close as a minor action"},{name:"While",action:"Trait",description:"the doors are closed, line of effect and line of sight cannot be traced from outside the tower to creatures on the lower level"},{name:"The",action:"Trait",description:"upper level has arrow slits and can be reached by either of two ladders from the lower level"},{name:"Creatures",action:"Trait",description:"inside the tower or on its exterior move with it as if it were a vehicle"},{name:"Rough Ride",action:"Trait",description:"While the tower is bloodied, it is slowed, and creatures inside it take a -2 penalty to attack rolls"},{name:"Dragon's Head",action:"Standard",keywords:["fire"],description:"Attack: Area burst 1 within 20 (creatures in the burst outside the tower); +16 vs. Reflex Hit: 1d12 + 7 fire damage, and ongoing 10 fire damage (save ends). Miss: Half damage."},{name:"Crush",action:"Move",description:"1/round Effect: The siege tower moves up to its speed and can enter enemies' spaces during this movement. When the tower enters a nonflying creature's space for the first time during this movement, the tower makes the following attack against that creature. Attack: Melee 0 (creature in the square); +16 vs. Reflex Hit: 3d12 + 6 damage. The creature falls prone. Miss: The creature falls prone."},{name:"Collapse",action:"Triggered",recharge:"Encounter",description:"Trigger: The tower drops to 0 hit points. Effect (No Action): The tower is destroyed. Its space becomes difficult terrain until the end of the encounter. Creatures inside the tower fall prone in the tower's space, and the tower makes the following attack. Attack: Close burst 1 (creatures in the burst); +16 vs. Reflex Hit: 4d10 + 17 damage, and the target falls prone. Miss: Half damage."}],alignment:"Unaligned",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 46."] },
  { id:"mvttnv-mikus-gravelstoke",name:"Mikus Gravelstoke",source:"mvttnv",level:13,role:"Soldier",xp:800,size:"Medium",origin:"Natural",type:"Humanoid",hp:128,ac:29,fort:27,ref:23,will:25,initiative:11,perception:9,speed:"6",senses:["Darkvision"],powers:[{name:"Gloaming Shroud",action:"Aura",description:"Aura 1 Any enemy that starts its turn in the aura is slowed until the end of its next turn"},{name:"Stone Cold Slayer",action:"Trait",description:"Any creature slain by Mikus is petrified"},{name:"As",action:"Trait",description:"long as the creature remains petrified, it cannot be raised from the dead"},{name:"Mikus",action:"Trait",description:"can end the effect by touching the petrified creature"},{name:"The",action:"Trait",description:"effect can also be ended by spilling one or more drops of Mikus's blood on the petrified creature"},{name:"Greatsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 2d10 + 10 damage. Effect: The target is marked until the end of Mikus's next turn."},{name:"Incite the Blood",action:"Standard",keywords:["charm","weapon"],recharge:"Recharge when first bloodied",description:"Effect: Close burst 3 (enemies in the burst). Mikus pulls the target up to 2 squares to a square adjacent to him. He then makes the following attack against each enemy adjacent to him. Attack: Melee 1 (one adjacent enemy); +18 vs. AC Hit: 2d10 + 12 damage."},{name:"Shadow's Curse",action:"Triggered",keywords:["necrotic"],description:"Trigger: An enemy marked by Mikus and within 5 squares of him makes an attack that doesn't include him as a target. Effect (Immediate Reaction): Close burst 5 (triggering enemy in the burst). The target takes 10 necrotic damage. This damage ignores resistances and immunities. Skills Athletics +16, Intimidate +15"}],alignment:"Evil",languages:["Common Equipment : greatsword","leather armor . Monster Vault: Threats to the Nentir Vale","page(s) 59."] },
  { id:"mvttnv-tovin-gravelstoke",name:"Tovin Gravelstoke",source:"mvttnv",level:13,role:"Artillery",xp:800,size:"Medium",origin:"Natural",type:"Humanoid",hp:96,ac:27,fort:25,ref:26,will:23,initiative:11,perception:9,speed:"6",senses:["Darkvision"],powers:[{name:"Stone Cold Slayer",action:"Trait",description:"Any creature slain by Tovin is petrified"},{name:"As",action:"Trait",description:"long as the creature remains petrified, it cannot be raised from the dead"},{name:"Tovin",action:"Trait",description:"can end the effect by touching the petrified creature"},{name:"The",action:"Trait",description:"effect can also be ended by spilling one or more drops of Tovin's blood on the petrified creature"},{name:"Dagger of Death",action:"Standard",keywords:["necrotic","weapon"],description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 3d6 + 10 necrotic damage."},{name:"Crossbow of Dread",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 20 (one creature); +20 vs. AC Hit: 2d8 + 12 damage, and Tovin gains a +4 power bonus to damage rolls against the target until the end of his next turn."},{name:"Poisoned Shot",action:"Standard",keywords:["necrotic","poison","weapon"],recharge:"Recharge 4-6",description:"Attack: Ranged 20 (one creature); +20 vs. AC Hit: 2d8 + 12 damage, and ongoing 10 necrotic and poison damage (save ends). First Failed Saving Throw: The target is immobilized and takes ongoing 10 necrotic and poison damage (save ends both). Second Failed Saving Throw: The power's other effects end, and the target falls unconscious (save ends)."},{name:"Shadow Escape",action:"Triggered",keywords:["necrotic","teleportation"],recharge:"Encounter",description:"Trigger: An adjacent enemy attacks Tovin with a melee attack. Effect (Immediate Interrupt): Melee 1 (triggering enemy). The target takes 5 necrotic damage, and Tovin teleports up to 5 squares. Skills Acrobatics +16, Athletics +15, Bluff +13, Insight +14, Stealth +16"}],alignment:"Evil",languages:["Common","Draconic","Elven Equipment : crossbow","crossbow bolt x20","dagger","leather armor . Monster Vault: Threats to the Nentir Vale","page(s) 58."] },
  { id:"mvttnv-vestapalk",name:"Vestapalk",source:"mvttnv",level:13,role:"Skirmisher",roleModifier:"Solo",xp:4000,size:"Large",origin:"Natural",type:"Magical beast",keywords:["dragon"],hp:524,ac:27,fort:25,ref:26,will:23,initiative:14,perception:13,speed:"10 (forest walk), fly 14",senses:["Darkvision"],resist:["15 poison"],powers:[{name:"Poisonous Wounds",action:"Aura",keywords:["poison"],description:"Aura 1 While Vestapalk is bloodied, any enemy that ends its turn in the aura takes 10 poison damage"},{name:"Action Recovery Whenever Vestapalk",action:"Trait",description:"ends his turn, any dazing, stunning, or dominating effect on him ends"},{name:"Instinctive Flyby Vestapalk",action:"Trait",description:"can use a free action to fly up to his speed on an initiative of 10 + his initiative check. During the movement, Vestapalk gains a +4 bonus to all defenses against opportunity attacks and can use bite or claw once at any point during the move"},{name:"If Vestapalk",action:"Trait",description:"cannot use a free action to make this attack due to a dominating or stunning effect, then that effect ends instead of Vestapalk making the attack"},{name:"Bite",action:"Standard",keywords:["poison"],description:"Attack: Melee 2 (one creature); +18 vs. AC Hit: 2d10 + 5 damage, and ongoing 5 poison damage (save ends). Miss: Half damage."},{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one or two creatures); +18 vs. ACIf Vestapalk targets only one creature, he can make this attack against it twice. Hit: 3d10 + 5 damage, and Vestapalk can shift up to 2 squares."},{name:"Breath Weapon",action:"Standard",keywords:["poison"],recharge:"Recharge 4-6",description:"Attack: Close blast 5 (creatures in the blast); +16 vs. Fortitude Hit: 2d10 + 5 poison damage, and the target is slowed and takes ongoing 10 poison damage (save ends both). Miss: Half damage, and ongoing 5 poison damage (save ends)."},{name:"Share the Mad Visions",action:"Standard",keywords:["psychic"],recharge:"Recharge when first bloodied",description:"Attack: Close burst 2 (creatures in the burst); +16 vs. Will Hit: 3d12 + 5 psychic damage, and Vestapalk pushes the target up to a number of squares equal to the target's speed. Miss: Half damage. Effect: Vestapalk can shift up to his speed."},{name:"Luring Glare",action:"Minor",keywords:["charm"],description:"Attack: Close blast 10 (one creature in the blast); +16 vs. Will Hit: Vestapalk slides the target up to 3 squares."},{name:"Tail Sweep",action:"Triggered",description:"Trigger: An enemy adjacent to Vestapalk ends its turn without moving. Attack (Immediate Reaction): Melee 1 (the triggering enemy); +16 vs. Reflex Hit: 3d8 + 7 damage, and the target falls prone. Bloodied Breath ✦ Encounter Trigger: Vestapalk is first bloodied. Effect (Free Action): Breath weapon recharges, and Vestapalk uses it. Skills Bluff +14, Insight +13, Stealth +17"}],alignment:"Evil",languages:["Common","Draconic Monster Vault: Threats to the Nentir Vale","page(s) 112."] },
  { id:"mvttnv-alesia-gravelstoke",name:"Alesia Gravelstoke",source:"mvttnv",level:14,role:"Controller",xp:1000,size:"Medium",origin:"Natural",type:"Humanoid",hp:140,ac:28,fort:26,ref:25,will:27,initiative:11,perception:13,speed:"6",senses:["Darkvision"],powers:[{name:"Stone Cold Slayer",action:"Trait",description:"Any creature slain by Alesia is petrified"},{name:"As",action:"Trait",description:"long as the creature remains petrified, it cannot be raised from the dead"},{name:"Alesia",action:"Trait",description:"can end the effect by touching the petrified creature"},{name:"The",action:"Trait",description:"effect can also be ended by spilling one or more drops of Alesia's blood on the petrified creature"},{name:"Bewildering Chakram",action:"Standard",keywords:["psychic","weapon"],description:"Attack: Melee 1 (one creature); +19 vs. AC Hit: 3d6 + 12 damage. Effect: If the target moves on its next turn, during the move it takes 5 psychic damage for each square of movement."},{name:"Bewildering Chakram",action:"Standard",keywords:["psychic","weapon"],description:"Attack: Ranged 5 (one creature); +19 vs. AC Hit: 3d6 + 12 damage. Effect: If the target moves on its next turn, during the move it takes 5 psychic damage for each square of movement. In addition, if Alesia uses this power as a ranged attack, her chakram returns to her hand."},{name:"Toxic Tendrils",action:"Standard",keywords:["necrotic","poison"],recharge:"Recharge 4-6",description:"Attack: Area burst 2 within 10 (enemies in the burst); +17 vs. Reflex Hit: 3d6 + 6 necrotic and poison damage, and the target is slowed (save ends)."},{name:"Reeling Chakram",action:"Standard",keywords:["weapon"],recharge:"Recharge when first bloodied",description:"Attack: Melee 1 (one creature); +19 vs. AC Hit: 6d6 + 12 damage. Miss: Half damage. Effect: Alesia slides the target up to 2 squares and knocks it prone."},{name:"Reeling Chakram",action:"Standard",keywords:["weapon"],recharge:"Recharge when first bloodied",description:"Attack: Ranged 5 (one creature); +19 vs. AC Hit: 6d6 + 12 damage. Miss: Half damage. Effect: Alesia slides the target up to 2 squares and knocks it prone. In addition, if Alesia uses this power as a ranged attack, her chakram returns to her hand. Skills Acrobatics +15, Bluff +17, Stealth +16, Streetwise +17"}],alignment:"Evil",languages:["Common","Draconic","Elven Equipment : chakram","cloth armor (basic clothing) . Monster Vault: Threats to the Nentir Vale","page(s) 59."] },
  { id:"mvttnv-blood-raven-swarm",name:"Blood Raven Swarm",source:"mvttnv",level:14,role:"Skirmisher",xp:1000,size:"Large",origin:"Natural",type:"Beast",keywords:["swarm"],hp:138,ac:28,fort:26,ref:26,will:26,initiative:15,perception:12,speed:"3, fly 8 (hover)",senses:["Low-light vision"],powers:[{name:"Swarm Attack",action:"Aura",description:"Aura 1 Any enemy that ends its turn in the aura takes 10 damage"},{name:"Carrion Vigor",action:"Trait",description:"When the swarm starts its turn in the space of a bloodied creature, the swarm can take move actions as minor actions until the end of that turn"},{name:"Swarm",action:"Trait",description:"The swarm can occupy the same space as another creature, and an enemy can enter its space, which is difficult terrain"},{name:"The",action:"Trait",description:"swarm cannot be pulled, pushed, or slid by melee or ranged attacks"},{name:"It",action:"Trait",description:"can squeeze through any opening that is large enough for a Tiny creature"},{name:"Blood Beaks",action:"Standard",description:"Attack: Close burst 1 (enemies in the burst); +19 vs. AC Hit: 3d8 + 4 damage. If the target is bloodied, it is weakened until the end of its next turn."}],alignment:"Unaligned",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 116."] },
  { id:"mvttnv-calastryx",name:"Calastryx",source:"mvttnv",level:14,role:"Brute",roleModifier:"Solo",xp:5000,size:"Huge",origin:"Natural",type:"Magical beast",keywords:["dragon"],hp:684,ac:26,fort:27,ref:25,will:27,initiative:0,perception:19,speed:"6, fly 8",senses:["Darkvision"],resist:["10 fire"],powers:[{name:"Action Recovery Whenever Calastryx",action:"Trait",description:"ends any of her turns, any marking, dazing, stunning, or dominating effect on her ends"},{name:"Multiple Heads Calastryx",action:"Trait",description:"gets a full turn at initiative counts 30, 20, and 10"},{name:"She",action:"Trait",description:"cannot delay or ready actions"},{name:"If",action:"Trait",description:"she is granted immediate actions, she can take no more than one after each of her turns"},{name:"Power",action:"Trait",description:"of Three Each of Calastryx's heads has its own breath weapon and rip and tear, and it tracks its usage of those powers separately"},{name:"Bite",action:"Standard",description:"Attack: Melee 3 (one creature); +19 vs. AC Hit: 3d12 + 8 damage, and Calastryx slides the target up to 3 squares."},{name:"Inferno Shot",action:"Standard",keywords:["fire"],description:"Attack: Ranged 10 (one creature); +17 vs. Reflex Hit: 3d10 + 6 fire damage."},{name:"Breath Weapon",action:"Standard",keywords:["fire","zone"],recharge:"Recharge 5-6",description:"Attack: Close blast 5 (creatures in the blast); +17 vs. Reflex Hit: 2d12 + 7 fire damage. Miss: Half damage. Effect: The blast creates a zone that lasts until the end of Calastryx's next turn. Any creature that ends its turn in one or more zones created by this power takes 10 fire damage."},{name:"Rip and Tear",action:"Standard",recharge:"Encounter",description:"Attack: Melee 3 (one, two, or three creatures); +19 vs. AC Hit: 2d12 + 11 damage."},{name:"Bloodied Birth",action:"Triggered",recharge:"Encounter",description:"Trigger: Calastryx is first bloodied. Effect (No Action): Calastryx sprouts a fourth head, which acts on initiative count 40. Skills Arcana +17, Diplomacy +17, History +17, Insight +19, Intimidate +17"}],alignment:"Evil",languages:["Common","Draconic","Giant","Goblin Monster Vault: Threats to the Nentir Vale","page(s) 33."] },
  { id:"mvttnv-phantom-brigade-knight-commander",name:"Phantom Brigade Knight-Commander",source:"mvttnv",level:14,role:"Soldier",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:96,ac:30,fort:27,ref:24,will:26,initiative:12,perception:17,speed:"6; phasing",senses:["Darkvision"],immune:["disease, poison"],powers:[{name:"Insubstantial",action:"Trait",description:"The knight-commander takes only half damage from any damage source, except force damage"},{name:"Unrelenting Brigade Whenever",action:"Trait",description:"an ally who also has this trait drops to 0 hit points within 5 squares of the knight-commander, the knight-commander gains a +2 power bonus to attack rolls until the end of its next turn"},{name:"Keening Soulbound Backsword",action:"Standard",keywords:["psychic","thunder","weapon"],description:"Attack: Melee 1 (one creature); +19 vs. AC Hit: 3d6 + 12 psychic and thunder damage. Effect: The target is marked until the end of the knight-commander's next turn."},{name:"Soul Strike",action:"Standard",keywords:["psychic","weapon"],recharge:"Recharge 4-6",description:"Attack: Melee 1 (one creature); +19 vs. AC Hit: 4d8 + 15 psychic damage, and the knight-commander gains 10 temporary hit points."},{name:"Oath of Nerath",action:"Standard",keywords:["psychic"],description:"Attack: Close burst 1 (enemies in the burst); +17 vs. Fortitude Hit: 2d10 + 6 psychic damage."},{name:"Call to Arms",action:"Triggered",description:"Trigger: An enemy marked by the knight-commander and within 2 squares of it uses an attack power that doesn't include it as a target. Effect (Immediate Reaction): Close burst 5 (one ally in the burst). The target can take a free action to shift up to 3 squares and make a melee basic attack against the triggering enemy."}],alignment:"Lawful Good",languages:["Common Monster Vault: Threats to the Nentir Vale","page(s) 86."] },
  { id:"mvttnv-warped-mage-of-saruun",name:"Warped Mage of Saruun",source:"mvttnv",level:14,role:"Brute",roleModifier:"Elite",xp:2000,size:"Medium",origin:"Natural",type:"Humanoid",hp:346,ac:26,fort:26,ref:25,will:24,initiative:10,perception:10,speed:"6, climb 4",senses:["Blindsight 10"],resist:["10 psychic"],powers:[{name:"Shadow Tentacle",action:"Standard",description:"Attack: Melee 3 (one creature); +17 vs. Reflex Hit: 4d10 + 6 damage, and the target is grabbed (escape DC 21). Whenever a creature attempts to escape the grab and fails, that creature takes 10 damage."},{name:"Tentacle Lash",action:"Standard",description:"Attack: Close blast 3 (enemies in the blast); +17 vs. Reflex Hit: 3d10 + 6 damage, and the target falls prone."},{name:"Psychic Burst",action:"Standard",keywords:["psychic"],recharge:"Encounter",description:"Attack: Close burst 2 (enemies in the burst); +17 vs. Will Hit: 2d12 + 3 psychic damage, and the target is dazed (save ends). Miss: Half damage."},{name:"Arcane Release",action:"Triggered",keywords:["cold","fire","lightning","thunder"],recharge:"Encounter",description:"Trigger: The mage is stunned or drops to 0 hit points. Attack (No Action): Close burst 2 (creatures in the burst); +17 vs. Fortitude Hit: 2d10 + 12 cold, fire, lightning, and thunder damage. Miss: Half damage. Skills Arcana +17, Dungeoneering +15"}],alignment:"Evil",languages:["Common","Deep Speech","Dwarven Monster Vault: Threats to the Nentir Vale","page(s) 78."] },
  { id:"mvttnv-wood-woad-druid",name:"Wood Woad Druid",source:"mvttnv",level:14,role:"Skirmisher",xp:0,size:"Medium",origin:"Fey",type:"Humanoid",keywords:["plant"],hp:145,ac:28,fort:27,ref:25,will:25,initiative:14,perception:17,speed:"5",immune:["immobilized, restrained, slowed"],vulnerable:["15 fire. Move Actions Earthen Stride ✦ At-Will Effect: The druid and one ally adjacent to it can each shift up to","2 squares. Minor Actions Nature's Boon ✦ Encounter Effect: Close burst","5 (one plant ally in the burst). The target gains","25 temporary hit points. Skills Endurance +19, Heal +17, Nature +17"],powers:[{name:"Cudgel",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +19 vs. AC Hit: 3d6 + 11 damage."},{name:"Darting Strike (weapon)",action:"Standard",description:"Darting Strike (weapon) �� At-Will Attack: Melee 1 (one creature); +19 vs. AC Hit: 3d6 + 11 damage. Effect: Before or after the attack, the druid can shift up to 2 squares."},{name:"Polymorph into Plant",action:"Standard",keywords:["polymorph"],description:"Recharge if the power misses Attack: Melee 1 (one creature); +17 vs. Fortitude Hit: The druid alters the target's physical form to appear as a plant until the end of the druid's next turn, or until the druid drops to 0 hit points. While in this form, the target is stunned and has vulnerable 15 fire."},{name:"Earthen Stride",action:"Move",description:"Effect: The druid and one ally adjacent to it can each shift up to 2 squares."},{name:"Nature's Boon",action:"Minor",recharge:"Encounter",description:"Effect: Close burst 5 (one plant ally in the burst). The target gains 25 temporary hit points. Skills Endurance +19, Heal +17, Nature +17"}],alignment:"Unaligned",languages:["Common","Elven Equipment : cudgel Monster Vault: Threats to the Nentir Vale","page(s) 107","Dungeon Magazine 196."] },
  { id:"mvttnv-drow-darklasher",name:"Drow Darklasher",source:"mvttnv",level:15,role:"Lurker",xp:1200,size:"Medium",origin:"Natural",type:"Humanoid",hp:114,ac:29,fort:26,ref:28,will:24,initiative:17,perception:14,speed:"6",senses:["Darkvision"],powers:[{name:"Combat Advantage",action:"Trait",description:"The darklasher's attacks deal 2d10 extra damage against creatures granting combat advantage to it"},{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +20 vs. AC Hit: 2d8 + 10 damage."},{name:"Lashing Darkness",action:"Standard",keywords:["force"],description:"Attack: Ranged 10 (one creature that can't see the darklasher); +18 vs. Reflex Hit: 3d10 + 12 force damage, and the darklasher can slide the target 1 square. Shadow Levitation ✦ At-Will Effect: The darklasher shifts up to 4 squares (20 feet) into the air. It then gains a fly speed of 4 (hover) and total concealment until the end of its next turn or until immediately after it attacks. When the flight ends, the darklasher descends safely to the ground."},{name:"Cloud of Darkness",action:"Minor",keywords:["zone"],recharge:"Encounter",description:"Effect: Close burst 1. The burst creates a zone that lasts until the end of the encounter. The cloud blocks line of sight for all creatures except the darklasher. While entirely in the cloud, any creature other than the darklasher is blinded. The darklasher can dismiss the zone as a free action. Skills Acrobatics +18, Stealth +18"}],alignment:"Evil",languages:["Common","Elven Equipment : chainmail","dagger . Monster Vault: Threats to the Nentir Vale","page(s) 70."] },
  { id:"mvttnv-frozen-cauldron-guardian",name:"Frozen Cauldron Guardian",source:"mvttnv",level:15,role:"Brute",xp:1200,size:"Medium",origin:"Elemental",type:"Animate",keywords:["cold"],hp:179,ac:27,fort:27,ref:29,will:25,initiative:13,perception:14,speed:"0 (ice walk), fly 8 (hover)",resist:["10 cold"],vulnerable:["5 fire"],powers:[{name:"Cold Snap",action:"Standard",keywords:["cold"],description:"Attack: Melee 1 (one creature); +20 vs. AC Hit: 3d10 + 12 cold damage, and the target falls prone."},{name:"Enveloping Chill",action:"Standard",keywords:["cold"],recharge:"Recharge 3-6",description:"Attack: Close burst 1 (creatures in the burst); +18 vs. Fortitude Hit: 2d10 + 11 cold damage, and the target falls prone. The target can't stand up and takes ongoing 10 cold damage (save ends both). Skills Stealth +18"}],alignment:"Evil",languages:["Primordial Monster Vault: Threats to the Nentir Vale","page(s) 56."] },
  { id:"mvttnv-legatus-dythan",name:"Legatus Dythan",source:"mvttnv",level:15,role:"Soldier",roleModifier:"Elite",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:290,ac:31,fort:28,ref:26,will:27,initiative:10,perception:11,speed:"6",powers:[{name:"Last Stand",action:"Aura",description:"Aura 5 Bloodied allies gain a +2 power bonus to damage rolls while in the aura"},{name:"Phalanx Formation Dythan",action:"Trait",description:"gains a +1 power bonus to AC for each ally adjacent to him, up to a maximum power bonus of +4"},{name:"Longsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +20 vs. AC. Dythan has a +2 bonus to hit while bloodied Hit: 3d8 + 10 damage, or 5d8 + 10 if Dythan is marked by the target or if the target has an active defender aura."},{name:"Shock Javelin",action:"Standard",keywords:["lightning","weapon"],description:"Attack: Ranged 10 (one creature); +18 vs. Reflex. Dythan has a +2 bonus to hit while bloodied. Hit: 3d8 + 10 lightning damage."},{name:"Shield Bash",action:"Minor",keywords:["weapon"],description:"1/round Attack: Melee 1 (one creature); +20 vs. AC. Dythan has a +2 bonus to hit while bloodied. Hit: 2d6 + 4 damage, and Dythan can push the target 1 square and then shift 1 square to a square the target occupied."},{name:"Dragon Breath",action:"Minor",keywords:["fire"],recharge:"Encounter",description:"Attack: Close blast 3 (creatures in the blast); +18 vs. Reflex Hit: 2d6 + 4 fire damage."},{name:"Dythan's Challenge",action:"Triggered",description:"Trigger: An ally within 5 squares of Dythan is marked by an enemy. Effect (Immediate Interrupt): The enemy marks Dythan instead. Skills Athletics +19, History +17"}],alignment:"Evil",languages:["Common","Draconic Equipment : javelin x6","light shield","longsword","plate armor . Monster Vault: Threats to the Nentir Vale","page(s) 45."] },
  { id:"mvttnv-mirror-mimic",name:"Mirror Mimic",source:"mvttnv",level:15,role:"Lurker",xp:1200,size:"Medium",origin:"Aberrant",type:"Magical beast",hp:118,ac:29,fort:27,ref:27,will:27,initiative:16,perception:13,speed:"6; phasing",senses:["Darkvision"],powers:[{name:"Slam",action:"Standard",description:"Attack: Melee 1 (one creature); +20 vs. AC Hit: 3d8 + 10 damage."},{name:"Body Duplication",action:"Standard",keywords:["conjuration","polymorph","psychic","teleportation"],recharge:"Recharge when the mimic has no duplicates",description:"Attack: Melee 1 (one Medium creature); +18 vs. Will Hit: The mimic assumes the form of the target and teleports up to 3 squares. The mimic also conjures three duplicates of the target within 3 squares of it. The duplicates can be attacked and have the same defenses as the mimic. The mimic can take a minor action to move each of the duplicates up to its speed. A creature must succeed on a DC 35 Insight check to tell the difference between the mimic and the duplicates. Each duplicate lasts until it takes any damage, which destroys it. When a duplicate is destroyed, the target takes 3d8 + 10 psychic damage. When all the duplicates are destroyed, the mimic reverts to its normal form."},{name:"Body Transfer",action:"Move",keywords:["teleportation"],description:"Requirement: The mimic must have at least one duplicate created by body duplication. Effect: The mimic teleports, secretly swapping places with one of its duplicates within 10 squares of it. Its next attack before the end of the turn deals 8 extra damage. Skills Bluff +19, Stealth +17 (Bluff +23 while the mimic is duplicating a creature)"}],alignment:"Unaligned",languages:["Common","Deep Speech Monster Vault: Threats to the Nentir Vale","page(s) 116","Dungeon Magazine 196","Dungeon Magazine 203."] },
  { id:"mvttnv-mooncalf-rogue",name:"Mooncalf Rogue",source:"mvttnv",level:15,role:"Soldier",roleModifier:"Solo",xp:6000,size:"Huge",origin:"Aberrant",type:"Magical beast",hp:620,ac:31,fort:30,ref:27,will:27,initiative:12,perception:16,speed:"6, fly 8",senses:["Darkvision"],resist:["10 lightning,","10 thunder"],powers:[{name:"Psychic Veil",action:"Trait",description:"The mooncalf is invisible to creatures more than 6 squares away from it"},{name:"Superior Brain",action:"Trait",description:"Any dazing or stunning effects on the mooncalf end at the start of its turn"},{name:"Tentacle Snare",action:"Trait",description:"When the mooncalf moves, all creatures grabbed by it are pulled with it"},{name:"Tentacle Slam",action:"Standard",description:"Attack: Melee 6 (one creature not grabbed by the mooncalf); +20 vs. AC Hit: 2d12 + 10 damage, and the target falls prone."},{name:"Tentacle Grab",action:"Standard",description:"Attack: Melee 6 (one Huge or smaller creature not grabbed by the mooncalf); +18 vs. Reflex Hit: 1d12 + 7 damage, the mooncalf pulls the target up to 5 squares, and the target is grabbed (escape DC 22). The target takes ongoing 10 damage until the grab ends. Special: The mooncalf can grab up to two creatures at once. It can release a grabbed creature as a free action."},{name:"Vile Bite",action:"Standard",description:"Attack: Melee 1 (one creature grabbed by the mooncalf); +20 vs. AC Hit: 2d10 + 12 damage, and the target cannot spend healing surges until the start of the mooncalf's next turn. Multiattack ✦ At-Will Effect: The mooncalf makes three melee attacks, each against a different target."},{name:"Windwrack",action:"Aura",recharge:"Recharge 4-6",description:"Effect: The mooncalf activates an aura 3 that lasts until the end of the mooncalf's next turn. Creatures in the aura cannot shift. Any Medium or smaller creature that ends its turn in the aura falls prone."},{name:"Tentacle Flurry",action:"Triggered",description:"Trigger: An enemy escapes the mooncalf's tentacle grab. Attack (Immediate Reaction): Close burst 1 (enemies in the burst); +20 vs. AC Hit: 2d12 + 10 damage. Skills Stealth +15"}],alignment:"Evil",languages:["understands Deep Speech","telepathy 20 Monster Vault: Threats to the Nentir Vale","page(s) 81."] },
  { id:"mvttnv-scroll-mummy-grisgol",name:"Scroll Mummy (Grisgol)",source:"mvttnv",level:15,role:"Soldier",roleModifier:"Elite",xp:2400,size:"Large",origin:"Natural",type:"Animate",keywords:["construct"],hp:276,ac:31,fort:29,ref:28,will:26,initiative:14,perception:15,speed:"6",senses:["Darkvision"],immune:["charm, disease, necrotic, poison"],vulnerable:["10 fire"],powers:[{name:"Paralyzing Claw",action:"Standard",keywords:["necrotic"],description:"Attack: Melee 2 (one creature); +20 vs. AC Hit: 3d10 + 7 necrotic damage, and the target is immobilized until the end of the scroll mummy's next turn."},{name:"Scroll Magic",action:"Minor",description:"1/round Effect: The scroll mummy activates a spell written on one of its many scrolls. Roll randomly to determine the spell:"},{name:"1: Boiling Blood",action:"Minor",description:"1: Boiling Blood (fire) Attack: Close burst 2 (enemies in the burst); +18 vs. Fortitude Hit: 1d6 + 4 fire damage, and ongoing 10 fire damage (save ends)."},{name:"2: Ice Barrage",action:"Minor",description:"2: Ice Barrage (cold) Attack: Close blast 5 (creatures in the blast); +18 vs. Reflex Hit: 2d12 + 4 cold damage. Miss: Half damage."},{name:"3: Lightning Lure",action:"Minor",description:"3: Lightning Lure (lightning) Attack: Close blast 5 (enemies in the blast); +18 vs. Reflex Hit: 3d8 + 4 lightning damage, and the scroll mummy pulls the target up to 4 squares."},{name:"4: Shadowy Tendrils",action:"Minor",description:"4: Shadowy Tendrils (necrotic) Attack: Close burst 2 (enemies in the burst); +18 vs. Fortitude Hit: 2d10 + 2 necrotic damage, and the target gains vulnerable 10 necrotic (save ends)."},{name:"5: Thunderforce Pulse",action:"Minor",description:"5: Thunderforce Pulse (force, thunder) Attack: Close burst 2 (enemies in the burst); +18 vs. Fortitude Hit: 3d6 + 7 force and thunder damage, and the target falls prone."},{name:"6: Wave of",action:"Minor",description:"6: Wave of Madness (psychic) Attack: Close blast 5 (enemies in the blast); +18 vs. Will Hit: 2d8 + 4 psychic damage, and the target must make a basic attack as a free action against its nearest ally or take 10 psychic damage."},{name:"Choking Dust",action:"Triggered",keywords:["necrotic","poison"],description:"Trigger: The scroll mummy is first bloodied or reduced to 0 hit points. Attack (No Action): Close burst 2 (creatures in the burst); +18 vs. Fortitude Hit: 3d6 + 6 necrotic and poison damage, and ongoing 10 necrotic and poison damage (save ends)."}],alignment:"Unaligned",languages:["- Monster Vault: Threats to the Nentir Vale","page(s) 97."] },
  { id:"mvttnv-wood-woad-juggernaut",name:"Wood Woad Juggernaut",source:"mvttnv",level:15,role:"Brute",xp:1200,size:"Large",origin:"Fey",type:"Humanoid",keywords:["plant"],hp:160,ac:27,fort:28,ref:25,will:27,initiative:10,perception:12,speed:"5",resist:["15 to all damage while charging."],powers:[{name:"Juggernaut Charge",action:"Trait",description:"The juggernaut has resist 15 to all damage while charging"},{name:"Slam",action:"Standard",description:"Attack: Melee 2 (one creature); +20 vs. AC Hit: 3d8 + 15 damage."},{name:"Nature's Reign",action:"Standard",keywords:["healing"],recharge:"Recharge 4-6",description:"Attack: Melee 2 (one creature); +20 vs. AC Hit: 3d12 + 14 damage, and ongoing 10 damage (save ends). Whenever the target takes this ongoing damage, the juggernaut regains 10 hit points."}],alignment:"Unaligned",languages:["Common","Elven Monster Vault: Threats to the Nentir Vale","page(s) 106","Dungeon Magazine 196."] },
  { id:"mvttnv-drow-spider-totemist",name:"Drow Spider Totemist",source:"mvttnv",level:16,role:"Controller",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:154,ac:30,fort:26,ref:29,will:27,initiative:11,perception:17,speed:"6",senses:["Darkvision"],powers:[{name:"Dark Pact Mobility",action:"Aura",description:"Aura 5 Bloodied allies in the aura automatically succeed on saving throws against slowing effects and immobilizing effects."},{name:"Totem Bite",action:"Standard",keywords:["poison","weapon"],description:"Attack: Melee 1 (one creature); +21 vs. AC Hit: 2d10 + 3 damage, and ongoing 10 poison damage (save ends)."},{name:"Venom Ray",action:"Standard",keywords:["implement","poison"],description:"Attack: Ranged 5 (one creature); +19 vs. Reflex Hit: 3d8 + 6 poison damage, and the target is immobilized until the end of its next turn."},{name:"Spider Swarm",action:"Minor",keywords:["poison","zone"],recharge:"Recharge 4-6",description:"Effect: Close burst 2. The burst creates a zone that lasts until the end of the encounter or until the totemist uses spider swarm again. Enemies grant combat advantage while in the zone, and any enemy that ends its turn there takes 10 poison damage. Skills Arcana +20, Intimidate +18"}],alignment:"Evil",languages:["Common","Elven Equipment : robes","spider totem Monster Vault: Threats to the Nentir Vale","page(s) 70."] },
  { id:"mvttnv-winterbole-frostbeard",name:"Winterbole Frostbeard",source:"mvttnv",level:16,role:"Controller",roleModifier:"Elite",xp:0,size:"Huge",origin:"Natural",type:"Humanoid",hp:308,ac:30,fort:28,ref:28,will:29,initiative:11,perception:15,speed:"8 (forest walk, ice walk)",senses:["Low-light vision"],resist:["10 cold"],immune:["prone"],powers:[{name:"Ice Glaze",action:"Aura",description:"Aura 3 The ground in the aura is difficult terrain for creatures without ice walk"},{name:"Deep Roots Whenever",action:"Trait",description:"the frostbeard is subjected to a pull, a push, or a slide, it can move 2 squares fewer than the effect specifies"},{name:"Nature's Wrath",action:"Trait",description:"When the frostbeard spends an action point, one ally within 10 squares of it can make a melee basic attack as a free action"},{name:"Wooden Body Whenever",action:"Trait",description:"the frostbeard takes fire damage, it also takes ongoing 5 fire damage (save ends)"},{name:"Slam",action:"Standard",description:"Attack: Melee 3 (one creature); +21 vs. AC Hit: 2d12 + 11 damage, and the target is slowed until the end of its next turn."},{name:"Double Attack",action:"Standard",description:"Effect: The frostbeard uses slam twice."},{name:"Howling Blizzard",action:"Standard",keywords:["cold","thunder","zone"],recharge:"Encounter",description:"Attack: Area burst 2 within 10 (creatures in the burst); +19 vs. Fortitude Hit: 4d6 + 10 cold and thunder damage, and the target falls prone. Effect: The burst creates a zone that lasts until the end of the frostbeard's next turn. Any enemy that ends its turn in the zone takes 10 cold damage. The frostbeard can move the zone up to 5 squares as a move action. Sustain Minor: The zone persists until the end of the frostbeard's next turn."},{name:"Spirits of the Forest",action:"Move",keywords:["teleportation"],recharge:"Recharge 5-6",description:"Effect: Close burst 5 (one, two, or three allies). The frostbeard and each target teleport up to 5 squares. The frostbeard and each target gain a +2 power bonus to all defenses until the end of the frostbeard's next turn."}],alignment:"Unaligned",languages:["Elven Monster Vault: Threats to the Nentir Vale","page(s) 105."] },
  { id:"mvttnv-xander-gravelstoke",name:"Xander Gravelstoke",source:"mvttnv",level:16,role:"Skirmisher",roleModifier:"Elite",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:304,ac:30,fort:26,ref:29,will:28,initiative:16,perception:0,speed:"6",senses:["Darkvision"],powers:[{name:"Stone Cold Slayer",action:"Trait",description:"Any creature slain by Xander is petrified"},{name:"As",action:"Trait",description:"long as the creature remains petrified, it cannot be raised from the dead"},{name:"Xander",action:"Trait",description:"can end the effect by touching the petrified creature"},{name:"The",action:"Trait",description:"effect can also be ended by spilling one or more drops of Xander's blood on the petrified creature"},{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +21 vs. AC Hit: 3d6 + 14 damage, and Xander can slide the target 1 square. This attack's damage ignores 10 points of resistance."},{name:"Lunge",action:"Standard",keywords:["weapon"],recharge:"Recharge 4-6",description:"Effect: Before the attack, Xander can shift up to half his speed. Attack: Melee 1 (one creature); +21 vs. AC Hit: 6d6 + 15 damage. This attack's damage ignores 10 points of resistance."},{name:"Shadow Step",action:"Move",keywords:["teleportation"],recharge:"Encounter",description:"Effect: Xander teleports up to 5 squares and gains partial concealment until the start of his next turn."},{name:"Off-Hand Swipe",action:"Minor",keywords:["weapon"],description:"1/round Effect: Before the attack, Xander shifts up to 2 squares. Attack: Melee 1 (one creature); +21 vs. AC Hit: 2d6 + 5 damage. Quick Rally ✦ Encounter Effect: Close burst 3 (allies in the burst). Each target can take a free action to shift up to 2 squares and then make a melee basic attack. Each target must attack a different creature. Skills Acrobatics +19, Bluff +18, Diplomacy +18, Insight +17"}],alignment:"Evil",languages:["Common","Dwarven","Elven Equipment : leather armor","short sword x2. Monster Vault: Threats to the Nentir Vale","page(s) 59."] },
  { id:"mvttnv-drow-razorscourge",name:"Drow Razorscourge",source:"mvttnv",level:17,role:"Soldier",xp:1600,size:"Medium",origin:"Natural",type:"Humanoid",hp:163,ac:33,fort:28,ref:28,will:30,initiative:13,perception:16,speed:"6",senses:["Darkvision"],powers:[{name:"Scourge",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +22 vs. AC Hit: 3d10 + 9 damage. Effect: The target is marked until the end of the razorscourge's next turn."},{name:"Ensnaring Lash",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +22 vs. AC Hit: 2d10 + 6 damage, and the target is grabbed (escape DC 23). Until the grab ends, the target takes ongoing 20 damage. The grab ends automatically if the razorscourge uses this power again."},{name:"Darkfire",action:"Minor",recharge:"Encounter",description:"Attack: Ranged 10 (one creature); +20 vs. Reflex Hit: The target grants combat advantage and cannot benefit from invisibility or concealment until the end of the razorscourge's next turn."},{name:"Retributive Flogging",action:"Triggered",description:"Trigger: An enemy within 2 squares of the razorscourge and marked by it deals damage to one of the razorscourge's allies. Effect (Immediate Reaction): The razorscourge uses scourge against the triggering enemy. Skills Athletics +17, Intimidate +19"}],alignment:"Evil",languages:["Common","Elven Equipment : chainmail","scourge . Monster Vault: Threats to the Nentir Vale","page(s) 70."] },
  { id:"mvttnv-ti-irtha-drow-werespider",name:"Ti'irtha, Drow Werespider",source:"mvttnv",level:17,role:"Skirmisher",roleModifier:"Elite",xp:3200,size:"Medium",origin:"Natural",type:"Humanoid",hp:288,ac:31,fort:27,ref:30,will:29,initiative:17,perception:17,speed:"7, climb 7 (spider climb)",senses:["Darkvision"],resist:["10 poison"],vulnerable:["5 poison (save ends). If Ti'irtha has combat advantage against the target for the attack, the target also takes a -5 penalty to this"],powers:[{name:"Regeneration Ti'irtha",action:"Trait",description:"regains 10 hit points whenever she starts her turn with at least 1 hit point"},{name:"When",action:"Trait",description:"she takes damage from a silvered weapon, her regeneration does not function on her next turn"},{name:"Spidery Nature Ti'irtha",action:"Trait",description:"ignores the hindering effects of spider swarms and spiderwebs"},{name:"Bite",action:"Standard",keywords:["disease","poison"],description:"Requirement: Ti'irtha must be in spider form. Attack: Melee 1 (one creature); +22 vs. AC Hit: 2d8 + 16 poison damage. In addition, at the end of the encounter, the target makes a saving throw. On a failure, the target contracts Spider Queen's curse (stage 1)."},{name:"Dark Caress",action:"Standard",description:"Requirement: Ti'irtha must be in humanoid form. Attack: Melee 1 (one creature); +20 vs. Reflex Hit: 3d6 + 15 damage, and the target gains vulnerable 5 poison (save ends). If Ti'irtha has combat advantage against the target for the attack, the target also takes a -5 penalty to this saving throw."},{name:"Double Attack",action:"Standard",description:"Effect: Ti'irtha makes two melee basic attacks. She can shift 1 square after each attack, or up to 3 squares after each attack if she is in spider form."},{name:"Change Shape",action:"Minor",keywords:["polymorph"],description:"Effect: Ti'irtha alters her physical form to appear as a Medium spider or a unique Medium drow until she uses change shape again or until she dies."},{name:"Spiderweb",action:"Minor",recharge:"Recharge when first bloodied",description:"Requirement: Ti'irtha must be in spider form. Attack: Area burst 1 within 5 (creatures in the burst); +20 vs. Reflex Hit: The target is restrained until it escapes (DC 23) or leaves the area of the burst. Effect: The area of the burst is difficult terrain until the end of the encounter. Skills Insight +17, Intimidate +20, Stealth +20"}],alignment:"Evil",languages:["Common","Elven Spider Queen's Curse Level 17 Disease Stage 0 : The target recovers from the disease. Stage 1 : While affected by this stage","the target gains a +1 bonus to Fortitude","Reflex","and Will. Whenever the target spends a healing surge","it regains 2d6 extra hit points. Stage 2 : While affected by this stage","the target keeps the +1 bonus to Fortitude","Reflex","and Will","but takes a -2 penalty to Endurance checks made to recover from this disease. Whenever the target spends a healing surge","it regains 3d6 extra hit points. Stage 3 : The target dies. A spider swarm (described in Monster Vault) erupts from the target's corpse. Check : At the end of each extended rest","the target makes an Endurance check if it is at stage 1 or 2. 15 or lower : The stage of the disease increases by one. 16-22 : No Change 23 or higher : The stage of the disease decreases by one. Monster Vault: Threats to the Nentir Vale","page(s) 69."] },
  { id:"mvttnv-clenderi",name:"Clenderi",source:"mvttnv",level:18,role:"Controller",roleModifier:"Elite",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:344,ac:32,fort:29,ref:30,will:31,initiative:12,perception:19,speed:"6 (ice walk)",resist:["10 cold"],vulnerable:["5 fire"],powers:[{name:"Frost Aura",action:"Aura",description:"Aura 2 Enemies have vulnerable 5 cold while in the aura"},{name:"Wild Step Clenderi",action:"Trait",description:"ignores difficult terrain when she shifts"},{name:"Frost Staff",action:"Standard",keywords:["cold","weapon"],description:"Attack: Melee 1 (one creature); +23 vs. AC Hit: 3d10 + 7 cold damage, and Clenderi slides the target up to 2 squares."},{name:"Icy Glare",action:"Standard",keywords:["cold","implement"],description:"Attack: Ranged 5 (one or two creatures); +21 vs. Fortitude Hit: 3d10 + 10 cold damage, and the target is immobilized until the end of Clenderi's next turn."},{name:"Wind of Winter",action:"Standard",keywords:["cold","implement","teleportation"],recharge:"Recharge 4-6",description:"Attack: Area burst 2 within 10 (enemies in the burst); +21 vs. Fortitude Hit: 3d10 + 4 cold damage. Effect: The burst creates a zone that lasts until the end of Clenderi's next turn. The ground of the zone is difficult terrain for creatures without ice walk. Any ally of Clenderi that starts its turn in the zone can take a move action to teleport up to 10 squares to a square outside the zone."},{name:"Frostfall",action:"Standard",keywords:["cold","implement"],recharge:"Encounter",description:"Attack: Close blast 3 (creatures in the blast); +21 vs. Fortitude Hit: 4d10 + 2 cold damage, and the target is petrified (save ends). Miss: Half damage, and the target is restrained until the end of Clenderi's next turn."},{name:"Elven Accuracy",action:"Triggered",recharge:"Encounter",description:"Trigger: Clenderi makes an attack roll and dislikes the result. Effect (Free Action): Clenderi rerolls the attack roll and must use the second result. Skills Arcana +20, Bluff +21, Diplomacy +21, Nature +19"}],alignment:"Evil",languages:["Common","Elven","Primordial Equipment : staff implement . Monster Vault: Threats to the Nentir Vale","page(s) 56."] },
  { id:"mvttnv-core-of-the-tower",name:"Core of the Tower",source:"mvttnv",level:18,role:"Controller",roleModifier:"Solo",xp:10000,size:"Huge",origin:"Natural",type:"Humanoid",hp:716,ac:32,fort:31,ref:29,will:29,initiative:15,perception:14,speed:"6; phasing",senses:["Darkvision"],resist:["15 acid"],immune:["dominated"],powers:[{name:"One",action:"Trait",description:"with the Tower The core cannot leave the tower, and it is immune to any effect that would transport it outside the tower"},{name:"Threatening Reach",action:"Trait",description:"The core can make opportunity attacks against any creature within 3 squares of it"},{name:"Undaunted",action:"Trait",description:"If the core is stunned, it is dazed instead"},{name:"Slam",action:"Standard",description:"Attack: Melee 3 (one creature); +23 vs. AC Hit: 3d10 + 10 damage. Effect: The core slides the target up to 3 squares."},{name:"Grab",action:"Standard",description:"Attack: Melee 3 (one, two, or three creatures); +21 vs. Reflex Hit: 3d10 + 8 damage, and the target is grabbed (escape DC 23)."},{name:"No Exit",action:"Minor",description:"1/round Effect: The core creates a door within 20 squares of it. The door must appear in a passage that is no more than 2 squares wide. The door is jammed shut (break DC 25)."},{name:"Rippling Architecture",action:"Minor",recharge:"Recharge when first bloodied",description:"Attack: Close burst 5 (nonflying enemies in the burst); +21 vs. Reflex Hit: The target falls prone, and it is slowed (save ends). Shapeshift (polymorph) ✦ At-Will 1/round Effect: The core assumes the form of an object. It can't change its size, and it remains in this form until it uses this power again. While in this form, the core has resist 10 to all damage, is immobilized, and cannot attack. In addition, a creature must succeed on a DC 32 Perception check to notice that the core is a living creature."},{name:"Maw of Doom",action:"Free",keywords:["acid"],description:"1/round Requirement: It must be the core's turn. Attack: Melee 3 (one creature grabbed by the core); +21 vs. Fortitude Hit: The core slides the target up to 3 squares to a square adjacent to itself or to a wall of the tower. The target then takes 3d10 + 17 acid damage. Skills Bluff +20, Stealth +20"}],alignment:"Unaligned",languages:["Common","Deep Speech Monster Vault: Threats to the Nentir Vale","page(s) 114."] },
  { id:"mvttnv-ragewind",name:"Ragewind",source:"mvttnv",level:18,role:"Skirmisher",xp:2000,size:"Large",origin:"Natural",type:"Animate",keywords:["undead"],hp:112,ac:32,fort:31,ref:31,will:29,initiative:16,perception:15,speed:"10, fly 5",senses:["Blindsight 20"],powers:[{name:"Slashing Aura",action:"Aura",description:"Aura 1 An enemy that ends its turn in the aura takes 10 damage, or 15 while the ragewind is bloodied. All-Around Defense The ragewind does not provoke opportunity attacks when it moves"},{name:"Freedom",action:"Trait",description:"of Movement Any immobilizing or slowing effects on the ragewind end at the start of its turn"},{name:"Weapon Fury",action:"Standard",description:"Attack: Melee 1 (one creature); +23 vs. AC Hit: 4d8 + 8 damage. If the ragewind is bloodied, it gains 10 temporary hit points."},{name:"Rush of Blades",action:"Standard",description:"Effect: The ragewind shifts up to 5 squares and makes the following attack at any point during this movement. Attack: Melee 1 (one creature); +23 vs. AC Hit: 4d8 + 8 damage. If the ragewind is bloodied, it gains 10 temporary hit points."},{name:"Steel Whirlwind",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Close burst 1, or 2 if the ragewind is bloodied (enemies in the burst); +23 vs. AC Hit: 4d8 + 21 damage. Miss: Half damage."},{name:"Death's Rage",action:"Triggered",recharge:"Encounter",description:"Trigger: The ragewind dies. Attack (No Action): Close burst 5 (enemies in the burst); +21 vs. Will Hit: The target makes a basic attack against its nearest ally as a free action."}],alignment:"Chaotic Evil",languages:["Common Monster Vault: Threats to the Nentir Vale","page(s) 89","Dungeon Magazine 215."] },
  { id:"mvttnv-crimson-deathmist",name:"Crimson Deathmist",source:"mvttnv",level:19,role:"Soldier",roleModifier:"Elite",xp:4800,size:"Huge",origin:"Shadow",type:"Animate",keywords:["undead"],hp:328,ac:35,fort:31,ref:34,will:30,initiative:21,perception:20,speed:"0, fly 6 (altitude limit 3)",senses:["Darkvision"],resist:["10 necrotic,","10 poison"],immune:["disease"],vulnerable:["10 radiant"],powers:[{name:"Impending Doom",action:"Aura",keywords:["necrotic"],description:"Aura 2 Enemies can't spend healing surges in the aura"},{name:"When",action:"Trait",description:"an enemy ends its turn in the aura, it takes 10 necrotic damage, and the deathmist gains 10 temporary hit points"},{name:"Insubstantial",action:"Trait",description:"The deathmist takes half damage from any damage source, except those that deal fire, force, or radiant damage"},{name:"When",action:"Trait",description:"it takes fire or radiant damage, it loses this trait until the start of its next turn"},{name:"Mist Form",action:"Trait",description:"The deathmist can move through openings of any size"},{name:"It",action:"Trait",description:"can also enter other creatures' spaces and end its turn there"},{name:"Deathly Grasp",action:"Standard",keywords:["necrotic","poison"],description:"Attack: Melee 2 (one creature); +22 vs. Fortitude Hit: 3d8 + 14 necrotic and poison damage, and the target is slowed until the end of the deathmist's next turn."},{name:"Demand Obedience",action:"Standard",keywords:["necrotic","psychic"],description:"Attack: Melee 2 (one or two creatures); +22 vs. Will Hit: 4d8 + 10 necrotic and psychic damage. If the target uses an attack power that doesn't include the deathmist as a target before the end of the deathmist's next turn, the target takes 10 necrotic and psychic damage."},{name:"Terror Wave",action:"Standard",keywords:["fear","psychic"],recharge:"Recharge when first bloodied",description:"Attack: Close burst 2 (enemies in the burst); +22 vs. Will Hit: 3d10 + 11 psychic damage, and the target is immobilized until the end of the deathmist's next turn."},{name:"Hypnotic Lure",action:"Minor",keywords:["charm"],description:"1/round Attack: Close burst 5 (one or two creatures in the burst); +22 vs. Will Hit: The deathmist pulls the target up to 4 squares. Skills Stealth +24"}],alignment:"Evil",languages:["Abyssal Monster Vault: Threats to the Nentir Vale","page(s) 111."] },
  { id:"mvttnv-shadowmire",name:"Shadowmire",source:"mvttnv",level:19,role:"Lurker",roleModifier:"Solo",xp:12000,size:"Huge",origin:"Natural",type:"Magical beast",keywords:["aquatic","dragon"],hp:712,ac:33,fort:31,ref:32,will:29,initiative:20,perception:17,speed:"8 (swamp walk), fly 8, swim 8",senses:["Darkvision"],resist:["15 acid"],powers:[{name:"Acidic Blood",action:"Aura",keywords:["acid"],description:"Aura 1 While Shadowmire is bloodied, each enemy in the aura takes 10 acid damage whenever Shadowmire takes damage from an attack"},{name:"Action Recovery Whenever Shadowmire",action:"Trait",description:"ends his turn, any dazing, stunning, or dominating effect on him ends"},{name:"Aquatic Shadowmire",action:"Trait",description:"can breathe underwater. In aquatic combat, he gains a +2 bonus to attack rolls against nonaquatic creatures"},{name:"Instinctive Devouring On",action:"Trait",description:"an initiative of 10 + his initiative check, Shadowmire can use a free action to charge or to use bite"},{name:"If",action:"Trait",description:"he cannot use a free action to make this attack due to a dominating or stunning effect, then that effect ends instead of him making the attack"},{name:"Bite",action:"Standard",keywords:["acid"],description:"Attack: Melee 3 (one creature); +24 vs. AC Hit: 2d8 + 8 damage, and ongoing 10 acid damage (save ends). Miss: Half damage."},{name:"Claw",action:"Standard",description:"Attack: Melee 3 (one or two creatures); +24 vs. AC Hit: 3d10 + 12 damage, and Shadowmire pulls the target up to 2 squares."},{name:"Breath Weapon",action:"Standard",keywords:["acid"],recharge:"Recharge 4-6",description:"Attack: Close blast 5 (creatures in the blast); +22 vs. Reflex Hit: 2d10 + 4 acid damage, and ongoing 15 acid damage (save ends). Miss: Half damage, and ongoing 10 acid damage (save ends)."},{name:"Swamp Simulacrum",action:"Standard",keywords:["acid","conjuration","illusion"],recharge:"Recharge when first bloodied",description:"Effect: Shadowmire becomes invisible until the start of his next turn. Additionally, he conjures two Huge duplicates of himself, which occupy different unoccupied spaces within 10 squares of him. The duplicates last until the end of the encounter or until they are destroyed. When Shadowmire takes a move action, he can move each duplicate up to 8 squares. The duplicates can be attacked. Each one has 1 hit point (a duplicate takes no damage on a miss), acid immunity, and the same defenses as Shadowmire. When a duplicate drops to 0 hit points, Shadowmire makes the following attack centered on the duplicate. He can take a standard action to reduce a single duplicate to 0 hit points. Attack (No Action): Close burst 2 (creatures in the burst); +22 vs. Reflex Hit: 4d10 + 5 acid damage. Miss: Half damage."},{name:"Tail Sweep",action:"Triggered",description:"Trigger: An enemy misses Shadowmire with a melee attack. Attack (Immediate Reaction): Melee 4 (the triggering enemy); +22 vs. Reflex Hit: 3d8 + 15 damage, and the target falls prone. In addition, each enemy adjacent to the target takes 10 damage. Bloodied Breath ✦ Encounter Trigger: Shadowmire is first bloodied. Effect (Free Action): Breath weapon recharges, and Shadowmire uses it. Skills Intimidate +16, Nature +17, Stealth +21"}],alignment:"Evil",languages:["Common","Draconic Monster Vault: Threats to the Nentir Vale","page(s) 98."] },
  { id:"mvttnv-mysteriphal",name:"Mysteriphal",source:"mvttnv",level:20,role:"Controller",roleModifier:"Solo",xp:14000,size:"Huge",origin:"Natural",type:"Humanoid",hp:768,ac:34,fort:32,ref:29,will:33,initiative:12,perception:24,speed:"4",immune:["poison"],powers:[{name:"Ancient Entity",action:"Trait",description:"If Mysteriphal is stunned or dominated, he is instead dazed for the same duration"},{name:"Firecatcher Whenever Mysteriphal",action:"Trait",description:"takes fire damage, he also takes ongoing 10 fire damage (save ends)"},{name:"While",action:"Trait",description:"taking any ongoing fire damage, Mysteriphal deals 10 extra fire damage to any target he hits with a melee attack"},{name:"Threatening Reach Mysteriphal",action:"Trait",description:"can make opportunity attacks against enemies within 3 squares of him"},{name:"Slam",action:"Standard",description:"Attack: Melee 3 (one creature); +25 vs. AC Hit: 3d10 + 12 damage. Effect: Mysteriphal can push the target 1 square."},{name:"Quadruple Slam",action:"Standard",description:"Effect: Mysteriphal uses slam four times. If he hits the same target at least twice, the target falls prone."},{name:"Reverberating Word",action:"Standard",keywords:["thunder"],recharge:"Recharge when first bloodied",description:"Attack: Close burst 3 (nonplants in the burst); +23 vs. Fortitude Hit: 3d8 + 15 thunder damage, and the target is dazed until the end of Mysteriphal's next turn."},{name:"Teleport",action:"Move",keywords:["teleportation"],recharge:"Recharge 3-6",description:"Effect: Mysteriphal teleports up to 4 squares."},{name:"Root Grab",action:"Minor",description:"1/round Attack: Melee 3 (one prone creature); +23 vs. Reflex Hit: Mysteriphal pulls the target up to 2 squares, and the target is grabbed (escape DC 25) if he has fewer than four creatures grabbed."},{name:"Charred for Life",action:"Triggered",description:"Trigger: An attack deals fire damage to Mysteriphal. Effect (Immediate Reaction): Mysteriphal uses slam. Skills History +20, Nature +24"}],alignment:"Unaligned",languages:["Common","Elven Monster Vault: Threats to the Nentir Vale","page(s) 106."] }
